def soundboard_pad_css(state: str = "loaded") -> str:
    """Polished soundboard-pad styling.

    state: 'empty' (no clip), 'loaded' (clip assigned, idle), 'playing'.
    Glow is simulated with a bright accent edge that intensifies on hover
    (stylesheets can't box-shadow), giving a clean backlit-button feel.
    """
    if state == "playing":
        return """
            QPushButton {
                background: qlineargradient(x1:0,y1:0,x2:0,y2:1,
                    stop:0 rgba(74,224,134,0.95),
                    stop:1 rgba(26,160,88,0.96));
                color: #04230f;
                border: 1px solid rgba(176,255,206,0.96);
                border-radius: 10px;
                padding: 3px 9px;
                font-weight: 800;
            }
            QPushButton:hover {
                border: 1px solid rgba(214,255,230,1.0);
            }
        """
    if state == "empty":
        return """
            QPushButton {
                background: qlineargradient(x1:0,y1:0,x2:0,y2:1,
                    stop:0 rgba(255,255,255,0.022),
                    stop:1 rgba(255,255,255,0.006));
                color: rgba(172,182,206,0.50);
                border: 1px dashed rgba(124,61,255,0.34);
                border-radius: 10px;
                padding: 3px 9px;
                font-size: 17px;
                font-weight: 800;
            }
            QPushButton:hover {
                background: rgba(124,61,255,0.16);
                border: 1px dashed rgba(178,150,255,0.74);
                color: rgba(228,231,244,0.92);
            }
            QPushButton:pressed {
                background: rgba(46,16,101,0.70);
            }
        """
    # loaded (idle): dark glassy pad with a purple accent edge that lights up.
    return """
        QPushButton {
            background: qlineargradient(x1:0,y1:0,x2:0,y2:1,
                stop:0 rgba(30,25,55,0.96),
                stop:1 rgba(14,14,28,0.96));
            color: #e9e6f7;
            border: 1px solid rgba(124,61,255,0.45);
            border-radius: 10px;
            padding: 3px 9px;
            font-weight: 750;
        }
        QPushButton:hover {
            background: qlineargradient(x1:0,y1:0,x2:0,y2:1,
                stop:0 rgba(62,42,116,0.97),
                stop:1 rgba(32,21,62,0.97));
            border: 1px solid rgba(182,152,255,0.95);
            color: #ffffff;
        }
        QPushButton:pressed {
            background: rgba(40,16,92,0.92);
            border: 1px solid rgba(198,172,255,1.0);
        }
    """

