# --- SQLite search/index workers (no UI-thread blocking) ---
class SongSearchThread(QThread):
    results_ready = pyqtSignal(int, list)

    def __init__(self, job_id: int, query: str, limit: int = 500, fuzzy: bool = True):
        super().__init__()
        self.job_id = job_id
        self.query = query
        self.limit = limit
        self.fuzzy = bool(fuzzy)

    def run(self):
        started = time.monotonic()
        try:
            # Exact/substring results are cheap and should reach the UI first.
            rows = song_index.search_songs(self.query, limit=int(self.limit), fuzzy=False)
        except Exception:
            rows = []
        strict_ms = (time.monotonic() - started) * 1000.0
        _perf_log_if_slow("search_query", strict_ms)
        self.results_ready.emit(self.job_id, rows)
        if self.isInterruptionRequested() or not self.fuzzy:
            return
        # Fuzzy is helpful for typos, but it is the expensive part. Only run it
        # for sparse non-trivial searches, and cap the candidate count so an old
        # Intel Mac does not spend the next few keystrokes catching up.
        try:
            q = str(self.query or "").strip()
            if len(q) < 3 or len(rows) >= 40:
                return
            fuzzy_started = time.monotonic()
            fuzzy_rows = song_index.search_songs(q, limit=min(int(self.limit), 150), fuzzy=True)
            fuzzy_ms = (time.monotonic() - fuzzy_started) * 1000.0
            _perf_log_if_slow("fuzzy_search", fuzzy_ms)
            if self.isInterruptionRequested():
                return
            if fuzzy_rows:
                self.results_ready.emit(self.job_id, fuzzy_rows)
        except Exception:
            return


class IndexBuildThread(QThread):
    done = pyqtSignal(bool, str)
    progress = pyqtSignal(str, int, int)  # message, current, total

    def __init__(self, force: bool = False):
        super().__init__()
        self.force = force

    def run(self):
        try:
            tp = song_index.tracks_json_path()
            dbf = song_index.db_path()
            if not tp.exists():
                self.done.emit(False, "No library found - Please scan a folder first")
                return
            if (not self.force) and dbf.exists():
                self.done.emit(True, "Import Complete")
                return
            
            # Full rebuild with progress callback
            def progress_cb(msg: str, current: int, total: int):
                self.progress.emit(msg, current, total)
            
            song_index.rebuild_from_tracks_json(tp, dbf, verbose=False, progress_callback=progress_cb)
            self.done.emit(True, "Import Complete")
        except Exception as e:
            self.done.emit(False, f"Import failed: {e}")


def _version_key(value: str) -> tuple:
    parts = []
    for part in re.split(r"[^0-9]+", str(value or "").lstrip("vV")):
        if part == "":
            continue
        try:
            parts.append(int(part))
        except Exception:
            parts.append(0)
    while len(parts) < 4:
        parts.append(0)
    return tuple(parts[:6])


def _is_newer_version(remote: str, current: str) -> bool:
    return _version_key(remote) > _version_key(current)


def _preferred_update_asset(assets: list) -> dict | None:
    dmg_assets = [a for a in (assets or []) if str(a.get("name", "")).lower().endswith(".dmg")]
    if not dmg_assets:
        return None
    machine = platform.machine().lower()
    preferred_terms = []
    if sys.platform == "darwin":
        if machine in {"arm64", "aarch64"}:
            preferred_terms = ["arm64", "universal"]
        elif machine in {"x86_64", "amd64", "i386", "i686"}:
            preferred_terms = ["x86_64", "intel", "universal"]
    for term in preferred_terms:
        for asset in dmg_assets:
            if term in str(asset.get("name", "")).lower():
                return asset
    return dmg_assets[0]


class GitHubUpdateWorker(QThread):
    checked = pyqtSignal(dict)
    progress = pyqtSignal(int, str)
    downloaded = pyqtSignal(dict)
    failed = pyqtSignal(str)

    def __init__(self, *, repo: str, current_version: str, manifest_url: str = "", download_dir: str = "", download: bool = False):
        super().__init__()
        self.repo = str(repo or "DanDemolition/SingWS").strip()
        self.current_version = str(current_version or "")
        self.manifest_url = str(manifest_url or "").strip()
        self.download_dir = str(download_dir or "")
        self.download = bool(download)
        self._cancel = False

    def cancel(self):
        self._cancel = True
        try:
            self.requestInterruption()
        except Exception:
            pass

    def _default_download_dir(self) -> Path:
        if self.download_dir.strip():
            return Path(os.path.expanduser(self.download_dir.strip()))
        return Path.home() / "Downloads" / "SingWS Updates"

    def _fetch_latest_release(self) -> dict:
        repo = self.repo.strip().strip("/")
        if "/" not in repo:
            repo = "DanDemolition/SingWS"
        url = f"https://api.github.com/repos/{repo}/releases/latest"
        headers = {
            "Accept": "application/vnd.github+json",
            "User-Agent": f"SingWS/{APP_VERSION}",
        }
        resp = requests.get(url, headers=headers, timeout=12)
        resp.raise_for_status()
        return resp.json()

    def _fetch_release_manifest(self) -> dict:
        url = self.manifest_url.strip()
        if not url:
            raise RuntimeError("No update manifest URL configured")
        headers = {
            "Accept": "application/json",
            "User-Agent": f"SingWS/{APP_VERSION}",
        }
        resp = requests.get(url, headers=headers, timeout=12)
        resp.raise_for_status()
        return resp.json()

    def _release_info(self, release: dict) -> dict:
        tag = str(release.get("tag_name") or release.get("name") or "").strip()
        version = tag.lstrip("vV")
        asset = _preferred_update_asset(release.get("assets") or [])
        available = bool(version and _is_newer_version(version, self.current_version) and asset)
        return {
            "available": available,
            "current_version": self.current_version,
            "version": version,
            "tag": tag,
            "name": str(release.get("name") or tag or version),
            "html_url": str(release.get("html_url") or ""),
            "published_at": str(release.get("published_at") or ""),
            "asset": asset or {},
        }

    def _manifest_info(self, manifest: dict) -> dict:
        version = str(manifest.get("version") or "").strip().lstrip("vV")
        downloads = manifest.get("downloads") or {}
        asset = {}
        keys = []
        machine = platform.machine().lower()
        if sys.platform == "darwin":
            if machine in {"arm64", "aarch64"}:
                keys = ["mac_arm64", "mac_universal"]
            elif machine in {"x86_64", "amd64", "i386", "i686"}:
                keys = ["mac_x86_64", "mac_universal"]
        keys.append("mac_universal")
        for key in keys:
            item = downloads.get(key)
            if isinstance(item, dict) and item.get("url"):
                asset = {
                    "name": str(item.get("filename") or f"SingWS-{version}.dmg"),
                    "browser_download_url": str(item.get("url") or ""),
                    "digest": f"sha256:{item.get('sha256')}" if item.get("sha256") else "",
                }
                break
        available = bool(version and _is_newer_version(version, self.current_version) and asset)
        return {
            "available": available,
            "current_version": self.current_version,
            "version": version,
            "tag": f"v{version}" if version else "",
            "name": str(manifest.get("name") or f"SingWS {version}"),
            "html_url": str(manifest.get("release_url") or ""),
            "published_at": str(manifest.get("release_date") or ""),
            "asset": asset,
            "source": "manifest",
        }

    def _download_asset(self, info: dict) -> dict:
        asset = dict(info.get("asset") or {})
        url = str(asset.get("browser_download_url") or "")
        name = str(asset.get("name") or f"SingWS-{info.get('version', 'update')}.dmg")
        if not url:
            raise RuntimeError("Release asset has no download URL")
        out_dir = self._default_download_dir()
        out_dir.mkdir(parents=True, exist_ok=True)
        out_path = out_dir / name
        tmp_path = out_dir / f".{name}.download"
        headers = {"User-Agent": f"SingWS/{APP_VERSION}"}
        started = time.perf_counter()
        with requests.get(url, headers=headers, stream=True, timeout=(12, 30)) as resp:
            resp.raise_for_status()
            total = int(resp.headers.get("content-length") or asset.get("size") or 0)
            done = 0
            last_pct = -1
            last_emit = 0.0
            with open(tmp_path, "wb") as fh:
                for chunk in resp.iter_content(chunk_size=1024 * 256):
                    if self._cancel or self.isInterruptionRequested():
                        raise RuntimeError("Download cancelled")
                    if not chunk:
                        continue
                    fh.write(chunk)
                    done += len(chunk)
                    if total > 0:
                        pct = max(0, min(100, int(done * 100 / total)))
                    else:
                        pct = 0
                    now = time.monotonic()
                    if pct != last_pct and (pct >= last_pct + 1 or now - last_emit >= 0.5):
                        last_pct = pct
                        last_emit = now
                        self.progress.emit(pct, f"Downloading {name} ({pct}%)")
        digest = str(asset.get("digest") or "")
        if digest.lower().startswith("sha256:"):
            expected = digest.split(":", 1)[1].strip().lower()
            h = hashlib.sha256()
            with open(tmp_path, "rb") as fh:
                for block in iter(lambda: fh.read(1024 * 1024), b""):
                    h.update(block)
            actual = h.hexdigest().lower()
            if expected and actual != expected:
                raise RuntimeError("Downloaded update failed SHA-256 verification")
        if out_path.exists():
            out_path.unlink()
        tmp_path.rename(out_path)
        elapsed_ms = (time.perf_counter() - started) * 1000.0
        _perf_log_if_slow("github_update_download", elapsed_ms)
        info["download_path"] = str(out_path)
        info["filename"] = name
        return info

    def run(self):
        started = time.perf_counter()
        try:
            try:
                manifest = self._fetch_release_manifest()
                info = self._manifest_info(manifest)
            except Exception as manifest_error:
                release = self._fetch_latest_release()
                info = self._release_info(release)
                info["manifest_error"] = str(manifest_error)
                info["source"] = "github_api"
            _perf_log_if_slow("github_update_check", (time.perf_counter() - started) * 1000.0)
            self.checked.emit(info)
            if self.download and info.get("available"):
                self.progress.emit(0, "Starting update download...")
                self.downloaded.emit(self._download_asset(info))
        except Exception as e:
            self.failed.emit(str(e))


class SongbookUploadThread(QThread):
    progress_text = pyqtSignal(str)
    done = pyqtSignal(bool, str, int)

    def __init__(self, base_url: str, tenant: str, api_key: str, tracks: list):
        super().__init__()
        self.base_url = _network_normalize_base_url(base_url)
        self.tenant = (tenant or "").strip()
        self.api_key = (api_key or "").strip()
        self.tracks = list(tracks or [])

    def _collect_rows(self):
        rows = []
        try:
            dbf = song_index.db_path()
            if dbf.exists():
                con = song_index._connect(dbf)
                db_rows = con.execute(
                    "SELECT DISTINCT artist, title FROM songs "
                    "WHERE artist IS NOT NULL AND title IS NOT NULL "
                    "ORDER BY artist, title"
                ).fetchall()
                con.close()
                rows = [
                    (str(r["artist"]).strip(), str(r["title"]).strip())
                    for r in db_rows
                    if r["artist"] and r["title"]
                ]
        except Exception:
            rows = []

        if rows:
            return rows

        seen = set()
        for track in self.tracks:
            artist = str(track.get("artist", "")).strip()
            title = str(track.get("title", "")).strip()
            if not artist or not title:
                continue
            key = (artist.lower(), title.lower())
            if key in seen:
                continue
            seen.add(key)
            rows.append((artist, title))
        rows.sort(key=lambda x: (x[0].lower(), x[1].lower()))
        return rows

    def run(self):
        import csv

        tmp_path = None
        try:
            self.progress_text.emit("Preparing local songbook...")
            rows = self._collect_rows()
            if not rows:
                self.done.emit(False, "No songs found to upload.", 0)
                return

            fd, tmp_path = tempfile.mkstemp(prefix="singws-songbook-", suffix=".csv")
            os.close(fd)

            with open(tmp_path, "w", newline="", encoding="utf-8") as f:
                writer = csv.writer(f)
                writer.writerow(["Artist", "Title"])
                writer.writerows(rows)

            self.progress_text.emit(f"Uploading {len(rows):,} songs to the server...")
            headers = {"X-API-Key": self.api_key} if self.api_key else {}
            with open(tmp_path, "rb") as f:
                resp = requests.post(
                    f"{self.base_url}/api/v1/upload_songbook.php",
                    data={"user": self.tenant, "tenant": self.tenant},
                    files={"songbook_csv": ("songbook.csv", f, "text/csv")},
                    headers=headers,
                    timeout=180,
                )

            try:
                data = resp.json()
            except Exception:
                preview = (resp.text or "")[:200]
                self.done.emit(False, f"Unexpected server response: {preview}", 0)
                return

            if resp.status_code != 200 or not data.get("success"):
                self.done.emit(False, data.get("error") or f"Upload failed ({resp.status_code})", 0)
                return

            self.done.emit(True, "Songbook uploaded successfully.", int(data.get("count", len(rows)) or 0))
        except Exception as e:
            self.done.emit(False, f"Upload failed: {e}", 0)
        finally:
            if tmp_path:
                try:
                    os.remove(tmp_path)
                except Exception:
                    pass


