# ===== RESOURCE MANAGEMENT FOR PYINSTALLER =====

def get_resource_path(relative_path: str) -> str:
    """
    Resolve an asset path for both dev and frozen builds.

    Lookup order:
      1) PyInstaller bundle dir (sys._MEIPASS)
      2) Folder next to the exe (dist/SingWS/*.svg in your current build script)
      3) Source folder (dev)
    """
    rel = relative_path.lstrip("/\\")
    # 1) PyInstaller bundle
    if getattr(sys, "frozen", False) and hasattr(sys, "_MEIPASS"):
        p = os.path.join(sys._MEIPASS, rel)
        if os.path.exists(p):
            return p

    # 2) Next to exe (onedir builds often keep assets here)
    if getattr(sys, "frozen", False):
        exe_dir = os.path.dirname(sys.executable)
        p = os.path.join(exe_dir, rel)
        if os.path.exists(p):
            return p

    # 3) Dev
    return os.path.join(os.path.dirname(os.path.abspath(__file__)), rel)



