def configure_app_font(app, point_bump: int = 5):
    """Use an explicit installed app font to avoid Qt fallback alias warnings."""
    try:
        from PyQt6.QtGui import QFontDatabase

        families = set(QFontDatabase.families())
        preferred = (
            ("Helvetica Neue", ".AppleSystemUIFont", "Arial", "Lucida Grande")
            if sys.platform == "darwin"
            else ("Segoe UI", "Arial", "DejaVu Sans")
        )
        f = app.font()
        for family in preferred:
            if family in families:
                f.setFamily(family)
                break
        ps = f.pointSize() if f.pointSize() and f.pointSize() > 0 else 13
        f.setPointSize(ps + int(point_bump or 0))
        app.setFont(f)
    except Exception:
        pass


def force_dark_palette(app):
    """Force a dark Qt palette so text stays readable even when the OS is in Light mode.

    This avoids having to manually set text colors on every widget.
    """
    try:
        from PyQt6.QtGui import QPalette, QColor

        pal = QPalette()

        # Surfaces
        pal.setColor(QPalette.ColorRole.Window, QColor(_v("canvas")))
        pal.setColor(QPalette.ColorRole.Base, QColor(_v("surface_input")))
        pal.setColor(QPalette.ColorRole.AlternateBase, QColor(_v("surface")))
        pal.setColor(QPalette.ColorRole.Button, QColor(_v("surface")))

        # Text roles (critical fix)
        pal.setColor(QPalette.ColorRole.WindowText, QColor(_v("text")))
        pal.setColor(QPalette.ColorRole.Text, QColor(_v("text")))
        pal.setColor(QPalette.ColorRole.ButtonText, QColor(_v("text")))
        pal.setColor(QPalette.ColorRole.PlaceholderText, QColor(_v("text_soft")))
        pal.setColor(QPalette.ColorRole.ToolTipBase, QColor(_v("surface")))
        pal.setColor(QPalette.ColorRole.ToolTipText, QColor(_v("text")))

        # Selection
        pal.setColor(QPalette.ColorRole.Highlight, QColor(_v("accent")))
        pal.setColor(QPalette.ColorRole.HighlightedText, QColor(_v("accent_text")))

        app.setPalette(pal)

        # App-wide widget chrome for Qt popups/native-looking controls that do not
        # pass through the local screen helpers.
        try:
            existing = app.styleSheet() or ""
            chrome_css = app_stylesheet()
            app.setStyleSheet(existing + ("\n" if existing else "") + chrome_css)
        except Exception:
            pass

    except Exception:
        pass

    except Exception:
        pass


##############################################
# FAST MP3 DURATION FROM STREAM (no decode)  #
##############################################
import struct

def _read_exact(f, n):
    b = f.read(n)
    return b if b and len(b) == n else None

def _skip_id3v2(f):
    """If ID3v2 tag exists at start of stream, skip it. Returns bytes skipped."""
    hdr = _read_exact(f, 10)
    if not hdr or hdr[0:3] != b'ID3':
        if hdr:
            try: f.seek(-len(hdr), 1)
            except Exception: pass
        return 0
    size = ((hdr[6] & 0x7f) << 21) | ((hdr[7] & 0x7f) << 14) | ((hdr[8] & 0x7f) << 7) | (hdr[9] & 0x7f)
    footer = 10 if (hdr[5] & 0x10) else 0
    try: f.seek(size + footer, 1)
    except Exception: pass
    return 10 + size + footer

def _parse_mpeg_frame_header(hdr4):
    """Return (version, layer, bitrate_kbps, samplerate_hz, padding, channel_mode) or None."""
    if len(hdr4) != 4: return None
    b = struct.unpack(">I", hdr4)[0]
    if (b & 0xFFE00000) != 0xFFE00000: return None
    ver_id = (b >> 19) & 0x3
    layer  = (b >> 17) & 0x3
    br_id  = (b >> 12) & 0xF
    sr_id  = (b >> 10) & 0x3
    pad    = (b >> 9) & 0x1
    chmode = (b >> 6) & 0x3
    if ver_id == 0b01 or layer == 0b00 or br_id in (0, 0b1111) or sr_id == 0b11:
        return None
    mpeg_ver = {0b11:"MPEG1", 0b10:"MPEG2", 0b00:"MPEG2.5"}[ver_id]
    layer_map = {0b01:3, 0b10:2, 0b11:1}
    layer_no = layer_map[layer]
    base_sr = {0b00:44100, 0b01:48000, 0b10:32000}[sr_id]
    sr = base_sr // 2 if mpeg_ver=="MPEG2" else (base_sr // 4 if mpeg_ver=="MPEG2.5" else base_sr)
    br_tbl = {
        ("MPEG1",1): [0,32,64,96,128,160,192,224,256,288,320,352,384,416,448],
        ("MPEG1",2): [0,32,48,56,64,80,96,112,128,160,192,224,256,320,384],
        ("MPEG1",3): [0,32,40,48,56,64,80,96,112,128,160,192,224,256,320],
        ("MPEG2",1): [0,32,48,56,64,80,96,112,128,144,160,176,192,224,256],
        ("MPEG2",2): [0,8,16,24,32,40,48,56,64,80,96,112,128,144,160],
        ("MPEG2",3): [0,8,16,24,32,40,48,56,64,80,96,112,128,144,160],
        ("MPEG2.5",1): [0,32,48,56,64,80,96,112,128,144,160,176,192,224,256],
        ("MPEG2.5",2): [0,8,16,24,32,40,48,56,64,80,96,112,128,144,160],
        ("MPEG2.5",3): [0,8,16,24,32,40,48,56,64,80,96,112,128,144,160],
    }
    bitrate_kbps = br_tbl.get((mpeg_ver, layer_no), [0]*15)[br_id]
    if bitrate_kbps == 0: return None
    return (mpeg_ver, layer_no, bitrate_kbps, sr, pad, chmode)

def _find_xing_vbri(f):
    pos = f.tell()
    hdr4 = _read_exact(f, 4)
    if not hdr4: return None
    info = _parse_mpeg_frame_header(hdr4)
    if not info: return None
    mpeg_ver, layer_no, bitrate_kbps, sr, pad, chmode = info
    rest = _read_exact(f, 200) or b""
    scan = hdr4 + rest
    ix = scan.find(b"Xing")
    if ix < 0: ix = scan.find(b"Info")
    if ix >= 0:
        flags_off = ix + 4
        if flags_off + 4 <= len(scan):
            import struct as _struct
            flags = _struct.unpack(">I", scan[flags_off:flags_off+4])[0]
            p = flags_off + 4
            frames = bytes_total = None
            if flags & 0x1 and p+4 <= len(scan): frames = _struct.unpack(">I", scan[p:p+4])[0]; p += 4
            if flags & 0x2 and p+4 <= len(scan): bytes_total = _struct.unpack(">I", scan[p:p+4])[0]; p += 4
            out = {'type':'xing'}
            if frames is not None: out['frames'] = frames
            if bytes_total is not None: out['bytes'] = bytes_total
            return out
    iv = scan.find(b"VBRI")
    if iv >= 0 and iv + 26 <= len(scan):
        import struct as _struct
        base = iv + 10
        if base + 8 <= len(scan):
            bytes_total = _struct.unpack(">I", scan[base:base+4])[0]
            frames      = _struct.unpack(">I", scan[base+4:base+8])[0]
            return {'type':'vbri', 'frames':frames, 'bytes':bytes_total}
    return None

def fast_mp3_duration_from_stream(f, file_size_hint=None):
    """Compute duration (seconds) from an MP3 stream using header heuristics only."""
    try:
        f.seek(0)
        _skip_id3v2(f)
        start = f.tell()
        hdr4 = _read_exact(f, 4)
        if not hdr4: return None
        info = _parse_mpeg_frame_header(hdr4)
        if not info: return None
        mpeg_ver, layer_no, bitrate_kbps, sr, pad, chmode = info
        f.seek(start)
        x = _find_xing_vbri(f)
        if x and 'frames' in x and sr:
            spf = 1152 if layer_no in (3,2) else 384
            secs = (x['frames'] * spf) / float(sr)
            return int(secs + 0.5)
        if file_size_hint:
            bytes_per_sec = (bitrate_kbps * 1000) // 8
            if bytes_per_sec > 0:
                return max(1, int(file_size_hint // bytes_per_sec))
        return None
    except Exception:
        return None

def fast_mp3_duration_from_zip(zip_path):
    """
    Calculate duration from CDG file size (OpenKJ method - MUCH faster!).
    CDG format: 96 bytes/frame at 75 frames/second.
    No MP3 reading or decompression needed - just reads ZIP metadata.
    
    Falls back to MP3 header parsing if CDG size method fails.
    """
    import os
    zip_path = os.path.abspath(zip_path)  # Fix for Windows background thread context
    try:
        with zipfile.ZipFile(zip_path, 'r') as zf:
            cdg_member = None
            mp3_member = None
            candidate = None
            info_list = zf.infolist()
            
            # Find CDG and MP3 files
            for zi in info_list:
                if zi.is_dir(): 
                    continue
                name = zi.filename.lower()
                
                # Look for CDG file
                if name.endswith(".cdg"):
                    cdg_member = zi
                
                # Look for MP3 file
                if name.endswith(".mp3"):
                    if candidate is None:
                        candidate = zi
                    stem = name.rsplit(".", 1)[0]
                    if any(i.filename.lower().startswith(stem) and i.filename.lower().endswith(".cdg") for i in info_list):
                        mp3_member = zi
            
            if mp3_member is None:
                mp3_member = candidate
            
            # Method 1: Fast CDG size calculation (OpenKJ method)
            if cdg_member is not None and cdg_member.file_size > 0:
                # CDG format: 96 bytes per frame, 75 frames per second
                cdg_size = cdg_member.file_size  # Uncompressed size from ZIP metadata
                dur = int((cdg_size / 96) / 75)  # Duration in seconds
                
                if dur > 0:
                    cache_key = {
                        "zip_mtime": int(os.path.getmtime(zip_path)) if os.path.exists(zip_path) else 0,
                        "zip_size":  os.path.getsize(zip_path) if os.path.exists(zip_path) else 0,
                        "member":    cdg_member.filename,
                        "crc":       cdg_member.CRC,
                        "usize":     cdg_member.file_size,
                    }
                    # Uncomment to see when CDG method is used:
                    # print(f"✓ CDG size method: {dur}s for {os.path.basename(zip_path)}")
                    return int(dur), cache_key
            
            # Method 2: Fallback to MP3 header parsing (slower, but works if no CDG)
            if mp3_member is not None:
                from io import BytesIO
                with zf.open(mp3_member, 'r') as mf:
                    chunk = mf.read(64 * 1024)
                    dur = fast_mp3_duration_from_stream(BytesIO(chunk), file_size_hint=mp3_member.file_size)
                    if dur is None:
                        more = mf.read(64 * 1024)
                        if more:
                            chunk += more
                            dur = fast_mp3_duration_from_stream(BytesIO(chunk), file_size_hint=mp3_member.file_size)
                    if dur is None:
                        more = mf.read(128 * 1024)  # cap at ~256KB total
                        if more:
                            chunk += more
                            dur = fast_mp3_duration_from_stream(BytesIO(chunk), file_size_hint=mp3_member.file_size)

                if dur and dur > 0:
                    cache_key = {
                        "zip_mtime": int(os.path.getmtime(zip_path)) if os.path.exists(zip_path) else 0,
                        "zip_size":  os.path.getsize(zip_path) if os.path.exists(zip_path) else 0,
                        "member":    mp3_member.filename,
                        "crc":       mp3_member.CRC,
                        "usize":     mp3_member.file_size,
                    }
                    return int(dur), cache_key
            
            return None, None
            
    except Exception as e:
        print(f"zip fast duration failed: {zip_path} :: {e}")
        return None, None

