# --- Karaoke loudness normalization -----------------------------------------
# Measures each audio file's integrated loudness (EBU R128) once, caches it,
# and applies a static per-file gain at playback so songs play at a consistent
# level. Analysis runs in the background; playback just reads the cached gain.
# BGM applies this per source deck, under the user volume/fade master.
LOUDNESS_CACHE_PATH = APP_USER_DIR / "loudness.json"
LOUDNESS_TARGET_LUFS = -16.0
LOUDNESS_MAX_GAIN_DB = 12.0      # clamp so a bad measurement can't blow out volume
LOUDNESS_MIN_GAIN_DB = -18.0
LOUDNESS_TRUE_PEAK_HEADROOM_DB = 1.0
_loudness_cache = {}
_loudness_cache_loaded = False
_loudness_lock = threading.Lock()
_loudness_inflight = set()
# Serialize loudness analysis so at most one ffmpeg ebur128 pass runs at a
# time.  Combined with single-threaded + niced ffmpeg below, this keeps the
# background analysis from starving the audio decode/stretch thread and
# causing choppy playback on weaker CPUs (e.g. Intel Macs).
_loudness_sem = threading.Semaphore(1)


def _loudness_lower_priority(pid: int):
    """Renice the analysis subprocess from the parent so the OS scheduler favors
    playback threads.  Done after spawn (not via preexec_fn) because preexec_fn
    is unsafe in a multithreaded program.  Best-effort; ignored if unsupported."""
    try:
        os.setpriority(os.PRIO_PROCESS, pid, 12)
    except Exception:
        pass


def _loudness_load_cache():
    global _loudness_cache_loaded
    if _loudness_cache_loaded:
        return
    with _loudness_lock:
        if _loudness_cache_loaded:
            return
        try:
            if LOUDNESS_CACHE_PATH.exists():
                data = json.loads(LOUDNESS_CACHE_PATH.read_text(encoding="utf-8") or "{}")
                if isinstance(data, dict):
                    _loudness_cache.update(data)
        except Exception:
            pass
        _loudness_cache_loaded = True


def _loudness_save_cache():
    try:
        tmp = LOUDNESS_CACHE_PATH.with_suffix(".json.tmp")
        tmp.write_text(json.dumps(_loudness_cache), encoding="utf-8")
        os.replace(tmp, LOUDNESS_CACHE_PATH)
    except Exception:
        pass


def _loudness_file_sig(path: str):
    try:
        st = os.stat(path)
        return int(st.st_mtime), int(st.st_size)
    except Exception:
        return None


def _loudness_gain_from_lufs(integrated_lufs: float, peak_db: float | None = None) -> float:
    try:
        gain = LOUDNESS_TARGET_LUFS - float(integrated_lufs)
    except Exception:
        return 0.0
    gain = max(LOUDNESS_MIN_GAIN_DB, min(LOUDNESS_MAX_GAIN_DB, gain))
    if peak_db is not None:
        try:
            # Conservative peak guard: after applying gain, the measured sample
            # peak should stay below -1 dBFS.  This is static per-track gain,
            # not a compressor, so it avoids clipping without pumping.
            gain = min(gain, -LOUDNESS_TRUE_PEAK_HEADROOM_DB - float(peak_db))
        except Exception:
            pass
    return max(LOUDNESS_MIN_GAIN_DB, min(LOUDNESS_MAX_GAIN_DB, gain))


def loudness_info_cached(audio_path: str):
    """Return cached loudness diagnostics for an audio file, or None."""
    _loudness_load_cache()
    if not audio_path:
        return None
    sig = _loudness_file_sig(audio_path)
    entry = _loudness_cache.get(audio_path)
    if not isinstance(entry, dict):
        return None
    if sig is not None and (int(entry.get("mtime", 0)) != sig[0] or int(entry.get("size", 0)) != sig[1]):
        return None
    try:
        lufs = float(entry["i"])
    except Exception:
        return None
    peak_db = None
    try:
        if entry.get("peak_db") is not None:
            peak_db = float(entry.get("peak_db"))
    except Exception:
        peak_db = None
    gain_db = _loudness_gain_from_lufs(lufs, peak_db)
    return {
        "lufs": lufs,
        "peak_db": peak_db,
        "gain_db": gain_db,
        "gain_linear": 10.0 ** (float(gain_db) / 20.0),
    }


def loudness_gain_db_cached(audio_path: str):
    """Return the cached normalization gain (dB) for an audio file, or None if
    not yet analyzed / the file changed."""
    _loudness_load_cache()
    if not audio_path:
        return None
    sig = _loudness_file_sig(audio_path)
    entry = _loudness_cache.get(audio_path)
    if not isinstance(entry, dict):
        return None
    if sig is not None and (int(entry.get("mtime", 0)) != sig[0] or int(entry.get("size", 0)) != sig[1]):
        return None
    try:
        peak_db = entry.get("peak_db")
        peak = float(peak_db) if peak_db is not None else None
        return _loudness_gain_from_lufs(float(entry["i"]), peak)
    except Exception:
        return None


def _measure_loudness_lufs(audio_path: str):
    """Measure integrated loudness (LUFS) and sample peak via ffmpeg.

    Returns (integrated_lufs, max_volume_db) or (None, None).  The peak pass is
    cached and used only to cap static gain; no live compressor/limiter is added.
    """
    try:
        from python_karaoke_transport import _ffmpeg_path
        ffmpeg = _ffmpeg_path("ffmpeg")
    except Exception:
        ffmpeg = "ffmpeg"
    cmd = [
        ffmpeg, "-hide_banner", "-nostats", "-nostdin", "-threads", "1",
        "-i", audio_path, "-map", "0:a:0", "-af", "ebur128", "-f", "null", "-",
    ]
    proc = None
    try:
        proc = subprocess.Popen(
            cmd, stdin=subprocess.DEVNULL, stdout=subprocess.DEVNULL,
            stderr=subprocess.PIPE,
        )
        if hasattr(os, "setpriority"):
            _loudness_lower_priority(proc.pid)
        _out, err = proc.communicate(timeout=120)
        text = (err or b"").decode("utf-8", errors="ignore")
    except Exception:
        # On timeout or any failure, make sure the child is not left running.
        if proc is not None:
            try:
                proc.kill()
                proc.communicate(timeout=5)
            except Exception:
                pass
        return None, None
    matches = re.findall(r"\bI:\s*(-?\d+(?:\.\d+)?)\s*LUFS", text)
    if not matches:
        return None, None
    try:
        val = float(matches[-1])
    except Exception:
        return None, None
    # Guard against pathological/silent results.
    if not (-70.0 <= val <= 0.0):
        return None, None

    peak_db = None
    peak_cmd = [
        ffmpeg, "-hide_banner", "-nostats", "-nostdin", "-threads", "1",
        "-i", audio_path, "-map", "0:a:0", "-af", "volumedetect", "-f", "null", "-",
    ]
    proc = None
    try:
        proc = subprocess.Popen(
            peak_cmd, stdin=subprocess.DEVNULL, stdout=subprocess.DEVNULL,
            stderr=subprocess.PIPE,
        )
        if hasattr(os, "setpriority"):
            _loudness_lower_priority(proc.pid)
        _out, err = proc.communicate(timeout=120)
        peak_text = (err or b"").decode("utf-8", errors="ignore")
        peak_match = re.findall(r"max_volume:\s*(-?\d+(?:\.\d+)?)\s*dB", peak_text)
        if peak_match:
            peak_db = float(peak_match[-1])
    except Exception:
        if proc is not None:
            try:
                proc.kill()
                proc.communicate(timeout=5)
            except Exception:
                pass
        peak_db = None
    return val, peak_db


def analyze_loudness_async(audio_path: str):
    """Measure + cache loudness for a file in the background if not already done."""
    if not audio_path:
        return
    _loudness_load_cache()
    if loudness_gain_db_cached(audio_path) is not None:
        return
    with _loudness_lock:
        if audio_path in _loudness_inflight:
            return
        _loudness_inflight.add(audio_path)

    def _work():
        try:
            sig = _loudness_file_sig(audio_path)
            with _loudness_sem:
                lufs, peak_db = _measure_loudness_lufs(audio_path)
            if lufs is not None and sig is not None:
                with _loudness_lock:
                    _loudness_cache[audio_path] = {
                        "i": lufs, "peak_db": peak_db, "mtime": sig[0], "size": sig[1],
                    }
                    _loudness_save_cache()
                try:
                    _diag(f"[LOUDNESS] {os.path.basename(audio_path)} I={lufs:.1f} LUFS "
                          f"peak={peak_db if peak_db is not None else 'n/a'}dB "
                          f"gain={_loudness_gain_from_lufs(lufs, peak_db):+.1f}dB")
                except Exception:
                    pass
        finally:
            with _loudness_lock:
                _loudness_inflight.discard(audio_path)

    threading.Thread(target=_work, daemon=True).start()

# --- Logging Setup ---
def setup_logging():
    """Setup comprehensive logging system"""
    # Create log filename with today's date
    log_filename = LOGS_DIR / f"singws_{datetime.now().strftime('%Y-%m-%d')}.log"
    
    # Create rotating file handler (keeps last 7 days)
    # Format: [HH:MM:SS] [LEVEL] message
    formatter = logging.Formatter(
        '[%(asctime)s] [%(levelname)s] %(message)s',
        datefmt='%H:%M:%S'
    )
    
    # Also log to console for development
    console_handler = logging.StreamHandler()
    console_handler.setFormatter(formatter)
    
    # Setup root logger
    logger = logging.getLogger()
    logger.setLevel(logging.INFO)
    try:
        file_handler = logging.handlers.TimedRotatingFileHandler(
            filename=str(log_filename),
            when='midnight',
            interval=1,
            backupCount=7,
            encoding='utf-8'
        )
        file_handler.setFormatter(formatter)
        logger.addHandler(file_handler)
    except Exception as e:
        print(f"SingWS log file unavailable ({log_filename}): {e}")
    logger.addHandler(console_handler)
    
    return logger

# Initialize logging
logger = setup_logging()

_MAC_LOCATION_DELEGATE_CLASS = None

def _diag(msg: str):
    """Write diagnostic messages to both terminal and SingWS log."""
    try:
        print(msg)
    except Exception:
        pass
    try:
        logging.info(msg)
    except Exception:
        pass

def _network_log(msg: str):
    _diag(f"[NETWORK-SYNC] {msg}")

def _network_safe_body(resp, limit: int = 300) -> str:
    try:
        return str(getattr(resp, "text", "") or "")[:limit]
    except Exception:
        return ""

def _network_normalize_base_url(base_url: str) -> str:
    base = str(base_url or "").strip().rstrip("/")
    if base and "://" not in base:
        base = "https://" + base
    return base

def remote_request_song_key(singer: str = "", artist: str = "", title: str = "") -> str:
    """Stable loose key used only to prevent stale server requests resurrecting."""
    def norm(value: str) -> str:
        return re.sub(r"[^a-z0-9]+", " ", str(value or "").lower()).strip()
    parts = [norm(singer), norm(artist), norm(title)]
    return "|".join(parts)

def probe_network_sync_status(
    base_url: str,
    tenant: str,
    api_key: str = "",
    *,
    timeout_sec: float = 6.0,
    requests_module=None,
) -> dict:
    """Probe the request-server endpoints used by desktop sync/status.

    The live request intake endpoint is authoritative for "connected" because
    that is the path singers depend on. Other endpoints are reported as partial
    sync details so the UI can stop spinning and show the real failing piece.
    """
    req = requests_module or requests
    base = _network_normalize_base_url(base_url)
    user = str(tenant or "").strip()
    key = str(api_key or "").strip()
    timeout = max(1.0, float(timeout_sec or 6.0))
    headers = {
        "Accept": "application/json",
        "User-Agent": "SingWS/network-sync",
    }
    if key:
        headers["X-API-Key"] = key

    result = {
        "ok": False,
        "connected": False,
        "partial": False,
        "message": "",
        "base_url": base,
        "tenant": user,
        "accepting": None,
        "checks": {},
        "errors": [],
        "endpoints": {
            "request_intake": f"{base}/get_requests.php" if base else "",
            "accepting": f"{base}/tenants/{user}/accepting.txt" if base else "",
            "host_controls": f"{base}/api/v1/host_commands.php" if base else "",
            "singer_history": f"{base}/api/v1/singer_history_sync.php" if base else "",
            "rotation": f"{base}/post_rotation.php" if base else "",
            "queue_clear": f"{base}/api/v1/clear_remote_queue.php" if base else "",
            "queue_order": f"{base}/api/v1/set_remote_request_order.php" if base else "",
        },
    }

    def record(name: str, ok: bool, status=None, message: str = "", *, body: str = "", skipped: bool = False):
        check = {
            "ok": bool(ok),
            "status": status,
            "message": str(message or ""),
            "body": str(body or ""),
            "skipped": bool(skipped),
        }
        result["checks"][name] = check
        if skipped:
            _network_log(f"{name}: skipped {message}")
        elif ok:
            _network_log(f"{name}: ok status={status} {message}")
        else:
            detail = f"{name}: failed status={status} {message}".strip()
            if body:
                detail += f" body={body!r}"
            result["errors"].append(detail)
            _network_log(detail)
        return check

    if not base or not base.startswith(("http://", "https://")):
        record("config", False, message="Missing or invalid Base URL")
        result["message"] = "Missing or invalid Base URL"
        return result
    if not user:
        record("config", False, message="Missing User ID")
        result["message"] = "Missing User ID"
        return result

    host = ""
    try:
        from urllib.parse import urlparse
        host = (urlparse(base).hostname or "").lower()
    except Exception:
        host = ""
    if host == "wskar.com":
        _network_log("base_url host is wskar.com; beta deployments should use https://beta.wskar.com")
    _network_log(f"sync requested base_url={base} tenant={user} api_key={'set' if key else 'missing'} timeout={timeout:.1f}s")

    request_url = result["endpoints"]["request_intake"]
    try:
        _network_log(f"request sent name=request_intake method=GET url={request_url}")
        resp = req.get(
            request_url,
            params={"user": user, "sync": "1"},
            headers=headers,
            timeout=timeout,
        )
        body = _network_safe_body(resp)
        status = getattr(resp, "status_code", None)
        _network_log(f"response name=request_intake status={status}")
        if status == 200:
            try:
                resp.json()
                record("request_intake", True, status, "request intake reachable")
            except Exception as e:
                record("request_intake", False, status, f"invalid JSON: {e}", body=body)
        elif status in (401, 403):
            record("request_intake", False, status, "request intake rejected credentials", body=body)
        else:
            record("request_intake", False, status, "request intake failed", body=body)
    except requests.exceptions.Timeout as e:
        record("request_intake", False, message=f"timeout after {timeout:.1f}s: {e}")
    except requests.exceptions.ConnectionError as e:
        record("request_intake", False, message=f"connection error: {e}")
    except Exception as e:
        record("request_intake", False, message=f"{type(e).__name__}: {e}")

    accepting_url = result["endpoints"]["accepting"]
    try:
        _network_log(f"request sent name=accepting method=GET url={accepting_url}")
        resp = req.get(accepting_url, params={"_": int(time.time())}, timeout=min(timeout, 5.0))
        body = _network_safe_body(resp)
        status = getattr(resp, "status_code", None)
        _network_log(f"response name=accepting status={status}")
        if status == 200:
            txt = body.strip()
            if txt in ("0", "1"):
                result["accepting"] = (txt == "1")
                record("accepting", True, status, f"accepting={txt}")
            else:
                record("accepting", False, status, "unexpected accepting.txt body", body=body)
        else:
            record("accepting", False, status, "accepting state unavailable", body=body)
    except requests.exceptions.Timeout as e:
        record("accepting", False, message=f"timeout after {min(timeout, 5.0):.1f}s: {e}")
    except Exception as e:
        record("accepting", False, message=f"{type(e).__name__}: {e}")

    if key:
        host_url = result["endpoints"]["host_controls"]
        try:
            _network_log(f"request sent name=host_controls method=GET url={host_url}")
            resp = req.get(
                host_url,
                params={"user": user, "action": "poll"},
                headers=headers,
                timeout=min(timeout, 4.0),
            )
            status = getattr(resp, "status_code", None)
            body = _network_safe_body(resp)
            _network_log(f"response name=host_controls status={status}")
            record("host_controls", status == 200, status, "host controls poll", body="" if status == 200 else body)
        except requests.exceptions.Timeout as e:
            record("host_controls", False, message=f"timeout after {min(timeout, 4.0):.1f}s: {e}")
        except Exception as e:
            record("host_controls", False, message=f"{type(e).__name__}: {e}")
    else:
        record("host_controls", True, message="API key not configured", skipped=True)

    # Read-only reachability probes. 400/405 still prove the endpoint exists but
    # does not support GET, which is enough for a sync status check.
    for name, url in (
        ("singer_history", result["endpoints"]["singer_history"]),
        ("rotation", result["endpoints"]["rotation"]),
    ):
        try:
            _network_log(f"request sent name={name} method=GET url={url}")
            resp = req.get(url, params={"user": user, "_probe": "1"}, headers=headers, timeout=min(timeout, 4.0))
            status = getattr(resp, "status_code", None)
            body = _network_safe_body(resp)
            _network_log(f"response name={name} status={status}")
            ok = status in (200, 400, 405)
            record(name, ok, status, "endpoint reachable" if ok else "endpoint unavailable", body="" if ok else body)
        except requests.exceptions.Timeout as e:
            record(name, False, message=f"timeout after {min(timeout, 4.0):.1f}s: {e}")
        except Exception as e:
            record(name, False, message=f"{type(e).__name__}: {e}")

    request_ok = bool(result["checks"].get("request_intake", {}).get("ok"))
    result["connected"] = request_ok
    result["ok"] = request_ok
    supporting_failures = [
        name for name, check in result["checks"].items()
        if name != "request_intake" and not check.get("ok") and not check.get("skipped")
    ]
    result["partial"] = bool(request_ok and supporting_failures)
    if request_ok and supporting_failures:
        result["message"] = "Connected; partial sync issue: " + ", ".join(supporting_failures)
    elif request_ok:
        result["message"] = "Connected / Synced"
    else:
        first = result["errors"][0] if result["errors"] else "Sync failed"
        result["message"] = first
    _network_log(f"final UI state ok={result['ok']} partial={result['partial']} message={result['message']}")
    return result

def _load_json_file(path: Path, default, *, expected_type=None, label: str = "JSON"):
    try:
        if not path.exists():
            return default
        with open(path, "r", encoding="utf-8") as f:
            value = json.load(f)
        if expected_type is not None and not isinstance(value, expected_type):
            print(f"{label} ignored: expected {expected_type.__name__} in {path}")
            return default
        return value
    except Exception as e:
        print(f"{label} ignored: could not load {path}: {e}")
        return default

def _save_json_atomic(path: Path, value) -> None:
    _perf_t0 = time.perf_counter()
    path.parent.mkdir(parents=True, exist_ok=True)
    fd, tmp_name = tempfile.mkstemp(prefix=f".{path.name}.", suffix=".tmp", dir=str(path.parent))
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            json.dump(value, f, indent=2)
            f.write("\n")
        os.replace(tmp_name, path)
        _perf_record(f"json_write:{path.name}", (time.perf_counter() - _perf_t0) * 1000.0)
    except Exception:
        try:
            os.unlink(tmp_name)
        except Exception:
            pass
        raise

class PerfStats:
    def __init__(self):
        self._lock = threading.Lock()
        self._stats = {}

    def record(self, name: str, ms: float):
        try:
            ms = float(ms)
        except Exception:
            return
        with self._lock:
            s = self._stats.setdefault(str(name), {"count": 0, "total": 0.0, "max": 0.0, "slow": 0})
            s["count"] += 1
            s["total"] += ms
            if ms > s["max"]:
                s["max"] = ms
            if ms >= _perf_threshold_ms(str(name)):
                s["slow"] += 1

    def snapshot(self):
        with self._lock:
            rows = []
            for name, s in self._stats.items():
                count = int(s.get("count", 0) or 0)
                if count <= 0:
                    continue
                total = float(s.get("total", 0.0) or 0.0)
                rows.append({
                    "name": name,
                    "count": count,
                    "avg": total / max(1, count),
                    "max": float(s.get("max", 0.0) or 0.0),
                    "slow": int(s.get("slow", 0) or 0),
                })
            return sorted(rows, key=lambda r: (r["max"], r["avg"]), reverse=True)

PERF_STATS = PerfStats()
_PERF_LAST_PRINT = {}

def _perf_threshold_ms(name: str) -> float:
    n = str(name or "").lower()
    if "audio" in n or "meter" in n:
        return 5.0
    if "ui_" in n or "frame" in n or "render" in n or "paint" in n or "tick" in n:
        return 16.0
    if "search" in n:
        return 50.0
    if "server" in n or "json" in n or "db" in n or "sync" in n or "save" in n:
        return 100.0
    return 50.0

def _perf_record(name: str, ms: float):
    try:
        PERF_STATS.record(name, ms)
    except Exception:
        pass

def _perf_log_if_slow(name: str, ms: float):
    try:
        _perf_record(name, ms)
        if float(ms) >= _perf_threshold_ms(name):
            now = time.monotonic()
            key = str(name)
            last = float(_PERF_LAST_PRINT.get(key, 0.0) or 0.0)
            if now - last < 1.0:
                return
            _PERF_LAST_PRINT[key] = now
            print(f"[PERF] {name} took {float(ms):.0f}ms")
    except Exception:
        pass

