DISC_ID_PRIORITY = [
    "SC",
    "CC",
    "KARAFUN",
    "KV",
    "SBI",
    "ME",
    "CB",
]

DISC_BRAND_ALIASES = {
    "KV": ["KV", "KARAOKE VERSION", "KARAOKEVERSION", "KARAOKE-VERSION", "KARAOKE_VERSION"],
    "ZM": ["ZM", "ZOOM", "ZDL", "ZOOM DL", "ZOOMDL", "ZOOM KARAOKE"],
    "SC": ["SC", "SOUNDCHOICE", "SOUND CHOICE", "SOUND-CHOICE", "SOUND_CHOICE"],
    "CC": ["CC"],  # Chris Call Karaoke — always labeled just "CC" (no name variants / code prefixes)
    "CB": ["CB", "CHARTBUSTER", "CHART BUSTER", "CHART-BUSTER", "CHART_BUSTER"],
    "PT": ["PT", "PARTY TYME", "PARTYTYME", "PARTY-TYME", "PARTY_TYME", "PARTY TIME", "PARTYTIME"],
    "SF": ["SF", "SUNFLY", "SUN FLY", "SUN-FLY", "SUN_FLY"],
    "SBI": ["SBI", "SBI KARAOKE"],
    "KARAFUN": ["KARAFUN", "KARA FUN", "KARA-FUN", "KARA_FUN"],
    "ME": ["ME", "MR ENTERTAINER", "MRENTERTAINER", "MR-ENTERTAINER"],
}

_DISC_BRAND_CANONICAL_BY_KEY = {}
_DISC_BRAND_ALIAS_KEYS_BY_CANONICAL = {}
for _canonical_brand, _aliases in DISC_BRAND_ALIASES.items():
    _keys = set()
    for _alias in [_canonical_brand] + list(_aliases):
        _key = re.sub(r"[^A-Z0-9]+", "", str(_alias or "").upper())
        if _key:
            _DISC_BRAND_CANONICAL_BY_KEY[_key] = _canonical_brand
            _keys.add(_key)
    _DISC_BRAND_ALIAS_KEYS_BY_CANONICAL[_canonical_brand] = _keys

def build_bg_index(roots, out_path=BG_MUSIC_INDEX_PATH, max_workers=8, fast_only=True):
    """
    Build/refresh a fast BG music index. Phase 1 is path/size/mtime only (instant at 60k+ files).
    If fast_only=False, will also probe tags/duration using mutagen in a thread pool.
    """
    import os, time, hashlib, json
    from pathlib import Path
    audio_exts = {'.mp3','.wav','.flac','.m4a','.aac','.ogg','.mp4'}

    roots = [str(Path(r)) for r in roots or [] if r and os.path.isdir(r)]
    if not roots:
        data = {"version": 1, "scanned_at": int(time.time()), "roots": [], "track_count": 0, "tracks": []}
        out_path.write_text(json.dumps(data, indent=2), encoding="utf-8")
        return data

    # Load existing for incremental checks
    existing = {}
    try:
        if out_path.exists():
            existing = json.loads(out_path.read_text(encoding="utf-8"))
    except Exception:
        existing = {}
    prev = {t.get("path"): (t.get("size",0), t.get("mtime",0)) for t in existing.get("tracks", [])}

    files = []
    for root in roots:
        for dirpath, _, filenames in os.walk(root):
            base = os.path.basename(dirpath)
            if base.startswith('.'):   # skip dot folders
                continue
            for fn in filenames:
                if fn.startswith('.'):  # skip dotfiles / ._*
                    continue
                ext = os.path.splitext(fn)[1].lower()
                if ext in audio_exts:
                    p = os.path.join(dirpath, fn)
                    try:
                        st = os.stat(p)
                    except Exception:
                        continue
                    files.append((p, st.st_size, int(st.st_mtime), ext))

    tracks, to_probe = [], []
    for p, size, mtime, ext in files:
        needs_probe = prev.get(p) != (size, mtime)
        entry = {
            "id": hashlib.blake2b(p.encode("utf-8"), digest_size=8).hexdigest(),
            "path": p,
            "file": os.path.basename(p),
            "ext": ext,
            "size": size,
            "mtime": mtime,
            "title": None, "artist": None, "album": None, "duration": None,
        }
        tracks.append(entry)
        if needs_probe and not fast_only:
            to_probe.append(entry)

    # Optional parallel tag probe (lazy by default)
    if to_probe:
        def _probe(e):
            try:
                if MutagenFile:
                    mf = MutagenFile(e["path"])
                    if mf:
                        if getattr(mf, "info", None) and getattr(mf.info, "length", None):
                            e["duration"] = int(mf.info.length + 0.5)
                        tags = getattr(mf, "tags", None)
                        def _first(*ks):
                            for k in ks:
                                v = tags.get(k) if tags and k in tags else None
                                if isinstance(v, list) and v: return str(v[0])
                                if v: return str(v)
                            return None
                        e["title"]  = _first("TIT2","title","TITLE")
                        e["artist"] = _first("TPE1","artist","ARTIST")
                        e["album"]  = _first("TALB","album","ALBUM")
            except Exception:
                pass
            return e

        from concurrent.futures import ThreadPoolExecutor
        with ThreadPoolExecutor(max_workers=max_workers) as ex:
            for _ in ex.map(_probe, to_probe):
                pass

    data = {"version": 1, "scanned_at": int(time.time()), "roots": roots, "track_count": len(tracks), "tracks": tracks}
    tmp = out_path.with_suffix(".tmp")
    tmp.write_text(json.dumps(data, indent=2), encoding="utf-8")
    tmp.replace(out_path)
    print(f"BG index written: {out_path} ({len(tracks)} tracks)")
    return data

def _disc_brand_key(value) -> str:
    return re.sub(r"[^A-Z0-9]+", "", str(value or "").upper())

def _disc_brand_prefix_key(value) -> str:
    key = _disc_brand_key(value)
    m = re.match(r"([A-Z]+)", key)
    return m.group(1) if m else key[:8]

def _disc_brand_value_segments(value) -> list[str]:
    raw = str(value or "").strip()
    if not raw:
        return []
    values = [raw]
    try:
        stem = Path(raw).stem if any(ch in raw for ch in ("/", "\\")) else raw
    except Exception:
        stem = raw
    for part in re.split(r"\s+-\s+|[|/\\()\[\]{}]+", stem):
        part = str(part or "").strip()
        if part and part not in values:
            values.append(part)
    return values

def karaoke_brand_match_info(value) -> dict:
    """Return canonical karaoke brand match metadata for a raw disc/company value."""
    raw = str(value or "").strip()
    key = _disc_brand_key(raw)
    info = {
        "raw": raw,
        "normalized": key,
        "canonical": "",
        "confidence": 0,
        "matched_alias": "",
        "match_type": "unknown",
    }
    if not key:
        info["match_type"] = "empty"
        return info

    known = _DISC_BRAND_CANONICAL_BY_KEY.get(key)
    if known:
        info.update({
            "canonical": known,
            "confidence": 100,
            "matched_alias": key,
            "match_type": "alias_exact",
        })
        return info

    candidates = []
    for canonical, alias_keys in _DISC_BRAND_ALIAS_KEYS_BY_CANONICAL.items():
        for alias_key in alias_keys:
            if not alias_key or not key.startswith(alias_key):
                continue
            remainder = key[len(alias_key):]
            long_alias = len(alias_key) >= 4
            coded_suffix = bool(re.match(r"^[0-9]", remainder or ""))
            separator_free_text = long_alias and bool(remainder)
            if not remainder or coded_suffix or separator_free_text:
                confidence = 94 if coded_suffix else (90 if separator_free_text else 88)
                candidates.append((confidence, len(alias_key), canonical, alias_key))
    if candidates:
        confidence, _alias_len, canonical, alias_key = max(candidates)
        info.update({
            "canonical": canonical,
            "confidence": confidence,
            "matched_alias": alias_key,
            "match_type": "alias_prefix",
        })
    return info

def canonical_disc_brand(value, allow_unknown: bool = True) -> str:
    raw = str(value or "").strip()
    if not raw:
        return ""
    for segment in _disc_brand_value_segments(raw):
        info = karaoke_brand_match_info(segment)
        if info.get("canonical"):
            return str(info.get("canonical") or "")
    return raw.upper() if allow_unknown else ""

def normalize_disc_priority(value, max_items: int = 10):
    """Normalize user priority input into canonical disc/brand prefixes (max 10)."""
    out = []
    seen = set()
    try:
        if isinstance(value, str):
            parts = value.split(",")
        elif isinstance(value, (list, tuple)):
            parts = list(value)
        else:
            parts = []
        for raw in parts:
            p = canonical_disc_brand(raw, allow_unknown=True)
            if not p or p in seen:
                continue
            seen.add(p)
            out.append(p)
            if len(out) >= int(max_items):
                break
    except Exception:
        return []
    return out

def normalize_singer_selected_disc_brand(value) -> str:
    """Return a known singer-selected brand alias, or blank for unknown/empty input."""
    return canonical_disc_brand(value, allow_unknown=False)

def disc_value_matches_brand(value, brand) -> bool:
    canonical = canonical_disc_brand(brand, allow_unknown=True)
    if not canonical:
        return False
    for segment in _disc_brand_value_segments(value):
        info = karaoke_brand_match_info(segment)
        if info.get("canonical") == canonical:
            return True
        if not info.get("canonical") and _disc_brand_key(segment).startswith(_disc_brand_key(canonical)):
            return True
    return False

def disc_id_matches_brand(disc_id, brand) -> bool:
    return disc_value_matches_brand(disc_id, brand)

def disc_brand_candidate_values(track) -> list[str]:
    if not isinstance(track, dict):
        return []
    values = []
    for key in ("disc_id", "discid", "DiscID", "Vendor", "vendor"):
        value = str(track.get(key) or "").strip()
        if value and value not in values:
            values.append(value)
    for key in ("display", "filename", "file", "path"):
        value = str(track.get(key) or "").strip()
        if not value:
            continue
        if key == "path":
            try:
                value = Path(value).name
            except Exception:
                value = os.path.basename(value)
        for segment in _disc_brand_value_segments(value):
            if segment and segment not in values:
                values.append(segment)
    return values

def _best_unknown_disc_brand_value(candidates: list[str]) -> str:
    for value in candidates or []:
        key = _disc_brand_key(value)
        if re.match(r"^[A-Z]{1,10}[0-9]", key):
            return value
    return candidates[0] if candidates else ""

def track_matches_disc_brand(track, brand) -> bool:
    return any(disc_value_matches_brand(value, brand) for value in disc_brand_candidate_values(track))

def effective_disc_priority(host_priority, singer_brand_raw="", singer_override=None, max_items: int = 10):
    host = normalize_disc_priority(host_priority, max_items=max_items)
    override = normalize_disc_priority(singer_override or [], max_items=max_items)
    selected_raw = str(singer_brand_raw or "").strip()
    selected = normalize_singer_selected_disc_brand(selected_raw)
    source = "request" if selected_raw else ""

    if not selected and not selected_raw and override:
        selected = override[0]
        selected_raw = selected
        source = "singer_history"

    if selected:
        effective = [selected] + [p for p in host if p != selected]
    else:
        effective = list(host)
    return {
        "host": host,
        "singer_raw": selected_raw,
        "singer_normalized": selected,
        "singer_source": source,
        "effective": effective,
        "unknown_ignored": bool(selected_raw and not selected),
    }

def disc_priority_available_versions(matches):
    versions = []
    for m in matches or []:
        if not isinstance(m, dict):
            continue
        disc = str(m.get("disc_id") or m.get("discid") or "").strip()
        if disc and disc not in versions:
            versions.append(disc)
    return versions

def build_disc_brand_scan_report(tracks, max_unknowns: int = 50) -> dict:
    report = {
        "track_count": 0,
        "raw_values": [],
        "canonical_counts": {},
        "unknown_prefixes": [],
    }
    raw_stats = {}
    unknown_stats = {}
    for track in tracks or []:
        if not isinstance(track, dict):
            continue
        report["track_count"] += 1
        candidates = disc_brand_candidate_values(track)
        chosen = ""
        chosen_info = None
        for value in candidates:
            info = karaoke_brand_match_info(value)
            if info.get("canonical"):
                chosen = value
                chosen_info = info
                break
        if chosen_info is None:
            chosen = _best_unknown_disc_brand_value(candidates)
            chosen_info = karaoke_brand_match_info(chosen)

        raw_key = chosen or "(blank)"
        stat = raw_stats.setdefault(raw_key, {
            "raw": raw_key,
            "normalized": chosen_info.get("normalized", ""),
            "canonical": chosen_info.get("canonical", ""),
            "confidence": int(chosen_info.get("confidence", 0) or 0),
            "count": 0,
            "matched_alias": chosen_info.get("matched_alias", ""),
            "match_type": chosen_info.get("match_type", "unknown"),
        })
        stat["count"] += 1

        canonical = str(chosen_info.get("canonical") or "")
        if canonical:
            report["canonical_counts"][canonical] = report["canonical_counts"].get(canonical, 0) + 1
        else:
            prefix = _disc_brand_prefix_key(chosen)
            if prefix:
                unk = unknown_stats.setdefault(prefix, {"prefix": prefix, "count": 0, "examples": []})
                unk["count"] += 1
                if chosen and chosen not in unk["examples"] and len(unk["examples"]) < 5:
                    unk["examples"].append(chosen)

    report["raw_values"] = sorted(raw_stats.values(), key=lambda item: (-item["count"], item["raw"]))[:200]
    report["unknown_prefixes"] = sorted(unknown_stats.values(), key=lambda item: (-item["count"], item["prefix"]))[:int(max_unknowns or 50)]
    return report

def request_preferred_disc_brand(req):
    if not isinstance(req, dict):
        return ""
    keys = (
        "preferred_brand",
        "preferred_version",
        "preferred_disc",
        "preferred_disc_id",
        "preferred_disc_priority",
        "brand",
        "version",
        "disc_id",
        "discid",
    )
    for key in keys:
        value = req.get(key)
        if isinstance(value, (list, tuple)):
            value = value[0] if value else ""
        value = str(value or "").strip()
        if key == "preferred_disc_priority" and "," in value:
            value = next((part.strip() for part in value.split(",") if part.strip()), "")
        if value:
            return value
    return ""

def pick_by_disc_priority(matches, priority_list=None):
    priorities = normalize_disc_priority(priority_list if priority_list is not None else DISC_ID_PRIORITY)
    if not priorities:
        return matches[0]
    for prefix in priorities:
        # Handle both 'disc_id' and 'discid' field names
        prefix_matches = [
            m for m in matches
            if track_matches_disc_brand(m, prefix)
        ]
        if prefix_matches:
            return prefix_matches[0]
    return matches[0]

# Add this new class after your existing classes, before KaraokeApp
# Lead-silence detection for better BG->karaoke transition timing (GStreamer-only).
def detect_lead_silence(path, noise_db=-50.0, min_silence=0.5) -> float:
    """
    Scan the first ~30s using GStreamer's level element and return initial
    silence length (content-start offset). Returns 0.0 on any error/no-match.
    """
    try:
        if not path or not os.path.exists(path):
            return 0.0

        max_scan_sec = 30.0
        timeout_sec = 15.0
        noise_db = float(noise_db)
        min_silence = max(0.0, float(min_silence))

        pipeline = Gst.Pipeline.new("silence_scan")
        src = Gst.ElementFactory.make("filesrc", None)
        dbin = Gst.ElementFactory.make("decodebin", None)
        q = Gst.ElementFactory.make("queue", None)
        aconv = Gst.ElementFactory.make("audioconvert", None)
        ares = Gst.ElementFactory.make("audioresample", None)
        level = Gst.ElementFactory.make("level", None)
        sink = Gst.ElementFactory.make("fakesink", None)

        if not all([pipeline, src, dbin, q, aconv, ares, level, sink]):
            return 0.0

        src.set_property("location", str(path))
        try:
            level.set_property("post-messages", True)
        except Exception:
            pass
        try:
            # 100ms windows
            level.set_property("interval", int(100 * Gst.MSECOND))
        except Exception:
            pass
        try:
            sink.set_property("sync", False)
        except Exception:
            pass

        for el in (src, dbin, q, aconv, ares, level, sink):
            pipeline.add(el)

        src.link(dbin)
        q.link(aconv)
        aconv.link(ares)
        ares.link(level)
        level.link(sink)

        def on_pad_added(_db, pad):
            try:
                caps = pad.query_caps(None)
                s = caps.to_string() if caps else ""
                if not s.startswith("audio/"):
                    return
                sink_pad = q.get_static_pad("sink")
                if sink_pad and not sink_pad.is_linked():
                    pad.link(sink_pad)
            except Exception:
                pass

        dbin.connect("pad-added", on_pad_added)

        bus = pipeline.get_bus()
        pipeline.set_state(Gst.State.PLAYING)

        saw_non_silent = False
        initial_silence_end = 0.0
        t0 = time.monotonic()

        while True:
            now = time.monotonic()
            if (now - t0) > timeout_sec:
                break

            # Hard cap at 30s of media progression when available
            try:
                ok_pos, pos = pipeline.query_position(Gst.Format.TIME)
                if ok_pos and pos is not None and pos >= int(max_scan_sec * Gst.SECOND):
                    break
            except Exception:
                pass

            msg = bus.timed_pop_filtered(
                int(200 * Gst.MSECOND),
                Gst.MessageType.ERROR | Gst.MessageType.EOS | Gst.MessageType.ELEMENT,
            )
            if msg is None:
                continue

            mtype = msg.type
            if mtype == Gst.MessageType.ERROR:
                break
            if mtype == Gst.MessageType.EOS:
                break
            if mtype != Gst.MessageType.ELEMENT:
                continue

            s = msg.get_structure()
            if s is None or s.get_name() != "level":
                continue

            ts_sec = now - t0
            try:
                if s.has_field("running-time"):
                    ts = s.get_value("running-time")
                    if ts is not None:
                        ts_sec = float(ts) / float(Gst.SECOND)
            except Exception:
                pass

            rms_db = -120.0
            try:
                vals = s.get_value("rms")
                if vals is not None:
                    nums = []
                    for v in vals:
                        try:
                            fv = float(v)
                            if fv > -1e8:
                                nums.append(fv)
                        except Exception:
                            continue
                    if nums:
                        rms_db = max(nums)
            except Exception:
                pass

            if rms_db <= noise_db:
                if not saw_non_silent:
                    initial_silence_end = max(initial_silence_end, ts_sec)
            else:
                saw_non_silent = True
                if initial_silence_end >= min_silence:
                    return max(0.0, min(10.0, float(initial_silence_end)))
                return 0.0

        return 0.0
    except Exception:
        return 0.0
    finally:
        try:
            if 'pipeline' in locals() and pipeline is not None:
                pipeline.set_state(Gst.State.NULL)
        except Exception:
            pass

# Trailing-silence (dead-air) detection tunables for background music.
BG_SILENCE_LEVEL = 0.02     # RMS meter (0..1) at/below this counts as silence
BG_SILENCE_MIN_S = 1.2      # sustained silence required before advancing
BG_SILENCE_TAIL_WINDOW = 45.0  # only act within this many seconds of the track end
BGM_UNKNOWN_ANALYSIS_PREGAIN = 0.75  # only when BG normalization is enabled and cache misses


class BackgroundMusicPlayer(QObject):
    """Background music player that integrates with karaoke playback - OPTIMIZED VERSION"""
    
    def __init__(self, parent=None):
        super().__init__(parent)
        self.playlist = []
        self.current_index = 0
        self.is_playing = False
        self.is_shuffled = False
        self.volume = 0.8  # Default lower volume for background
        self.stop_after_current = False  # Session-only; not persisted.
        # Set when manager mutates playlist while idle; realign pipeline on next play.
        self._pipeline_realign_needed = False

        # Master enable/disable
        self.enabled = True
        
        # NEW: Artwork caching system for instant UI updates
        self.artwork_cache = {}  # file_path -> QPixmap
        self.artwork_cache_size = 50  # Cache up to 50 artworks
        self.precache_count = 5  # Pre-cache this many tracks ahead
        
        # MAIN PIPELINE (current track)
        self.gst_bg_pipeline = None
        self._gst_bg_norm = {}
        
        # CROSSFADE PIPELINE (next track for seamless transitions)
        self.gst_crossfade_pipeline = None
        self.crossfade_active = False
        self.crossfade_duration_ms = 3000  # 3 second crossfade
        
        # Fade timers
        self.fade_timer = QTimer(self)
        self.fade_timer.timeout.connect(self._fade_step)
        self.fade_direction = 0  # 1 for fade in, -1 for fade out, 0 for none
        self.fade_target_volume = 0.3
        self.fade_step_size = 0.05
        
        # Crossfade timer
        self.crossfade_timer = QTimer(self)
        self.crossfade_timer.timeout.connect(self._crossfade_step)
        self.crossfade_progress = 0.0  # 0.0 = main only, 1.0 = crossfade only
        self.crossfade_step_size = 0.02  # Smaller steps for smoother crossfade
        
        # Track position monitoring for auto-crossfade
        self.position_timer = QTimer(self)
        self.position_timer.timeout.connect(self._check_track_position)
        self.position_timer.start(500)  # Check every 500ms

        # Audio meter for idle overlay visualizer (0.0..1.0).
        self._meter_level = 0.0
        self._meter_last_ts = 0.0
        # Trailing-silence (dead-air) detection for background music. When the
        # tail of a track goes quiet for a sustained moment we advance early
        # instead of letting silence play out.
        self._bg_silence_accum_s = 0.0
        self._bg_silence_last_ts = 0.0
        # Probe fields used to detect stale 'is_playing=True' state.
        self._play_probe_pos = None
        self._play_probe_ts = None
        self._bass_engine = None
        self._bass_fade_generation = 0
        self._bass_crossfade_generation = 0
        self._bg_first_play_logged = False
        self._bg_volume_probe_generation = 0
        self._bg_last_volume_source = "default"
        self._init_bass_engine()

    def _platform_audio_label(self) -> str:
        try:
            machine = platform.machine() or ""
        except Exception:
            machine = ""
        if sys.platform == "darwin" and machine.lower() in {"x86_64", "amd64"}:
            return "macOS Intel"
        if sys.platform == "darwin" and machine.lower() in {"arm64", "aarch64"}:
            return "macOS Apple Silicon"
        return f"{sys.platform} {machine}".strip()

    def _simple_audio_enabled(self) -> bool:
        try:
            host = self.parent()
            return bool(host is None or not hasattr(host, "settings") or host.settings.get("simple_audio_mode", True))
        except Exception:
            return True

    def _bg_volume_diag(self, stage: str, path: str | None = None, extra: str = ""):
        try:
            engine = getattr(self, "_bass_engine", None)
            backend = "BASS" if engine is not None else "GStreamer"
            master = ""
            if engine is not None:
                try:
                    master = f" engine_master={float(engine.master_volume):.3f}"
                except Exception:
                    master = ""
            track = Path(path).name if path else ""
            suffix = f" {extra}" if extra else ""
            _diag(
                f"[BG-VOLUME] stage={stage} platform={self._platform_audio_label()} "
                f"backend={backend} simple_audio={int(self._simple_audio_enabled())} "
                f"normalize={int(self._bg_normalize_active())} eq_bypassed={int(self._simple_audio_enabled())} "
                f"saved_or_ui={float(self.volume):.3f}{master} playing={int(bool(self.is_playing))} "
                f"track={track!r}{suffix}"
            )
        except Exception:
            pass

    def _sync_volume_from_ui_or_settings(self, reason: str) -> float:
        target = self._target_volume_from_ui()
        try:
            target = max(0.0, min(1.0, float(target)))
        except Exception:
            target = 0.8
        self.volume = target
        self._bg_last_volume_source = reason
        engine = getattr(self, "_bass_engine", None)
        if engine is not None:
            try:
                engine.set_master_volume(target)
            except Exception:
                pass
        self._bg_volume_diag(f"sync-target:{reason}", extra=f"target={target:.3f}")
        return target

    def _schedule_volume_state_probe(self, reason: str):
        self._bg_volume_probe_generation += 1
        generation = int(self._bg_volume_probe_generation)

        def _probe(label: str):
            if generation != int(getattr(self, "_bg_volume_probe_generation", 0) or 0):
                return
            path = self.get_active_track_path()
            extra = ""
            try:
                pos, dur = self.get_playback_times()
                extra = f"reason={reason} pos={pos:.2f}s dur={dur:.2f}s"
            except Exception:
                extra = f"reason={reason}"
            self._bg_volume_diag(label, path, extra)

        for ms, label in (
            (0, "play+0s"),
            (1000, "play+1s"),
            (2000, "play+2s"),
            (3000, "play+3s"),
            (4000, "play+4s"),
            (5000, "play+5s"),
        ):
            QTimer.singleShot(ms, lambda l=label: _probe(l))

    def initialize_startup_volume(self):
        target = self._sync_volume_from_ui_or_settings("app-launch")
        engine = getattr(self, "_bass_engine", None)
        if engine is not None:
            try:
                engine.set_master_volume(target)
            except Exception:
                pass
        self._bg_volume_diag("app-launch-init", extra=f"target={target:.3f}")

    def _init_bass_engine(self, output_name: str | None = None) -> bool:
        try:
            # Close old engine first to free BASS resources
            old_engine = getattr(self, "_bass_engine", None)
            if old_engine is not None:
                try:
                    old_engine.close()
                except Exception:
                    pass
                self._bass_engine = None
            
            self._bass_engine = BassBackgroundEngine(output_name=output_name)
            _diag(f"[BG-BASS] BASSmix background engine ready platform={self._platform_audio_label()}")
            # Attach the BGM 10-band graphic EQ ONLY in advanced mode. Simple
            # Audio Mode (default) leaves the EQ out of the chain entirely.
            try:
                parent = self.parent()
                simple = bool(parent.settings.get("simple_audio_mode", True)) if (parent is not None and hasattr(parent, "settings")) else True
                if parent is not None and not simple and hasattr(parent, "_ensure_eq_engines"):
                    parent._ensure_eq_engines()
                bgm_eq = getattr(parent, "bgm_eq", None) if parent is not None else None
                if bgm_eq is not None and not simple:
                    self._bass_engine.set_eq(bgm_eq)
                elif hasattr(self._bass_engine, "set_eq"):
                    self._bass_engine.set_eq(None)
                _diag(f"[BG-BASS] init simple_audio={int(simple)} eq_attached={int(bool(bgm_eq is not None and not simple))}")
            except Exception:
                pass
            return True
        except BassBackgroundError as e:
            self._bass_engine = None
            _diag(f"[BG-BASS] unavailable; GStreamer BG fallback remains active ({e})")
            return False

    def _bass_ready(self) -> bool:
        return getattr(self, "_bass_engine", None) is not None

    def _bass_selected_output_name(self) -> str | None:
        try:
            parent = self.parent()
            selected = parent._get_selected_audio_output_id()
            if selected == "default":
                return None
            for output in parent._refresh_audio_output_cache():
                if output.get("id") == selected:
                    return str(output.get("name") or "").strip() or None
        except Exception:
            pass
        return None

    def _bass_update_meter(self):
        engine = getattr(self, "_bass_engine", None)
        if engine is None:
            return
        try:
            target = engine.meter_level()
            self._meter_level = (self._meter_level * 0.70) + (target * 0.30)
            self._meter_last_ts = time.monotonic()
        except Exception:
            pass

    def _bass_stop_after_fade(self, generation: int):
        if generation != int(getattr(self, "_bass_fade_generation", 0) or 0):
            return
        self.pause()
        try:
            self.volume = self._target_volume_from_ui()
        except Exception:
            pass
    
    def set_enabled(self, flag: bool):
        """Master enable/disable for BG playback."""
        self.enabled = bool(flag)
        if self.enabled:
            # Re-sync desired volume from UI/setting immediately
            try:
                self.volume = self._target_volume_from_ui()
                print(f"[BG] Enabled; desired volume set to {self.volume}")
            except Exception:
                pass
        else:
            # Smoothly fade out if currently playing
            if self.is_playing:
                self.fade_out(500)

    def load_folder(self, folder_path):
        """Load all audio files from a folder into the playlist"""
        import os
        from pathlib import Path
        
        audio_extensions = {'.mp3', '.wav', '.flac', '.m4a', '.aac', '.ogg', '.mp4'}
        
        try:
            folder = Path(folder_path)
            audio_files = []
            
            # Recursively find all audio files
            for file_path in folder.rglob('*'):
                # Skip hidden/system files (._* files on macOS)
                if file_path.name.startswith('.') or file_path.name.startswith('._'):
                    continue
                    
                if file_path.is_file() and file_path.suffix.lower() in audio_extensions:
                    audio_files.append(str(file_path))
            
            if not audio_files:
                print(f"No audio files found in {folder_path}")
                return
            
            # Sort alphabetically for consistent order
            audio_files.sort()
            
            # Stop current playback
            self.stop()
            
            # Clear old artwork cache when loading new folder
            self.clear_artwork_cache()
            
            # Load new playlist
            self.playlist = audio_files
            self.current_index = 0
            self.is_shuffled = False
            
            print(f"Loaded {len(audio_files)} background music tracks from {folder_path}")
            
            # IMMEDIATE UI update - don't wait for background tasks
            if hasattr(self.parent(), 'update_bg_track_display'):
                self.parent().update_bg_track_display()
            
            # Start background pre-caching after UI is updated
            QTimer.singleShot(200, self._start_artwork_precache)
                
        except Exception as e:
            print(f"Failed to load background music folder: {e}")

    def _start_artwork_precache(self):
        """Start background pre-caching of artwork for upcoming tracks"""
        if not self.playlist:
            return
        
        # Cache artwork for current track + next few tracks in background
        tracks_to_cache = []
        for i in range(min(self.precache_count, len(self.playlist))):
            idx = (self.current_index + i) % len(self.playlist)
            track_path = self.playlist[idx]
            if track_path not in self.artwork_cache:
                tracks_to_cache.append(track_path)
        
        if tracks_to_cache:
            print(f"🎨 Starting background pre-cache for {len(tracks_to_cache)} tracks")
            # Use a thread to pre-cache without blocking UI
            import threading
            threading.Thread(
                target=self._precache_artwork_worker,
                args=(tracks_to_cache,),
                daemon=True
            ).start()

    def _precache_artwork_worker(self, tracks_to_cache):
        """Background worker to pre-cache artwork"""
        for i, track_path in enumerate(tracks_to_cache):
            try:
                artwork = self._extract_artwork_sync(track_path)
                if artwork and not artwork.isNull():
                    # Store in cache (thread-safe since we're only writing to new keys)
                    self.artwork_cache[track_path] = artwork
                    
                    # If this is the current track, update UI immediately
                    if (self.playlist and 
                        self.current_index < len(self.playlist) and 
                        track_path == self.playlist[self.current_index]):
                        QTimer.singleShot(0, self._update_ui_with_cached_artwork)
                    
                    # Small delay between extractions to not hammer the disk
                    if i < len(tracks_to_cache) - 1:
                        import time
                        time.sleep(0.1)
                        
            except Exception as e:
                print(f"⚠️ Pre-cache failed for {Path(track_path).name}: {e}")

    def _update_ui_with_cached_artwork(self):
        """Update UI when pre-cached artwork becomes available"""
        if hasattr(self.parent(), 'update_bg_track_display'):
            self.parent().update_bg_track_display()

    def clear_artwork_cache(self):
        """Clear the artwork cache to free memory"""
        self.artwork_cache.clear()
        print("🗑️ Artwork cache cleared")

    def manage_artwork_cache(self):
        """Remove old entries if cache gets too large"""
        if len(self.artwork_cache) > self.artwork_cache_size:
            # Remove the oldest entries (simple approach - remove first half)
            keys_to_remove = list(self.artwork_cache.keys())[:len(self.artwork_cache)//2]
            for key in keys_to_remove:
                del self.artwork_cache[key]
            print(f"🗑️ Trimmed artwork cache to {len(self.artwork_cache)} entries")

    def shuffle_playlist(self):
        """Shuffle the current playlist"""
        if not self.playlist:
            return
            
        import random
        
        # Remember current track
        current_track = self.playlist[self.current_index] if self.current_index < len(self.playlist) else None
        
        # Shuffle the playlist
        shuffled = self.playlist.copy()
        random.shuffle(shuffled)
        
        # If we were playing a track, make it the first in the shuffled list
        if current_track and current_track in shuffled:
            shuffled.remove(current_track)
            shuffled.insert(0, current_track)
            self.current_index = 0
        
        self.playlist = shuffled
        self.is_shuffled = True
        
        print(f"Shuffled background music playlist ({len(self.playlist)} tracks)")
        
        # IMMEDIATE UI update
        if hasattr(self.parent(), 'update_bg_track_display'):
            self.parent().update_bg_track_display()

        # Restart pre-caching for new order
        QTimer.singleShot(200, self._start_artwork_precache)

    def get_current_track_name(self):
        """Get just the filename of the current track"""
        if not self.playlist or self.current_index >= len(self.playlist):
            return "No track"
        
        from pathlib import Path
        return Path(self.playlist[self.current_index]).stem

    def get_playlist_info(self):
        """Get playlist information string"""
        if not self.playlist:
            return "No folder loaded"
        
        track_name = self.get_current_track_name()
        crossfade_info = " (crossfading)" if self.crossfade_active else ""
        return f"{track_name} ({self.current_index + 1}/{len(self.playlist)}){crossfade_info}"
    
    def get_current_track_info(self):
        """Get info about currently loaded track"""
        return self.get_playlist_info()

    def get_active_track_path(self) -> str:
        """Best-effort path for the track currently sounding from the live engine."""
        if self._bass_ready():
            try:
                deck = self._bass_engine.secondary or self._bass_engine.primary
                if deck is not None:
                    return str(deck.path)
            except Exception:
                pass
        try:
            p = self.gst_bg_pipeline
            if p is not None:
                filesrc = p.get_by_name("bg_music_filesrc")
                if filesrc is not None:
                    loc = filesrc.get_property("location")
                    if loc:
                        return str(loc)
        except Exception:
            pass
        try:
            if self.playlist and 0 <= int(self.current_index) < len(self.playlist):
                return str(self.playlist[int(self.current_index)])
        except Exception:
            pass
        return ""
        
    def _create_bg_pipeline(self, file_path, pipeline_name="bg_music"):
        """Create GStreamer pipeline for background music with a lightweight meter branch."""
        pipeline = Gst.Pipeline.new(pipeline_name)

        filesrc = Gst.ElementFactory.make("filesrc", f"{pipeline_name}_filesrc")
        filesrc.set_property("location", file_path)

        decodebin = Gst.ElementFactory.make("decodebin", f"{pipeline_name}_decodebin")

        audioconvert = Gst.ElementFactory.make("audioconvert", f"{pipeline_name}_audioconvert")
        audioresample = Gst.ElementFactory.make("audioresample", f"{pipeline_name}_audioresample")
        tee = Gst.ElementFactory.make("tee", f"{pipeline_name}_tee")

        # Main playback branch
        main_queue = Gst.ElementFactory.make("queue", f"{pipeline_name}_main_q")
        volume = Gst.ElementFactory.make("volume", f"{pipeline_name}_volume")
        norm_factor, info = self._bg_norm_factor_for_path(file_path)
        try:
            self._gst_bg_norm[pipeline_name] = norm_factor
        except Exception:
            pass
        # GStreamer fallback uses one static LUFS gain times the user/fade
        # volume element.  This keeps it single-pass like BASS: no live
        # compressor and no duplicate normalization branch.
        volume.set_property("volume", max(0.0, float(self.volume) * float(norm_factor)))
        try:
            lufs_label = f"{float(info.get('lufs')):.1f}" if info else "pending"
        except Exception:
            lufs_label = "pending"
        _diag(
            f"[BG-AUDIO] track={Path(file_path).name} gst={pipeline_name} "
            f"chain=GStreamer -> volume(norm_gain={20.0 * math.log10(max(1e-9, norm_factor)):+.1f}dB, "
            f"LUFS={lufs_label}) -> output"
        )
        try:
            parent = self.parent()
            if parent is not None and hasattr(parent, "_create_audio_sink_for_selected_output"):
                audiosink = parent._create_audio_sink_for_selected_output(
                    f"{pipeline_name}_audiosink",
                    default_factory="autoaudiosink",
                )
            else:
                audiosink = Gst.ElementFactory.make("autoaudiosink", f"{pipeline_name}_audiosink")
        except Exception:
            audiosink = Gst.ElementFactory.make("autoaudiosink", f"{pipeline_name}_audiosink")

        # Meter branch (appsink) - optional visualizer input. Keep it alive in
        # Performance Mode so the show screen still visualizes BGM; Safe Mode
        # disables it for subsystem isolation.
        try:
            parent = self.parent()
            meter_disabled = bool(
                parent is not None
                and (
                    (hasattr(parent, "_safe_mode") and parent._safe_mode())
                )
            )
        except Exception:
            meter_disabled = False
        meter_queue = meter_convert = meter_resample = meter_caps = meter_sink = None
        if not meter_disabled:
            meter_queue = Gst.ElementFactory.make("queue", f"{pipeline_name}_meter_q")
            meter_convert = Gst.ElementFactory.make("audioconvert", f"{pipeline_name}_meter_conv")
            meter_resample = Gst.ElementFactory.make("audioresample", f"{pipeline_name}_meter_res")
            meter_caps = Gst.ElementFactory.make("capsfilter", f"{pipeline_name}_meter_caps")
            meter_sink = Gst.ElementFactory.make("appsink", f"{pipeline_name}_meter_sink")

        if meter_caps is not None:
            try:
                meter_caps.set_property("caps", Gst.Caps.from_string("audio/x-raw,format=S16LE,channels=1,rate=22050"))
            except Exception:
                pass

        if meter_sink is not None:
            try:
                meter_sink.set_property("emit-signals", True)
                # Keep visualizer timing aligned with what the audience hears.
                meter_sink.set_property("sync", True)
                meter_sink.set_property("max-buffers", 1)
                meter_sink.set_property("drop", True)
                meter_sink.connect("new-sample", self._on_meter_sample)
            except Exception:
                meter_sink = None

        elements = [
            filesrc, decodebin, audioconvert, audioresample, tee,
            main_queue, volume, audiosink,
        ]
        meter_chain_ok = all([meter_queue, meter_convert, meter_resample, meter_caps, meter_sink])
        if meter_chain_ok:
            elements += [meter_queue, meter_convert, meter_resample, meter_caps, meter_sink]

        for e in elements:
            if e is not None:
                pipeline.add(e)

        filesrc.link(decodebin)
        audioconvert.link(audioresample)
        audioresample.link(tee)

        # Main branch link
        tee.link(main_queue)
        main_queue.link(volume)
        volume.link(audiosink)

        # Meter branch link
        if meter_chain_ok:
            try:
                tee.link(meter_queue)
                meter_queue.link(meter_convert)
                meter_convert.link(meter_resample)
                meter_resample.link(meter_caps)
                meter_caps.link(meter_sink)
            except Exception:
                pass

        def on_pad_added(src, pad):
            try:
                caps = pad.query_caps(None).to_string()
                if caps.startswith("audio/"):
                    sink_pad = audioconvert.get_static_pad("sink")
                    if sink_pad and not sink_pad.is_linked():
                        pad.link(sink_pad)
            except Exception:
                pass

        decodebin.connect("pad-added", on_pad_added)

        bus = pipeline.get_bus()
        bus.add_signal_watch()
        bus.connect("message", self._on_bg_message, pipeline_name)

        return pipeline

    def _on_meter_sample(self, sink):
        """Appsink callback: compute lightweight RMS meter (0..1)."""
        _perf_t0 = time.perf_counter()
        try:
            sample = sink.emit("pull-sample")
            if sample is None:
                return Gst.FlowReturn.OK
            buf = sample.get_buffer()
            if buf is None:
                return Gst.FlowReturn.OK

            ok, info = buf.map(Gst.MapFlags.READ)
            if not ok:
                return Gst.FlowReturn.OK
            try:
                raw = bytes(info.data or b"")
            finally:
                buf.unmap(info)

            if not raw:
                return Gst.FlowReturn.OK

            # S16LE mono expected (via capsfilter). Keep this tiny for low CPU.
            nbytes = min(len(raw), 4096)
            nbytes -= (nbytes % 2)
            if nbytes <= 2:
                return Gst.FlowReturn.OK

            arr = array('h')
            arr.frombytes(raw[:nbytes])
            if sys.byteorder != 'little':
                arr.byteswap()

            n = len(arr)
            if n <= 0:
                return Gst.FlowReturn.OK

            step = max(1, n // 1024)
            total = 0.0
            count = 0
            for i in range(0, n, step):
                v = float(arr[i])
                total += v * v
                count += 1

            if count <= 0:
                return Gst.FlowReturn.OK

            rms = (total / float(count)) ** 0.5 / 32768.0
            # Lift low-level material a bit so bars remain readable.
            target = max(0.0, min(1.0, rms * 4.0))
            self._meter_level = (self._meter_level * 0.70) + (target * 0.30)
            self._meter_last_ts = time.monotonic()
        except Exception:
            pass
        finally:
            _perf_log_if_slow("audio_bg_meter_callback", (time.perf_counter() - _perf_t0) * 1000.0)
        return Gst.FlowReturn.OK


    def _karaoke_is_active(self) -> bool:
        """
        Returns True if karaoke is currently playing (as reported by the parent app).
        We check a few common flags/methods so it works with your current app.
        """
        try:
            p = self.parent()
            # Common patterns — keep all three for robustness
            if hasattr(p, "karaoke_playing"):
                return bool(p.karaoke_playing)
            if hasattr(p, "is_karaoke_playing") and callable(p.is_karaoke_playing):
                return bool(p.is_karaoke_playing())
            if hasattr(p, "is_karaoke_active"):
                return bool(p.is_karaoke_active)
        except Exception:
            pass
        return False
    
    def _bg_end_silence_enabled(self) -> bool:
        try:
            host = self.parent()
            if host is not None and hasattr(host, "settings"):
                return bool(host.settings.get("bg_end_silence_trim_enabled", False))
        except Exception:
            pass
        return True

    def _bg_loudness_info_for_path(self, path: str | None):
        """Return cached BGM loudness info and kick off background analysis.

        This is intentionally analysis/cache only. Playback applies the cached
        static gain once per BASS source deck, avoiding live loudness DSP,
        compressors, or duplicate volume filters.
        """
        if not path:
            return None
        info = loudness_info_cached(path)
        if info is None:
            _diag(f"[BG-AUDIO] normalization cache miss track={Path(path).name} action=analyze_async")
            analyze_loudness_async(path)
        else:
            try:
                gain_db = float(info.get("gain_db", 0.0) or 0.0)
                gain_linear = float(info.get("gain_linear", 1.0) or 1.0)
                _diag(f"[BG-AUDIO] normalization cache hit track={Path(path).name} gain_db={gain_db:+.1f} gain_linear={gain_linear:.3f}")
            except Exception:
                _diag(f"[BG-AUDIO] normalization cache hit track={Path(path).name}")
        return info

    def _bg_dsp_chain_label(self, path: str | None, info: dict | None) -> str:
        try:
            eq = None
            parent = self.parent()
            if parent is not None:
                eq = getattr(parent, "bgm_eq", None)
            eq_on = bool(eq is not None and eq.enabled() and not eq.is_flat())
        except Exception:
            eq_on = False
        eq_chain = "off"
        if eq_on:
            try:
                engine = getattr(self, "_bass_engine", None)
                if engine is not None and getattr(engine, "_eq_fx_handles", None):
                    eq_chain = "native-bass"
                elif engine is not None and getattr(engine, "_eq_dsp_handle", 0):
                    eq_chain = "python-dsp"
                else:
                    eq_chain = "requested-unavailable"
            except Exception:
                eq_chain = "on"
        norm = "on" if self._bg_normalize_active() else "off"
        lufs = "pending"
        gain = "+0.0"
        peak = "n/a"
        if info is not None:
            lufs = f"{float(info.get('lufs', 0.0)):.1f}"
            gain = f"{float(info.get('gain_db', 0.0)):+.1f}"
            pk = info.get("peak_db")
            peak = "n/a" if pk is None else f"{float(pk):.1f}"
        return (
            f"BASSmix -> deck_gain(norm={norm}, LUFS={lufs}, peak={peak}dB, gain={gain}dB) "
            f"-> deck_fade/crossfade -> mixer_master(slider/fade={float(self.volume):.3f}) "
            f"-> EQ({eq_chain}) -> output"
        )

    def _bg_normalize_active(self) -> bool:
        """BG loudness normalization is active only in advanced mode. Simple
        Audio Mode (default) bypasses it entirely so the BG slider is the only
        gain stage."""
        try:
            host = self.parent()
            if host is None or not hasattr(host, "settings"):
                return False
            if bool(host.settings.get("simple_audio_mode", True)):
                return False
            return bool(host.settings.get("bg_normalize_enabled", True))
        except Exception:
            return False

    def _bg_norm_factor_for_path(self, path: str | None) -> tuple[float, dict | None]:
        enabled = self._bg_normalize_active()
        if not enabled or not path:
            return 1.0, None
        info = self._bg_loudness_info_for_path(path)
        if info is None:
            _diag(
                f"[BG-AUDIO] normalization cache miss safe pre-gain track={Path(path).name} "
                f"gain_linear={BGM_UNKNOWN_ANALYSIS_PREGAIN:.3f}"
            )
            return BGM_UNKNOWN_ANALYSIS_PREGAIN, None
        try:
            return max(0.05, min(4.0, float(info.get("gain_linear", 1.0) or 1.0))), info
        except Exception:
            return 1.0, info

    def _gst_pipeline_norm(self, pipeline_name: str) -> float:
        try:
            return max(0.05, min(4.0, float(getattr(self, "_gst_bg_norm", {}).get(pipeline_name, 1.0))))
        except Exception:
            return 1.0

    def _refresh_bg_normalize(self, path: str | None = None, deck: str = "primary"):
        """Apply per-track loudness normalization to the BASS engine so each BG
        track plays at a consistent level. The gain is per source deck; the
        user's volume/fades remain the single mixer-master stage."""
        try:
            engine = getattr(self, "_bass_engine", None)
            if engine is None:
                return None
            enabled = self._bg_normalize_active()
            if not enabled:
                if deck == "secondary" and hasattr(engine, "set_secondary_normalize_gain"):
                    engine.set_secondary_normalize_gain(1.0)
                elif hasattr(engine, "set_primary_normalize_gain"):
                    engine.set_primary_normalize_gain(1.0)
                _diag(f"[BG-AUDIO] normalization disabled chain={self._bg_dsp_chain_label(path, None)}")
                return None
            if not path:
                if self.playlist and 0 <= int(self.current_index) < len(self.playlist):
                    path = self.playlist[int(self.current_index)]
            if not path:
                if deck == "secondary" and hasattr(engine, "set_secondary_normalize_gain"):
                    engine.set_secondary_normalize_gain(1.0)
                elif hasattr(engine, "set_primary_normalize_gain"):
                    engine.set_primary_normalize_gain(1.0)
                return None
            info = self._bg_loudness_info_for_path(path)
            if info is None:
                factor = BGM_UNKNOWN_ANALYSIS_PREGAIN
                _diag(f"[BG-AUDIO] calculated gain unavailable deck={deck} track={Path(path).name}; using safe pre-gain={factor:.3f}")
                if deck == "secondary" and hasattr(engine, "set_secondary_normalize_gain"):
                    engine.set_secondary_normalize_gain(factor)
                elif hasattr(engine, "set_primary_normalize_gain"):
                    engine.set_primary_normalize_gain(factor)
            else:
                factor = float(info.get("gain_linear", 1.0) or 1.0)
                try:
                    _diag(f"[BG-AUDIO] calculated gain deck={deck} track={Path(path).name} gain_db={float(info.get('gain_db', 0.0)):+.1f} gain_linear={factor:.3f}")
                except Exception:
                    _diag(f"[BG-AUDIO] calculated gain deck={deck} track={Path(path).name} gain_linear={factor:.3f}")
                if deck == "secondary" and hasattr(engine, "set_secondary_normalize_gain"):
                    engine.set_secondary_normalize_gain(factor)
                elif hasattr(engine, "set_primary_normalize_gain"):
                    engine.set_primary_normalize_gain(factor)
            _diag(f"[BG-AUDIO] track={Path(path).name} deck={deck} chain={self._bg_dsp_chain_label(path, info)}")
            # Warm the next track so its gain is ready before the crossfade.
            try:
                if self.playlist:
                    nxt = self.playlist[(int(self.current_index) + 1) % len(self.playlist)]
                    if nxt and loudness_gain_db_cached(nxt) is None:
                        analyze_loudness_async(nxt)
            except Exception:
                pass
            return info
        except Exception:
            return None

    def _check_bg_tail_silence(self, pos_sec: float, dur_sec: float, time_left: float) -> bool:
        """Detect sustained trailing silence near the end of a BG track.

        Returns True when we should advance/crossfade early to avoid dead air.
        Uses the live RMS meter (self._meter_level); only acts within the last
        BG_SILENCE_TAIL_WINDOW seconds so quiet intros/breaks aren't cut.
        """
        if not self._bg_end_silence_enabled() or dur_sec <= 0:
            self._bg_silence_accum_s = 0.0
            self._bg_silence_last_ts = 0.0
            return False
        now = time.monotonic()
        last = self._bg_silence_last_ts
        self._bg_silence_last_ts = now
        dt = (now - last) if last > 0 else 0.0
        if dt <= 0 or dt > 2.0:
            dt = 0.0  # first tick after (re)start or a stall — don't over-accumulate
        in_tail = time_left <= BG_SILENCE_TAIL_WINDOW
        if in_tail and self._meter_level <= BG_SILENCE_LEVEL:
            self._bg_silence_accum_s += dt
        else:
            self._bg_silence_accum_s = 0.0
        if self._bg_silence_accum_s >= BG_SILENCE_MIN_S:
            self._bg_silence_accum_s = 0.0
            return True
        return False

    def _check_track_position(self):
        """Check current track position and start crossfade near the end"""
        if self._bass_ready():
            self._bass_update_meter()
            engine = self._bass_engine
            if not self.is_playing or engine.primary is None:
                return
            if not self.crossfade_active and engine.source_ended():
                if bool(getattr(self, "stop_after_current", False)):
                    self.stop_after_current = False
                    QTimer.singleShot(0, self.stop)
                else:
                    QTimer.singleShot(0, self.next_track)
                if hasattr(self.parent(), "update_bg_button_state"):
                    QTimer.singleShot(100, self.parent().update_bg_button_state)
                return
            if self.crossfade_active or bool(getattr(self, "stop_after_current", False)):
                return
            pos_sec, dur_sec = engine.get_times()
            time_left = dur_sec - pos_sec
            crossfade_start_time = self.crossfade_duration_ms / 1000.0
            if self._check_bg_tail_silence(pos_sec, dur_sec, time_left):
                print(f"[BG] trailing silence detected at {pos_sec:.1f}s — advancing early")
                self._start_crossfade()
                return
            if dur_sec > 0.0 and 0.0 < time_left <= crossfade_start_time:
                print(f"Starting BASSmix crossfade with {time_left:.1f}s left in track")
                self._start_crossfade()
            return
        if not self.is_playing or not self.gst_bg_pipeline or self.crossfade_active:
            return
        # If user requested stop-at-end, do not start crossfade into next track.
        if bool(getattr(self, "stop_after_current", False)):
            return
            
        # Query position and duration
        success_pos, position = self.gst_bg_pipeline.query_position(Gst.Format.TIME)
        success_dur, duration = self.gst_bg_pipeline.query_duration(Gst.Format.TIME)
        
        if success_pos and success_dur and duration > 0:
            # Convert to seconds
            pos_sec = position / Gst.SECOND
            dur_sec = duration / Gst.SECOND
            time_left = dur_sec - pos_sec

            if self._check_bg_tail_silence(pos_sec, dur_sec, time_left):
                print(f"[BG] trailing silence detected at {pos_sec:.1f}s — advancing early")
                self._start_crossfade()
                return

            # Start crossfade if less than crossfade_duration seconds left
            crossfade_start_time = self.crossfade_duration_ms / 1000.0
            if time_left <= crossfade_start_time and time_left > 0:
                print(f"Starting crossfade with {time_left:.1f}s left in track")
                self._start_crossfade()

    def get_playback_times(self) -> tuple[float, float]:
        """Return (position_seconds, duration_seconds) for current BG track."""
        if self._bass_ready():
            try:
                return self._bass_engine.get_times()
            except Exception:
                return 0.0, 0.0
        try:
            p = self.gst_bg_pipeline
            if not p:
                return 0.0, 0.0
            ok_pos, pos = p.query_position(Gst.Format.TIME)
            ok_dur, dur = p.query_duration(Gst.Format.TIME)
            if not ok_pos or not ok_dur or dur <= 0:
                return 0.0, 0.0
            return max(0.0, pos / Gst.SECOND), max(0.0, dur / Gst.SECOND)
        except Exception:
            return 0.0, 0.0

    def is_effectively_playing(self) -> bool:
        """True only when BG is really running (not stale PLAYING/muted state)."""
        if self._bass_ready():
            try:
                engine = self._bass_engine
                return bool(
                    self.is_playing
                    and engine.primary is not None
                    and engine.is_playing()
                    and (float(engine.master_volume) > 0.0005 or self.crossfade_active)
                )
            except Exception:
                return False
        if self.gst_bg_pipeline is None:
            return False

        # Fast state gate first.
        try:
            _ret, state, _pending = self.gst_bg_pipeline.get_state(0)
            if state != Gst.State.PLAYING:
                return False
        except Exception:
            pass

        # If effectively muted and no active fade/crossfade, treat as not playing.
        try:
            live_vol = None
            vol_element = self.gst_bg_pipeline.get_by_name("bg_music_volume")
            if vol_element is not None:
                live_vol = float(vol_element.get_property("volume") or 0.0)
            if live_vol is None:
                live_vol = float(self.volume or 0.0)
            if live_vol <= 0.0005 and not self.fade_timer.isActive() and not self.crossfade_active:
                return False
        except Exception:
            pass

        # Detect stuck playback: PLAYING but no position movement.
        try:
            ok_pos, pos = self.gst_bg_pipeline.query_position(Gst.Format.TIME)
            if ok_pos:
                pos_sec = max(0.0, float(pos) / float(Gst.SECOND))
                now = time.monotonic()
                prev_pos = self._play_probe_pos
                prev_ts = self._play_probe_ts
                self._play_probe_pos = pos_sec
                self._play_probe_ts = now

                if prev_pos is not None and prev_ts is not None:
                    dt = max(0.0, now - float(prev_ts))
                    # Need enough time between probes before calling it stuck.
                    if dt >= 0.35 and pos_sec <= (float(prev_pos) + 0.01) and not self.fade_timer.isActive():
                        return False
        except Exception:
            pass

        return True

    def seek_seconds(self, seconds: float) -> bool:
        """Seek current BG track to absolute seconds."""
        if self._bass_ready():
            try:
                return bool(self._bass_engine.seek(seconds))
            except Exception as e:
                _diag(f"[BG-BASS] seek failed: {e}")
                return False
        try:
            p = self.gst_bg_pipeline
            if not p:
                return False

            ok_dur, dur = p.query_duration(Gst.Format.TIME)
            target_ns = int(max(0.0, float(seconds)) * Gst.SECOND)
            if ok_dur and dur > 0:
                target_ns = max(0, min(int(dur - 1), target_ns))

            return bool(
                p.seek_simple(
                    Gst.Format.TIME,
                    Gst.SeekFlags.FLUSH | Gst.SeekFlags.KEY_UNIT,
                    target_ns,
                )
            )
        except Exception:
            return False
    
    def _start_crossfade(self):
        """Start crossfade to next track"""
        # Reset trailing-silence detector for the upcoming track.
        self._bg_silence_accum_s = 0.0
        self._bg_silence_last_ts = 0.0
        if self._bass_ready():
            if self.crossfade_active or not self.playlist:
                return
            self._sync_volume_from_ui_or_settings("crossfade-start")
            next_index = (self.current_index + 1) % len(self.playlist)
            next_file = self.playlist[next_index]
            try:
                info = self._bg_loudness_info_for_path(next_file)
                norm_gain = float((info or {}).get("gain_linear", 1.0) or 1.0)
                if not self._bass_engine.start_crossfade(next_file, self.crossfade_duration_ms, norm_gain=norm_gain):
                    return
                _diag(f"[BG-AUDIO] track={Path(next_file).name} deck=secondary chain={self._bg_dsp_chain_label(next_file, info)}")
                print(f"Starting BASSmix crossfade to: {Path(next_file).name}")
                self.crossfade_active = True
                self.crossfade_progress = 0.0
                self._bass_crossfade_generation += 1
                generation = int(self._bass_crossfade_generation)
                QTimer.singleShot(
                    max(1, int(self.crossfade_duration_ms)),
                    lambda g=generation: self._complete_crossfade(g),
                )
            except Exception as e:
                print(f"Failed to start BASSmix crossfade: {e}")
            return
        if self.crossfade_active or not self.playlist:
            return
        self._sync_volume_from_ui_or_settings("crossfade-start")
            
        # Get next track
        next_index = (self.current_index + 1) % len(self.playlist)
        next_file = self.playlist[next_index]
        
        print(f"Starting crossfade to: {Path(next_file).name}")
        
        # Create crossfade pipeline for next track
        try:
            self.gst_crossfade_pipeline = self._create_bg_pipeline(next_file, "bg_crossfade")
            # Start crossfade pipeline at 0 volume
            crossfade_volume = self.gst_crossfade_pipeline.get_by_name("bg_crossfade_volume")
            if crossfade_volume:
                crossfade_volume.set_property("volume", 0.0)
            
            self.gst_crossfade_pipeline.set_state(Gst.State.PLAYING)
            
            # Start crossfade process
            self.crossfade_active = True
            self.crossfade_progress = 0.0
            steps = self.crossfade_duration_ms // 50  # 50ms per step
            self.crossfade_step_size = 1.0 / steps if steps > 0 else 1.0
            self.crossfade_timer.start(50)
            
        except Exception as e:
            print(f"Failed to start crossfade: {e}")
    
    def _crossfade_step(self):
        """Single step of crossfade animation"""
        if not self.crossfade_active:
            self.crossfade_timer.stop()
            return
            
        self.crossfade_progress += self.crossfade_step_size
        
        if self.crossfade_progress >= 1.0:
            # Crossfade complete - switch to new track
            self._complete_crossfade()
            return
        
        # Update volumes for smooth crossfade
        main_volume = self.volume * (1.0 - self.crossfade_progress) * self._gst_pipeline_norm("bg_music")
        crossfade_volume = self.volume * self.crossfade_progress * self._gst_pipeline_norm("bg_crossfade")
        
        # Apply volumes
        if self.gst_bg_pipeline:
            main_vol_element = self.gst_bg_pipeline.get_by_name("bg_music_volume")
            if main_vol_element:
                main_vol_element.set_property("volume", main_volume)
        
        if self.gst_crossfade_pipeline:
            crossfade_vol_element = self.gst_crossfade_pipeline.get_by_name("bg_crossfade_volume")
            if crossfade_vol_element:
                crossfade_vol_element.set_property("volume", crossfade_volume)
    
    def _complete_crossfade(self, bass_generation=None):
        """Complete the crossfade and switch to the new track"""
        if self._bass_ready():
            if bass_generation is not None and bass_generation != int(getattr(self, "_bass_crossfade_generation", 0) or 0):
                return
            if not self.crossfade_active:
                return
            try:
                if not self._bass_engine.complete_crossfade():
                    return
            except Exception as e:
                _diag(f"[BG-BASS] crossfade completion failed: {e}")
                return
            self.current_index = (self.current_index + 1) % len(self.playlist)
            self.crossfade_active = False
            self.crossfade_progress = 0.0
            if hasattr(self.parent(), "update_bg_track_display"):
                self.parent().update_bg_track_display()
            QTimer.singleShot(200, self._start_artwork_precache)
            print(f"Switched to: {Path(self.playlist[self.current_index]).name}")
            return
        print("Completing crossfade")
        
        # Stop the old pipeline
        if self.gst_bg_pipeline:
            try:
                bus = self.gst_bg_pipeline.get_bus()
                bus.remove_signal_watch()
            except:
                pass
            self.gst_bg_pipeline.set_state(Gst.State.NULL)
        
        # Switch pipelines
        self.gst_bg_pipeline = self.gst_crossfade_pipeline
        self.gst_crossfade_pipeline = None
        try:
            self._gst_bg_norm["bg_music"] = self._gst_pipeline_norm("bg_crossfade")
            self._gst_bg_norm.pop("bg_crossfade", None)
        except Exception:
            pass
        
        # Update track index
        self.current_index = (self.current_index + 1) % len(self.playlist)
        
        # Set correct volume
        if self.gst_bg_pipeline:
            volume_element = self.gst_bg_pipeline.get_by_name("bg_crossfade_volume")
            if volume_element:
                volume_element.set_property("volume", self.volume * self._gst_pipeline_norm("bg_crossfade"))
        
        # Reset crossfade state
        self.crossfade_active = False
        self.crossfade_progress = 0.0
        self.crossfade_timer.stop()
        
        # IMMEDIATE UI update - don't delay
        if hasattr(self.parent(), 'update_bg_track_display'):
            self.parent().update_bg_track_display()
        
        # Start pre-caching for upcoming tracks
        QTimer.singleShot(200, self._start_artwork_precache)
        
        print(f"Switched to: {Path(self.playlist[self.current_index]).name}")
        
    def _on_bg_message(self, bus, msg, pipeline_name):
        """Handle GStreamer messages for background music"""
        mtype = msg.type

        if mtype == Gst.MessageType.EOS:
            if pipeline_name == "bg_music":
                if self.crossfade_active:
                    QTimer.singleShot(0, self._complete_crossfade)
                else:
                    if bool(getattr(self, "stop_after_current", False)):
                        self.stop_after_current = False
                        QTimer.singleShot(0, self.stop)
                    else:
                        QTimer.singleShot(0, self.next_track)
            if hasattr(self.parent(), 'update_bg_button_state'):
                QTimer.singleShot(100, self.parent().update_bg_button_state)
            if hasattr(self.parent(), 'update_bg_track_display'):
                QTimer.singleShot(120, self.parent().update_bg_track_display)
            return

        if mtype == Gst.MessageType.ERROR:
            err, debug = msg.parse_error()
            print(f"Background music error in {pipeline_name}: {err}")
            if pipeline_name == "bg_music":
                QTimer.singleShot(0, self.next_track)
            if hasattr(self.parent(), 'update_bg_button_state'):
                QTimer.singleShot(100, self.parent().update_bg_button_state)
            return

    def preload_current_track_paused(self) -> bool:
        """Build current track pipeline and leave it PAUSED (silent preroll)."""
        if self._bass_ready():
            if not self.playlist:
                return False
            if self._bass_engine.primary is not None:
                self._sync_volume_from_ui_or_settings("preload-existing")
                return True
            try:
                current_file = self.playlist[self.current_index]
                self._bg_volume_diag("preload-before-media-load", current_file)
                target = self._sync_volume_from_ui_or_settings("preload")
                self._bass_engine.set_master_volume(0.0)
                self._bass_engine.load(current_file, paused=True, volume=self.volume)
                self._bass_engine.set_master_volume(target)
                self._refresh_bg_normalize(current_file, deck="primary")
                self.is_playing = False
                self._bg_volume_diag("preload-after-media-load", current_file, extra=f"target={target:.3f}")
                print(f"[BG-BASS] Preloaded track (paused): {Path(current_file).name}")
                return True
            except Exception as e:
                print(f"[BG-BASS] Preload exception: {e}")
                return False
        if not self.playlist:
            return False
        if self.gst_bg_pipeline is not None:
            self._sync_volume_from_ui_or_settings("preload-existing")
            return True
        try:
            current_file = self.playlist[self.current_index]
            self._bg_volume_diag("preload-before-media-load", current_file)
            self._sync_volume_from_ui_or_settings("preload")
            self.gst_bg_pipeline = self._create_bg_pipeline(current_file, "bg_music")
            try:
                volume_element = self.gst_bg_pipeline.get_by_name("bg_music_volume")
                if volume_element:
                    volume_element.set_property("volume", self.volume * self._gst_pipeline_norm("bg_music"))
            except Exception:
                pass
            ret = self.gst_bg_pipeline.set_state(Gst.State.PAUSED)
            if ret == Gst.StateChangeReturn.FAILURE:
                print("[BG] Preload failed (PAUSED)")
                try:
                    self.gst_bg_pipeline.set_state(Gst.State.NULL)
                except Exception:
                    pass
                self.gst_bg_pipeline = None
                return False
            self.is_playing = False
            self._bg_volume_diag("preload-after-media-load", current_file)
            print(f"[BG] Preloaded track (paused): {Path(current_file).name}")
            return True
        except Exception as e:
            print(f"[BG] Preload exception: {e}")
            self.gst_bg_pipeline = None
            return False

    def _rebuild_current_track_and_seek(self, seek_sec: float = 0.0, dur_sec: float = 0.0) -> bool:
        """Recreate BG pipeline for current index and seek to approx previous position."""
        if not self.playlist:
            return False
        try:
            current_file = self.playlist[self.current_index]
        except Exception:
            return False

        try:
            if self.gst_bg_pipeline:
                try:
                    bus = self.gst_bg_pipeline.get_bus()
                    bus.remove_signal_watch()
                except Exception:
                    pass
                try:
                    self.gst_bg_pipeline.set_state(Gst.State.NULL)
                except Exception:
                    pass
        except Exception:
            pass
        self.gst_bg_pipeline = None

        # Preserve seek UI during rebuild so labels/slider don't flash to 0:00.
        try:
            parent = self.parent()
            hold_pos = max(0.0, float(seek_sec or 0.0))
            hold_dur = max(0.0, float(dur_sec or 0.0))
            hold_until = time.monotonic() + 1.1

            if parent is not None:
                # Main-window BG seek UI hold
                if hasattr(parent, "_bg_main_last_pos"):
                    parent._bg_main_last_pos = hold_pos
                if hasattr(parent, "_bg_main_last_dur") and hold_dur > 0.0:
                    parent._bg_main_last_dur = hold_dur
                if hasattr(parent, "_bg_main_seek_hold_until"):
                    parent._bg_main_seek_hold_until = hold_until

                # BG manager seek UI hold
                mgr = getattr(parent, "bg_manager", None)
                if mgr is not None:
                    if hasattr(mgr, "_seek_last_pos"):
                        mgr._seek_last_pos = hold_pos
                    if hasattr(mgr, "_seek_last_dur") and hold_dur > 0.0:
                        mgr._seek_last_dur = hold_dur
                    if hasattr(mgr, "_seek_hold_until"):
                        mgr._seek_hold_until = hold_until
        except Exception:
            pass

        print(f"[BG] Rebuilding pipeline for recovery: {Path(current_file).name}")
        try:
            self.gst_bg_pipeline = self._create_bg_pipeline(current_file, "bg_music")
            # Recovery path: preroll paused, seek, then play.
            ret = self.gst_bg_pipeline.set_state(Gst.State.PAUSED)
            if ret == Gst.StateChangeReturn.FAILURE:
                print("[BG] Recovery rebuild failed to preroll")
                try:
                    self.gst_bg_pipeline.set_state(Gst.State.NULL)
                except Exception:
                    pass
                self.gst_bg_pipeline = None
                self.is_playing = False
                return False

            try:
                target = max(0.0, float(seek_sec or 0.0))
            except Exception:
                target = 0.0

            def _seek_then_play():
                try:
                    if self.gst_bg_pipeline is None:
                        return
                    if target > 0.0:
                        self.seek_seconds(target)
                    ret_play = self.gst_bg_pipeline.set_state(Gst.State.PLAYING)
                    if ret_play == Gst.StateChangeReturn.FAILURE:
                        print("[BG] Recovery rebuild failed to play")
                        try:
                            self.gst_bg_pipeline.set_state(Gst.State.NULL)
                        except Exception:
                            pass
                        self.gst_bg_pipeline = None
                        self.is_playing = False
                        return
                    QTimer.singleShot(80, self._ensure_volume_set)
                except Exception:
                    pass

            # Small delay to allow decodebin pads to appear before seek.
            QTimer.singleShot(120, _seek_then_play)
            return True
        except Exception as e:
            print(f"[BG] Recovery rebuild exception: {e}")
            self.gst_bg_pipeline = None
            self.is_playing = False
            return False

    def play(self):
        """Start/resume background music"""
        if not self.playlist:
            print("No playlist loaded")
            return
        
        # Never play BG if karaoke is active
        if self._karaoke_is_active():
            print("Karaoke is active; suppressing BG play()")
            return
               
        if not self.enabled:
            print("BG disabled; play() ignored")
            return

        if self._bass_ready():
            if self._pipeline_realign_needed and self._bass_engine.primary is not None and not self.is_playing:
                self._bass_engine.stop()
            self._pipeline_realign_needed = False
            target_volume = self._sync_volume_from_ui_or_settings("play")
            if self.volume <= 0.001:
                self.volume = target_volume
                print(f"[BG-BASS] Play sanity: using desired volume {self.volume}")
            try:
                current_file = self.playlist[self.current_index]
                if not self._bg_first_play_logged:
                    self._bg_first_play_logged = True
                    _diag(f"[BG-VOLUME] first BGM file selected={Path(current_file).name!r}")
                if self._bass_engine.primary is None and not self.preload_current_track_paused():
                    return
                self._refresh_bg_normalize()
                self._bg_volume_diag("play-before-BASS_ChannelPlay", current_file)
                self._bass_engine.set_master_volume(target_volume)
                if not self._bass_engine.play():
                    print("[BG-BASS] Failed to start background mixer")
                    return
                self._bass_engine.set_master_volume(target_volume)
                self.is_playing = True
                self._bg_volume_diag("play-after-BASS_ChannelPlay", current_file)
                self._schedule_volume_state_probe("bass-play")
                print(f"Playing BASSmix background music: {Path(self.playlist[self.current_index]).name}")
            except Exception as e:
                print(f"[BG-BASS] play failed: {e}")
            return

        # If manager shuffled/reordered while idle, rebuild once before playing.
        if self._pipeline_realign_needed and self.gst_bg_pipeline is not None and not self.is_playing:
            try:
                self.stop()
            except Exception:
                pass
        self._pipeline_realign_needed = False
        
        # Ensure we aren't stuck at zero from a prior fade-out
        target_volume = self._sync_volume_from_ui_or_settings("play")
        if self.volume <= 0.001:
            self.volume = target_volume
            print(f"[BG] Play sanity: using desired volume {self.volume}")

        def _start_fresh_pipeline():
            current_file = self.playlist[self.current_index]
            if not self._bg_first_play_logged:
                self._bg_first_play_logged = True
                _diag(f"[BG-VOLUME] first BGM file selected={Path(current_file).name!r}")
            print(f"Creating new background music pipeline for: {current_file}")
            self._bg_volume_diag("play-before-media-load", current_file)
            self.gst_bg_pipeline = self._create_bg_pipeline(current_file, "bg_music")
            try:
                volume_element = self.gst_bg_pipeline.get_by_name("bg_music_volume")
                if volume_element:
                    volume_element.set_property("volume", self.volume * self._gst_pipeline_norm("bg_music"))
            except Exception:
                pass
            self._bg_volume_diag("play-after-media-load", current_file)
            # Preroll in PAUSED first, then switch to PLAYING shortly after.
            # This reduces first-frame/startup skips on some systems.
            ret = self.gst_bg_pipeline.set_state(Gst.State.PAUSED)
            if ret == Gst.StateChangeReturn.FAILURE:
                print("[BG] Failed to preroll new pipeline")
                try:
                    self.gst_bg_pipeline.set_state(Gst.State.NULL)
                except Exception:
                    pass
                self.gst_bg_pipeline = None
                self.is_playing = False
                return False

            def _go_playing():
                if self.gst_bg_pipeline is None:
                    return
                try:
                    volume_element = self.gst_bg_pipeline.get_by_name("bg_music_volume")
                    if volume_element:
                        volume_element.set_property("volume", self.volume * self._gst_pipeline_norm("bg_music"))
                except Exception:
                    pass
                self._bg_volume_diag("play-before-GStreamer-PLAYING", current_file)
                ret_play = self.gst_bg_pipeline.set_state(Gst.State.PLAYING)
                if ret_play == Gst.StateChangeReturn.FAILURE:
                    print("[BG] Failed to start new pipeline from preroll")
                    try:
                        self.gst_bg_pipeline.set_state(Gst.State.NULL)
                    except Exception:
                        pass
                    self.gst_bg_pipeline = None
                    self.is_playing = False
                    return
                self._bg_volume_diag("play-after-GStreamer-PLAYING", current_file)
                self._schedule_volume_state_probe("gst-play")
                # Ensure desired volume is re-applied after state change.
                QTimer.singleShot(70, self._ensure_volume_set)

            QTimer.singleShot(120, _go_playing)
            return True

        if self.gst_bg_pipeline:
            # Resume existing pipeline
            print("Resuming existing background music pipeline")
            paused_pos, _paused_dur = self.get_playback_times()
            self._ensure_volume_set()
            self._bg_volume_diag("resume-before-GStreamer-PLAYING", self.get_active_track_path())
            ret_main = self.gst_bg_pipeline.set_state(Gst.State.PLAYING)
            if ret_main == Gst.StateChangeReturn.FAILURE:
                print("[BG] Resume failed; recreating pipeline")
                try:
                    self.gst_bg_pipeline.set_state(Gst.State.NULL)
                except Exception:
                    pass
                self.gst_bg_pipeline = None
                if not _start_fresh_pipeline():
                    return
            else:
                # If pause happened during crossfade, resume both branches + timer.
                if self.crossfade_active:
                    if self.gst_crossfade_pipeline:
                        self.gst_crossfade_pipeline.set_state(Gst.State.PLAYING)
                        if not self.crossfade_timer.isActive():
                            self.crossfade_timer.start(50)
                    else:
                        # Defensive recovery: clear stale crossfade state.
                        self.crossfade_active = False
                        self.crossfade_progress = 0.0
                self._bg_volume_diag("resume-after-GStreamer-PLAYING", self.get_active_track_path())
                self._schedule_volume_state_probe("gst-resume")
                QTimer.singleShot(100, self._ensure_volume_set)
                # Some sinks can report PLAYING but never advance after unpause.
                # Verify movement once, then self-heal by rebuilding at same position.
                def _verify_unpause(start_pos: float):
                    if not self.is_playing or self.gst_bg_pipeline is None:
                        return
                    now_pos, _now_dur = self.get_playback_times()
                    # ~120ms tolerance avoids false positives on jittery clocks.
                    if now_pos <= (float(start_pos) + 0.12):
                        print(f"[BG] Resume appears stuck at {now_pos:.2f}s; recovering")
                        self._rebuild_current_track_and_seek(float(start_pos), float(_paused_dur))
                QTimer.singleShot(450, lambda: _verify_unpause(float(paused_pos)))
        else:
            if not _start_fresh_pipeline():
                return
            
        self.is_playing = True
        print(f"Playing background music: {Path(self.playlist[self.current_index]).name}")
        
    def pause(self):
        """Pause background music"""
        if self._bass_ready():
            self._bass_fade_generation += 1
            self._bass_engine.pause()
            self.is_playing = False
            self._meter_level = 0.0
            self._play_probe_pos = None
            self._play_probe_ts = None
            print("BASSmix background music paused")
            return
        try:
            self.fade_timer.stop()
        except Exception:
            pass
        self.fade_direction = 0
        if self.gst_bg_pipeline:
            self.gst_bg_pipeline.set_state(Gst.State.PAUSED)
        if self.gst_crossfade_pipeline:
            self.gst_crossfade_pipeline.set_state(Gst.State.PAUSED)
        self.is_playing = False
        self.crossfade_timer.stop()
        self._meter_level = 0.0
        self._play_probe_pos = None
        self._play_probe_ts = None
        print("Background music paused")
        
    def stop(self):
        """Stop background music"""
        if self._bass_ready():
            self._bass_fade_generation += 1
            self._bass_crossfade_generation += 1
            self._bass_engine.stop()
            try:
                self._gst_bg_norm.clear()
            except Exception:
                pass
            self.crossfade_active = False
            self.crossfade_progress = 0.0
            self.is_playing = False
            self._meter_level = 0.0
            self._play_probe_pos = None
            self._play_probe_ts = None
            print("BASSmix background music stopped")
            return
        try:
            self.fade_timer.stop()
        except Exception:
            pass
        self.fade_direction = 0
        # Stop both pipelines
        if self.gst_bg_pipeline:
            try:
                bus = self.gst_bg_pipeline.get_bus()
                bus.remove_signal_watch()
            except:
                pass
            self.gst_bg_pipeline.set_state(Gst.State.NULL)
            self.gst_bg_pipeline = None
            
        if self.gst_crossfade_pipeline:
            try:
                bus = self.gst_crossfade_pipeline.get_bus()
                bus.remove_signal_watch()
            except:
                pass
            self.gst_crossfade_pipeline.set_state(Gst.State.NULL)
            self.gst_crossfade_pipeline = None
        try:
            self._gst_bg_norm.clear()
        except Exception:
            pass
        
        # Reset crossfade state
        self.crossfade_active = False
        self.crossfade_timer.stop()
        self.is_playing = False
        self._meter_level = 0.0
        self._play_probe_pos = None
        self._play_probe_ts = None
        print("Background music stopped")

    def set_stop_after_current(self, enabled: bool):
        """Session-only toggle: stop at EOS instead of advancing to next track."""
        self.stop_after_current = bool(enabled)

    def apply_audio_output_change(self):
        """Apply selected output device to BG immediately (karaoke applies next track)."""
        if self._bass_ready():
            had_deck = self._bass_engine.primary is not None
            was_playing = bool(self.is_playing and self._bass_engine.is_playing())
            pos_sec, _dur_sec = self.get_playback_times()
            try:
                self._bass_engine.close()
            except Exception:
                pass
            if not self._init_bass_engine(self._bass_selected_output_name()):
                return
            if had_deck and self.playlist:
                if self.preload_current_track_paused() and pos_sec > 0.0:
                    self.seek_seconds(pos_sec)
                if was_playing:
                    self.play()
            _diag(f"[AUDIO] BASSmix BG output switched at {pos_sec:.2f}s")
            return
        if not self.playlist:
            return

        was_playing = bool(self.is_playing)
        pos_sec, dur_sec = self.get_playback_times()

        # Stop any fade/crossfade motion so old pipeline state cannot leak into rebuilt output.
        try:
            self.fade_timer.stop()
        except Exception:
            pass
        self.fade_direction = 0
        try:
            self.crossfade_timer.stop()
        except Exception:
            pass
        self.crossfade_active = False
        if self.gst_crossfade_pipeline is not None:
            try:
                self.gst_crossfade_pipeline.set_state(Gst.State.NULL)
            except Exception:
                pass
            self.gst_crossfade_pipeline = None

        if was_playing:
            if self._rebuild_current_track_and_seek(float(pos_sec), float(dur_sec)):
                self.is_playing = True
                _diag(f"[AUDIO] BG output switched immediately at {pos_sec:.2f}s")
            return

        # Paused/prerolled case: rebuild paused pipeline so next play uses new output.
        if self.gst_bg_pipeline is not None:
            try:
                self.gst_bg_pipeline.set_state(Gst.State.NULL)
            except Exception:
                pass
            self.gst_bg_pipeline = None
            self.preload_current_track_paused()
            _diag("[AUDIO] BG output switched (applies on next BG resume)")
        
    def next_track(self):
        """Advance to next track (manual or auto-advance) - OPTIMIZED FOR INSTANT UI"""
        if not self.playlist:
            return
            
        was_playing = self.is_playing
        
        # IMMEDIATE UI UPDATE - Update index and display BEFORE audio processing
        self.current_index = (self.current_index + 1) % len(self.playlist)
        
        # Update UI instantly - don't wait for audio
        if hasattr(self.parent(), 'update_bg_track_display'):
            self.parent().update_bg_track_display()
        
        # Stop current playback (including any crossfade)
        self.stop()
        
        # Start pre-caching for upcoming tracks
        QTimer.singleShot(200, self._start_artwork_precache)
        
        if was_playing:  # Auto-continue if we were playing
            self.play()
            
    def previous_track(self):
        """Go to previous track - OPTIMIZED FOR INSTANT UI"""
        if not self.playlist:
            return
            
        was_playing = self.is_playing
        
        # IMMEDIATE UI UPDATE - Update index and display BEFORE audio processing
        self.current_index = (self.current_index - 1) % len(self.playlist)
        
        # Update UI instantly - don't wait for audio
        if hasattr(self.parent(), 'update_bg_track_display'):
            self.parent().update_bg_track_display()
        
        # Stop current playback
        self.stop()
        
        # Start pre-caching for upcoming tracks  
        QTimer.singleShot(200, self._start_artwork_precache)
        
        if was_playing:  # Auto-continue if we were playing
            self.play()

    def _ensure_volume_set(self):
        """Ensure volume is properly set on the pipeline"""
        self._sync_volume_from_ui_or_settings("ensure-volume")
        if self._bass_ready():
            self._bass_engine.set_master_volume(self.volume)
            self._bg_volume_diag("ensure-volume-applied", self.get_active_track_path())
            return
        if self.gst_bg_pipeline:
            volume_element = self.gst_bg_pipeline.get_by_name("bg_music_volume")
            if volume_element:
                print(f"Setting background music volume to {self.volume}")
                volume_element.set_property("volume", self.volume * self._gst_pipeline_norm("bg_music"))
                self._bg_volume_diag("ensure-volume-applied", self.get_active_track_path())
            else:
                print("Warning: Could not find volume element in background music pipeline")  

    def _target_volume_from_ui(self):
        """Prefer the manager's visible slider; fall back to saved setting."""
        try:
            # Try BackgroundMusicManager's slider if the window is open
            p = self.parent()
            mgr = getattr(p, "bg_manager", None)
            if mgr is not None and hasattr(mgr, "volume_slider"):
                return max(0.0, min(1.0, mgr.volume_slider.value() / 100.0))
        except Exception:
            pass
        # Fall back to persisted setting (default 0.8)
        try:
            p = self.parent()
            return float(getattr(p, "settings", {}).get("bg_volume", 0.8))
        except Exception:
            return 0.8
            
    def set_volume(self, volume):
        """Set background music volume (0.0 to 1.0)"""
        ui_value = volume
        self.volume = max(0.0, min(1.0, volume))
        if self._bass_ready():
            self._bass_engine.set_master_volume(self.volume)
            try:
                eff = float(self._bass_engine._effective_master())
            except Exception:
                eff = self.volume
            _diag(f"[BG-VOL] ui={float(ui_value):.3f} applied={self.volume:.3f} backend=BASS master_gain={eff:.3f}")
            return

        applied_any = False
        # Update main pipeline volume
        if self.gst_bg_pipeline:
            volume_element = self.gst_bg_pipeline.get_by_name("bg_music_volume")
            if volume_element:
                # If crossfade is active, apply crossfade volume
                if self.crossfade_active:
                    main_volume = self.volume * (1.0 - self.crossfade_progress) * self._gst_pipeline_norm("bg_music")
                    volume_element.set_property("volume", main_volume)
                else:
                    volume_element.set_property("volume", self.volume * self._gst_pipeline_norm("bg_music"))
                applied_any = True

        # Update crossfade pipeline volume
        if self.gst_crossfade_pipeline:
            crossfade_volume_element = self.gst_crossfade_pipeline.get_by_name("bg_crossfade_volume")
            if crossfade_volume_element:
                if self.crossfade_active:
                    crossfade_volume = self.volume * self.crossfade_progress * self._gst_pipeline_norm("bg_crossfade")
                    crossfade_volume_element.set_property("volume", crossfade_volume)
                applied_any = True
        backend = "GStreamer" if self.gst_bg_pipeline else "none"
        _diag(f"[BG-VOL] ui={float(ui_value):.3f} applied={self.volume:.3f} backend={backend} element_found={applied_any}")

    def cancel_pending_fades(self, restore_to_target: bool = True):
        """Cancel any in-flight BG fade/crossfade so stale timers cannot mute playback later."""
        if self._bass_ready():
            self._bass_fade_generation += 1
            self._bass_crossfade_generation += 1
            self.crossfade_active = False
            self.crossfade_progress = 0.0
            self._bass_engine.cancel_crossfade()
            if not restore_to_target:
                return
            try:
                target = max(0.0, min(1.0, float(self._target_volume_from_ui())))
            except Exception:
                target = max(0.0, min(1.0, float(self.volume or 0.8)))
            self.volume = target
            self._bass_engine.set_master_volume(target)
            return
        try:
            self.fade_timer.stop()
        except Exception:
            pass
        self.fade_direction = 0
        try:
            self.crossfade_timer.stop()
        except Exception:
            pass
        self.crossfade_active = False

        if not restore_to_target:
            return

        try:
            target = max(0.0, min(1.0, float(self._target_volume_from_ui())))
        except Exception:
            target = max(0.0, min(1.0, float(self.volume or 0.8)))

        try:
            if self.gst_bg_pipeline and self.is_playing:
                self.set_volume(target)
            else:
                self.volume = target
        except Exception:
            self.volume = target
                
    def fade_out(self, duration_ms=1000):
        """Fade out background music"""
        if self._bass_ready():
            if self._bass_engine.primary is None or not self.is_playing:
                return
            self._bass_fade_generation += 1
            self._bass_crossfade_generation += 1
            self.crossfade_active = False
            self.crossfade_progress = 0.0
            self._bass_engine.cancel_crossfade()
            generation = int(self._bass_fade_generation)
            self._bass_engine.slide_master_volume(0.0, duration_ms)
            QTimer.singleShot(
                max(1, int(duration_ms)),
                lambda g=generation: self._bass_stop_after_fade(g),
            )
            return
        if not self.gst_bg_pipeline or not self.is_playing:
            return
            
        # Stop any crossfade in progress
        self.crossfade_timer.stop()
        self.crossfade_active = False
        if self.gst_crossfade_pipeline:
            self.gst_crossfade_pipeline.set_state(Gst.State.NULL)
            self.gst_crossfade_pipeline = None
            
        self.fade_direction = -1
        self.fade_target_volume = 0.0
        steps = duration_ms // 50  # 50ms per step
        current_vol = self.volume
        self.fade_step_size = current_vol / steps if steps > 0 else current_vol
        self.fade_timer.start(50)
        
    def fade_in(self, target_volume=None, duration_ms=1000, allow_during_karaoke=False):
        """Fade in background music - if no target_volume, use current slider value"""

        if self._karaoke_is_active() and not allow_during_karaoke:
            print("Karaoke is active; suppressing BG fade_in()")
            return
        
        if not self.enabled:
            print("BG disabled; fade_in ignored")
            return
    
        # If no target volume specified, use manager slider if open; else saved setting
        if target_volume is None:
            target_volume = self._target_volume_from_ui()
            print(f"Using target volume from UI/setting: {target_volume}")

        if self._bass_ready():
            try:
                target_volume = max(0.0, min(1.0, float(target_volume)))
                self.volume = target_volume
                current_file = self.playlist[self.current_index] if self.playlist else ""
                if current_file and not self._bg_first_play_logged:
                    self._bg_first_play_logged = True
                    _diag(f"[BG-VOLUME] first BGM file selected={Path(current_file).name!r}")
                self._bg_volume_diag("fade-in-before-preload", current_file, extra=f"target={target_volume:.3f}")
                if self._bass_engine.primary is None and not self.preload_current_track_paused():
                    return
                self._bass_fade_generation += 1
                self._refresh_bg_normalize(deck="primary")
                self._bass_engine.set_master_volume(0.0)
                self._bg_volume_diag("fade-in-before-BASS_ChannelPlay", current_file, extra=f"target={target_volume:.3f}")
                if not self._bass_engine.play():
                    print("[BG-BASS] fade_in start failed")
                    return
                self.is_playing = True
                self._bass_engine.slide_master_volume(target_volume, duration_ms)
                self._bg_volume_diag("fade-in-after-BASS_ChannelPlay", current_file, extra=f"target={target_volume:.3f} duration_ms={int(duration_ms)}")
                self._schedule_volume_state_probe("bass-fade-in")
                print(f"Starting BASSmix fade in to volume {target_volume}")
            except Exception as e:
                print(f"[BG-BASS] fade in failed: {e}")
            return
        
        print(f"Starting fade in to volume {target_volume}")
        
        # Start playing if not already
        if not self.gst_bg_pipeline or not self.is_playing:
            print("Starting playback for fade in...")
            # Ensure pipeline exists (prefer prerolled paused pipeline for smoother start)
            if not self.gst_bg_pipeline:
                if not self.preload_current_track_paused():
                    return

            # Start from silence BEFORE entering PLAYING to avoid audible blip.
            try:
                _ve = self.gst_bg_pipeline.get_by_name("bg_music_volume")
                if _ve:
                    _ve.set_property("volume", 0.0)
            except Exception:
                pass
            self._bg_volume_diag("fade-in-before-GStreamer-PLAYING", self.get_active_track_path(), extra=f"target={float(target_volume):.3f}")

            ret = self.gst_bg_pipeline.set_state(Gst.State.PLAYING)
            if ret == Gst.StateChangeReturn.FAILURE:
                print("[BG] fade_in start failed")
                try:
                    self.gst_bg_pipeline.set_state(Gst.State.NULL)
                except Exception:
                    pass
                self.gst_bg_pipeline = None
                self.is_playing = False
                return

            self.is_playing = True
            self._bg_volume_diag("fade-in-after-GStreamer-PLAYING", self.get_active_track_path(), extra=f"target={float(target_volume):.3f}")
            self._schedule_volume_state_probe("gst-fade-in")
            # Let playback settle very briefly, then ramp up.
            QTimer.singleShot(60, lambda: self._do_fade_in(target_volume, duration_ms))
        else:
            self._do_fade_in(target_volume, duration_ms)

    def _do_fade_in(self, target_volume, duration_ms):
        """Actually perform the fade in"""
        self.fade_direction = 1
        self.fade_target_volume = target_volume
        steps = duration_ms // 50  # 50ms per step
        # Start from a small audible floor to reduce perceived dead-air at handoff.
        floor = max(0.0, min(float(target_volume) * 0.25, float(target_volume) - 0.01))
        self.fade_step_size = (float(target_volume) - floor) / steps if steps > 0 else max(0.0, float(target_volume) - floor)
        try:
            if self.gst_bg_pipeline:
                _ve = self.gst_bg_pipeline.get_by_name("bg_music_volume")
                if _ve:
                    _ve.set_property("volume", floor * self._gst_pipeline_norm("bg_music"))
            # Keep internal value aligned with actual starting point so ramp is smooth.
            self.volume = floor
        except Exception:
            pass
        print(f"Fade in: target={target_volume}, steps={steps}, step_size={self.fade_step_size}")
        self.fade_timer.start(50)
        
    def _fade_step(self):
        """Single step of fade animation"""
        if self.fade_direction == 0:
            self.fade_timer.stop()
            return
            
        current_vol = self.volume
        
        if self.fade_direction == 1:  # Fade in
            new_vol = min(current_vol + self.fade_step_size, self.fade_target_volume)
            self.set_volume(new_vol)
            if new_vol >= self.fade_target_volume:
                self.fade_direction = 0
                self.fade_timer.stop()
                print(f"Fade in complete at volume: {new_vol}")
        else:  # Fade out
            new_vol = max(current_vol - self.fade_step_size, self.fade_target_volume)
            self.set_volume(new_vol)
            if new_vol <= self.fade_target_volume:
                self.fade_direction = 0
                self.fade_timer.stop()
                if self.fade_target_volume == 0.0:
                    self.pause()
                # Restore desired volume so the next play isn't stuck at 0.0
                try:
                    self.volume = self._target_volume_from_ui()
                    print(f"Restored desired BG volume to {self.volume} after fade-out")
                except Exception:
                    pass

    def _extract_artwork_sync(self, file_path):
        """Synchronous artwork extraction (for background threads)"""
        if not MutagenFile:
            return None
            
        try:
            audio_file = MutagenFile(file_path)
            if not audio_file:
                return None
                
            artwork_data = None
            
            # MP3 files (ID3 tags)
            if hasattr(audio_file, 'tags') and audio_file.tags:
                apic_keys = [key for key in audio_file.tags.keys() if key.startswith('APIC')]
                if apic_keys:
                    for key in apic_keys:
                        try:
                            frame = audio_file.tags[key]
                            if hasattr(frame, 'data') and frame.data and len(frame.data) > 100:
                                artwork_data = frame.data
                                break
                        except Exception:
                            continue
            
            # FLAC files
            elif hasattr(audio_file, 'pictures') and audio_file.pictures:
                for pic in audio_file.pictures:
                    if pic.data and len(pic.data) > 100:
                        artwork_data = pic.data
                        break
                        
            # MP4/M4A files
            elif hasattr(audio_file, 'tags') and audio_file.tags and 'covr' in audio_file.tags:
                covers = audio_file.tags['covr']
                if covers and len(covers) > 0:
                    cover_data = covers[0]
                    if hasattr(cover_data, 'data'):
                        artwork_data = cover_data.data
                    else:
                        artwork_data = bytes(cover_data)
            
            # OGG Vorbis files
            elif hasattr(audio_file, 'tags') and audio_file.tags:
                if 'METADATA_BLOCK_PICTURE' in audio_file.tags:
                    try:
                        import base64
                        import struct
                        
                        picture_b64 = audio_file.tags['METADATA_BLOCK_PICTURE'][0]
                        picture_data = base64.b64decode(picture_b64)
                        
                        if len(picture_data) >= 32:
                            offset = 4
                            mime_length = struct.unpack('>I', picture_data[offset:offset+4])[0]
                            offset += 4 + mime_length
                            desc_length = struct.unpack('>I', picture_data[offset:offset+4])[0]
                            offset += 4 + desc_length
                            offset += 16
                            data_length = struct.unpack('>I', picture_data[offset:offset+4])[0]
                            offset += 4
                            
                            if offset + data_length <= len(picture_data):
                                artwork_data = picture_data[offset:offset+data_length]
                            
                    except Exception:
                        pass
            
            if artwork_data and len(artwork_data) > 0:
                from PyQt6.QtGui import QPixmap
                from PyQt6.QtCore import QByteArray
                
                pixmap = QPixmap()
                byte_array = QByteArray(artwork_data)
                
                if pixmap.loadFromData(byte_array):
                    return pixmap
                    
        except Exception:
            pass
            
        return None

    def get_album_artwork(self, file_path):
        """Enhanced album artwork extraction with caching - OPTIMIZED VERSION"""
        
        # INSTANT RETURN: Check cache first
        if file_path in self.artwork_cache:
            return self.artwork_cache[file_path]
        
        # If not in cache, try to extract it synchronously
        artwork = self._extract_artwork_sync(file_path)
        
        if artwork and not artwork.isNull():
            # Store in cache for future instant access
            self.artwork_cache[file_path] = artwork
            self.manage_artwork_cache()  # Keep cache size reasonable
            
        return artwork

    def get_current_artwork(self):
        """Get artwork for currently playing track - OPTIMIZED VERSION"""
        if not self.playlist or self.current_index >= len(self.playlist):
            return None
            
        current_file = self.playlist[self.current_index]
        
        # Check cache first for instant return
        if current_file in self.artwork_cache:
            return self.artwork_cache[current_file]
        
        # If not cached, try to extract (this will cache it automatically)
        return self.get_album_artwork(current_file)
    
class VideoAreaWidget(QWidget):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.background_pixmap = QPixmap()
        self.karaoke_frame = QImage()
        self.karaoke_stretch_fill = False
        self.cdg_quality_mode = "standard"
        self._karaoke_scaled_pixmap = QPixmap()
        self._karaoke_scaled_key = None
        self._karaoke_scaled_pos = QPoint(0, 0)
        self._karaoke_frame_count = 0
        self._karaoke_scale_time_ms = 0.0
        self._idle_bg_artwork_path = ""
        self._idle_bg_artwork = QPixmap()
        self._viz_phase = 0.0
        self._viz_levels = [0.08] * 14
        self._viz_peaks = [0.12] * 14
        self._viz_audio_level = 0.0
        self._idle_paint_log_ts = 0.0

    def set_background_image(self, image_path):
        if image_path and os.path.exists(image_path):
            self.background_pixmap = QPixmap(image_path)
        else:
            self.background_pixmap = QPixmap()
        self.update()

    def set_cdg_quality_mode(self, mode: str):
        mode = "high" if str(mode or "").lower() == "high" else "standard"
        if mode == self.cdg_quality_mode:
            return
        self.cdg_quality_mode = mode
        self._karaoke_scaled_key = None
        self.update()

    def set_karaoke_frame(self, image, stretch_fill: bool = False):
        # QImage is implicitly shared; avoid copying here. Scaling is cached per
        # frame/size/quality so fullscreen paints only blit an already-scaled
        # pixmap instead of redoing CDG image processing every repaint.
        self.karaoke_frame = image if image is not None and not image.isNull() else QImage()
        self.karaoke_stretch_fill = bool(stretch_fill)
        self._ensure_karaoke_scaled_pixmap()
        self.update()

    def clear_karaoke_frame(self):
        self.karaoke_frame = QImage()
        self._karaoke_scaled_pixmap = QPixmap()
        self._karaoke_scaled_key = None
        self.update()

    def resizeEvent(self, event):
        super().resizeEvent(event)
        self._karaoke_scaled_key = None
        if not self.karaoke_frame.isNull():
            self._ensure_karaoke_scaled_pixmap()

    def _ensure_karaoke_scaled_pixmap(self):
        if self.karaoke_frame.isNull() or self.width() <= 0 or self.height() <= 0:
            self._karaoke_scaled_pixmap = QPixmap()
            self._karaoke_scaled_key = None
            return
        try:
            image_key = int(self.karaoke_frame.cacheKey())
        except Exception:
            image_key = id(self.karaoke_frame)
        key = (
            image_key,
            int(self.width()),
            int(self.height()),
            bool(self.karaoke_stretch_fill),
            str(self.cdg_quality_mode),
        )
        if key == self._karaoke_scaled_key and not self._karaoke_scaled_pixmap.isNull():
            return
        mode = (
            Qt.AspectRatioMode.IgnoreAspectRatio
            if bool(self.karaoke_stretch_fill)
            else Qt.AspectRatioMode.KeepAspectRatio
        )
        transform = (
            Qt.TransformationMode.SmoothTransformation
            if self.cdg_quality_mode == "high"
            else Qt.TransformationMode.FastTransformation
        )
        t0 = time.perf_counter()
        scaled = self.karaoke_frame.scaled(self.size(), mode, transform)
        self._karaoke_scaled_pixmap = QPixmap.fromImage(scaled)
        self._karaoke_scaled_pos = QPoint(
            (self.width() - self._karaoke_scaled_pixmap.width()) // 2,
            (self.height() - self._karaoke_scaled_pixmap.height()) // 2,
        )
        self._karaoke_scaled_key = key
        self._karaoke_frame_count += 1
        self._karaoke_scale_time_ms += (time.perf_counter() - t0) * 1000.0
        if self._karaoke_frame_count % 300 == 0:
            try:
                avg = self._karaoke_scale_time_ms / max(1, self._karaoke_frame_count)
                _diag(f"[CDG-RENDER] mode={self.cdg_quality_mode} frames={self._karaoke_frame_count} avg_scale_ms={avg:.3f}")
                _perf_log_if_slow("cdg_frame_render", avg)
            except Exception:
                pass

    def set_audio_level(self, level: float):
        try:
            self._viz_audio_level = max(0.0, min(1.0, float(level)))
        except Exception:
            self._viz_audio_level = 0.0

    def advance_visualizer(self, active: bool):
        """Beat-reactive but lightweight bar animation for idle BG now-playing card."""
        if active:
            amp = max(0.0, min(1.0, float(self._viz_audio_level)))
            # Decay between meter packets to keep motion smooth.
            self._viz_audio_level = max(0.0, self._viz_audio_level * 0.88)

            # Faster phase movement at higher energy.
            self._viz_phase = (self._viz_phase + (0.12 + amp * 0.55)) % 10000.0

            for i, old in enumerate(self._viz_levels):
                wave1 = 0.5 + 0.5 * math.sin(self._viz_phase + (i * 0.60))
                wave2 = 0.5 + 0.5 * math.sin((self._viz_phase * 0.72) + (i * 1.05))
                shape = (0.62 * wave1) + (0.38 * wave2)
                target = 0.05 + (0.08 + 0.87 * shape) * max(0.08, amp)
                lvl = (old * 0.70) + (target * 0.30)
                self._viz_levels[i] = lvl

                # Peak hold cap: rises instantly, falls slowly.
                pk = self._viz_peaks[i] if i < len(self._viz_peaks) else lvl
                if lvl >= pk:
                    pk = min(1.0, lvl)
                else:
                    pk = max(0.04, pk - 0.018)
                self._viz_peaks[i] = pk
        else:
            self._viz_audio_level = 0.0
            for i, old in enumerate(self._viz_levels):
                lvl = max(0.02, old * 0.84)
                self._viz_levels[i] = lvl
                pk = self._viz_peaks[i] if i < len(self._viz_peaks) else lvl
                self._viz_peaks[i] = max(lvl, pk * 0.92)

    def _get_idle_bg_overlay_info(self):
        """Return overlay payload when karaoke is idle and BG music is actively playing."""
        try:
            vw = self.parent()
            if vw is None or not bool(getattr(vw, "idle", False)):
                return None

            owner = getattr(vw, "_external_owner", None)
            if owner is None:
                owner = vw.parent()

            bg = getattr(owner, "bg_music", None)
            if bg is None or not bool(getattr(bg, "is_playing", False)):
                return None

            playlist = getattr(bg, "playlist", None) or []
            idx = int(getattr(bg, "current_index", -1))
            if not playlist or idx < 0 or idx >= len(playlist):
                return None

            path = str(playlist[idx])
            stem = Path(path).stem
            artist = ""
            title = stem
            if " - " in stem:
                artist, title = stem.split(" - ", 1)
                artist = artist.strip()
                title = title.strip()
            else:
                title = stem.strip()

            if path != self._idle_bg_artwork_path:
                self._idle_bg_artwork_path = path
                self._idle_bg_artwork = QPixmap()
                try:
                    art = bg.get_album_artwork(path)
                    if art is not None and not art.isNull():
                        self._idle_bg_artwork = art
                except Exception:
                    pass

            return {
                "title": title or "",
                "artist": artist or "",
                "artwork": self._idle_bg_artwork,
            }
        except Exception:
            return None

    def _draw_idle_bg_overlay(self, painter: QPainter, info: dict):
        w = self.width()
        h = self.height()
        if w <= 120 or h <= 120:
            return

        card_w = min(int(w * 0.46), 680)
        card_h = min(int(h * 0.22), 210)
        margin = 18
        card_x = margin
        card_y = max(4, h - card_h - 6)

        painter.save()
        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)

        painter.setPen(Qt.PenStyle.NoPen)
        painter.setBrush(QColor(0, 0, 0, 170))
        painter.drawRoundedRect(card_x, card_y, card_w, card_h, 16, 16)

        pad = 12
        art_size = max(0, card_h - pad * 2)
        art = info.get("artwork")
        has_art = art is not None and not art.isNull()

        text_x = card_x + pad
        if has_art:
            art_pm = art.scaled(
                art_size,
                art_size,
                Qt.AspectRatioMode.KeepAspectRatioByExpanding,
                Qt.TransformationMode.SmoothTransformation,
            )
            painter.setBrush(QColor(20, 20, 20, 220))
            painter.drawRoundedRect(card_x + pad, card_y + pad, art_size, art_size, 10, 10)
            painter.drawPixmap(card_x + pad, card_y + pad, art_pm)
            text_x = card_x + pad + art_size + 12

        text_w = (card_x + card_w - pad) - text_x
        if text_w <= 40:
            painter.restore()
            return

        title = str(info.get("title", "") or "")
        artist = str(info.get("artist", "") or "")

        title_font = painter.font()
        title_font.setBold(True)
        title_font.setPointSize(max(11, int(card_h * 0.20)))

        artist_font = painter.font()
        artist_font.setBold(False)
        artist_font.setPointSize(max(9, int(card_h * 0.14)))

        title_metrics = QFontMetrics(title_font)
        artist_metrics = QFontMetrics(artist_font)

        title_text = title_metrics.elidedText(title, Qt.TextElideMode.ElideRight, text_w)
        artist_text = artist_metrics.elidedText(artist, Qt.TextElideMode.ElideRight, text_w)

        # Keep text in upper half so visualizer has its own lane below.
        top_y = card_y + pad + 2
        title_y = top_y + title_metrics.ascent()
        artist_y = title_y + max(2, int(card_h * 0.02)) + artist_metrics.ascent()

        painter.setPen(QColor("#F4F4F4"))
        painter.setFont(title_font)
        painter.drawText(text_x, title_y, title_text)

        if artist_text:
            painter.setPen(QColor("#C8C8C8"))
            painter.setFont(artist_font)
            painter.drawText(text_x, artist_y, artist_text)

        # Lightweight visualizer inside the same card (separate lower lane).
        bar_area_h = max(24, int(card_h * 0.33))
        bar_area_y = card_y + card_h - pad - bar_area_h
        bar_area_x = text_x
        bar_area_w = text_w
        if bar_area_w > 60:
            painter.setPen(Qt.PenStyle.NoPen)
            painter.setBrush(QColor(255, 255, 255, 22))
            painter.drawRoundedRect(bar_area_x, bar_area_y, bar_area_w, bar_area_h, 6, 6)

            levels = self._viz_levels or [0.08] * 14
            bar_count = len(levels)
            gap = 3
            usable_w = max(1, bar_area_w - (gap * (bar_count - 1)) - 4)
            bar_w = max(2, usable_w // bar_count)
            max_h = max(6, bar_area_h - 6)
            x = bar_area_x + 2

            peaks = self._viz_peaks if hasattr(self, "_viz_peaks") else levels
            for i, lv in enumerate(levels):
                v = max(0.03, min(1.0, float(lv)))
                h_px = max(3, int(max_h * v))
                y = bar_area_y + bar_area_h - h_px - 2
                painter.setBrush(QColor(245, 245, 245, 215))
                painter.drawRoundedRect(int(x), int(y), int(bar_w), int(h_px), 2, 2)

                # Peak-hold cap
                try:
                    pv = max(v, min(1.0, float(peaks[i])))
                except Exception:
                    pv = v
                py = bar_area_y + bar_area_h - max(2, int(max_h * pv)) - 2
                painter.setBrush(QColor(255, 255, 255, 245))
                painter.drawRoundedRect(int(x), int(py), int(bar_w), 2, 1, 1)

                x += bar_w + gap

        painter.restore()

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.fillRect(self.rect(), QColor("black"))

        if not self.karaoke_frame.isNull():
            self._ensure_karaoke_scaled_pixmap()
            if self.cdg_quality_mode == "high":
                painter.setRenderHint(QPainter.RenderHint.SmoothPixmapTransform, True)
            if not self._karaoke_scaled_pixmap.isNull():
                painter.drawPixmap(self._karaoke_scaled_pos, self._karaoke_scaled_pixmap)
        elif not self.background_pixmap.isNull():
            pm = self.background_pixmap.scaled(
                self.size(),
                Qt.AspectRatioMode.KeepAspectRatio,
                Qt.TransformationMode.SmoothTransformation
            )
            x = (self.width() - pm.width()) // 2
            y = (self.height() - pm.height()) // 2
            painter.drawPixmap(x, y, pm)

        info = self._get_idle_bg_overlay_info()
        if info:
            self._draw_idle_bg_overlay(painter, info)

        painter.end()

        # Throttled diagnostic marker: prove Qt idle frame paints are occurring.
        try:
            vw = self.parent()
            if vw is not None and bool(getattr(vw, "idle", False)):
                now = time.monotonic()
                if (now - float(getattr(self, "_idle_paint_log_ts", 0.0))) >= 2.0:
                    self._idle_paint_log_ts = now
                    pix_ok = not bool(self.background_pixmap.isNull())
        except Exception:
            pass

class MusicDatabaseWidget(QListWidget):
    """Left panel - shows all music in database"""
    
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setDragEnabled(True)
        self.setDefaultDropAction(Qt.DropAction.CopyAction)
        self.setSelectionMode(QAbstractItemView.SelectionMode.ExtendedSelection)
        
    def startDrag(self, supportedActions):
        """Custom drag with file paths as mime data"""
        items = self.selectedItems()
        if not items:
            return
            
        mime_data = QMimeData()
        paths = []
        
        for item in items:
            file_path = item.data(Qt.ItemDataRole.UserRole)
            if file_path:
                paths.append(file_path)
        
        # Store paths as JSON in mime data
        mime_data.setText(json.dumps(paths))
        
        drag = QDrag(self)
        drag.setMimeData(mime_data)
        drag.exec(Qt.DropAction.CopyAction)


# ============================================================================
# Circular avatar + bar-level meter widgets for the redesigned Now Singing /
# On Deck / Rotation Waiting card.
# ============================================================================

class CircularAvatar(QWidget):
    """A round badge displaying the current singer's first name.

    Draws a glowing purple-ring circle with a dark interior; the name auto-
    fits down to ~12pt before being clipped.  Provides ``set_mode`` and
    ``set_media_badge`` shims so it's a drop-in replacement for the old
    ``HeroVisualizerWidget`` API.
    """

    def __init__(self, parent=None):
        super().__init__(parent)
        self._name = ""
        self._mode = "idle"
        self.setMinimumSize(80, 80)
        self.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Fixed)

    # ---- legacy API shims (kept so existing code doesn't have to change) ----
    def set_mode(self, mode: str):
        self._mode = str(mode or "idle").lower()
        self.update()

    def set_media_badge(self, _text: str):
        # No longer rendered — badge moved into the text column.
        pass

    def set_name(self, name: str):
        # First word only (mirrors mockup); strip a "duet" suffix if present.
        clean = str(name or "").strip()
        # Try to keep a useful glyph for blank/idle states.
        first = clean.split()[0] if clean else ""
        # Strip emoji + decorative chars that look weird in a tight circle.
        import re as _re
        first = _re.sub(r"[^0-9A-Za-z'._-]", "", first).strip("'._-")
        self._name = first[:10]  # cap; the auto-fit shrinks the rest
        self.update()

    # ---- paint ----
    def paintEvent(self, event):
        from PyQt6.QtGui import QPainter, QPen, QBrush, QColor, QFont, QLinearGradient
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        side = min(self.width(), self.height())
        pad = 6
        cx = self.width() / 2
        cy = self.height() / 2
        r_outer = side / 2 - 2
        # Outer soft glow (three concentric rings of decreasing alpha)
        for i, alpha in enumerate((40, 70, 110)):
            grad = QLinearGradient(cx - r_outer, cy - r_outer, cx + r_outer, cy + r_outer)
            grad.setColorAt(0.0, QColor(120, 80, 255, alpha))
            grad.setColorAt(1.0, QColor(200, 100, 230, alpha))
            p.setPen(QPen(QBrush(grad), 6 - i * 2))
            p.setBrush(Qt.BrushStyle.NoBrush)
            p.drawEllipse(int(cx - r_outer + i * 2), int(cy - r_outer + i * 2),
                          int((r_outer - i * 2) * 2), int((r_outer - i * 2) * 2))
        # Solid ring + dark fill
        grad = QLinearGradient(cx - r_outer, cy - r_outer, cx + r_outer, cy + r_outer)
        grad.setColorAt(0.0, QColor(140, 80, 255))
        grad.setColorAt(1.0, QColor(210, 110, 230))
        p.setPen(QPen(QBrush(grad), 2.4))
        p.setBrush(QColor(15, 18, 30))
        inner = int(r_outer - pad)
        p.drawEllipse(int(cx - inner), int(cy - inner), int(inner * 2), int(inner * 2))
        # Name — auto-fit the largest size that fits with comfortable margin
        if self._name:
            from PyQt6.QtGui import QFontMetrics as _Fm
            font = QFont(self.font())
            font.setBold(True)
            avail = inner * 2 - 16
            for size in (34, 30, 26, 22, 18, 15, 12):
                font.setPointSize(size)
                if _Fm(font).horizontalAdvance(self._name) <= avail:
                    break
            p.setFont(font)
            p.setPen(QColor("#FFFFFF"))
            from PyQt6.QtCore import QRect as _QRect
            p.drawText(_QRect(int(cx - inner), int(cy - inner), int(inner * 2), int(inner * 2)),
                       Qt.AlignmentFlag.AlignCenter, self._name)


class BarLevelMeter(QWidget):
    """Vertical purple-pink bars whose heights respond to the current
    karaoke audio level.  Mimics the visualiser on the right of the
    mockup; bursts taller in the middle and falls off toward the edges."""

    def __init__(self, level_provider=None, n_bars: int = 12, parent=None):
        super().__init__(parent)
        self._level_provider = level_provider
        self._n_bars = max(4, int(n_bars))
        self._heights = [0.10] * self._n_bars
        self._phase = 0.0
        self._active = False
        self.setMinimumSize(86, 60)
        self.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Fixed)
        self._timer = QTimer(self)
        self._timer.setInterval(45)  # ~22 fps
        self._timer.timeout.connect(self._tick)
        self._timer.start()

    def set_active(self, active: bool):
        self._active = bool(active)

    def _sample_level(self) -> float:
        if not self._level_provider:
            return 0.0
        try:
            db, ts = self._level_provider()
        except Exception:
            return 0.0
        if db is None or ts is None:
            return 0.0
        if (time.monotonic() - float(ts)) > 0.5:
            return 0.0
        # Map -60dB→0 .. 0dB→1 with a tiny boost so quiet content still moves.
        x = max(0.0, min(1.0, (float(db) + 60.0) / 60.0))
        return x ** 0.85

    def _tick(self):
        import math
        self._phase += 0.20
        base = self._sample_level() if self._active else 0.0
        for i in range(self._n_bars):
            # Tall in centre, taper toward the edges.
            center_dist = abs(i + 0.5 - self._n_bars / 2.0) / (self._n_bars / 2.0)
            shape = 1.0 - center_dist * 0.55
            wobble = (math.sin(self._phase + i * 0.9) + 1.0) * 0.5
            target = base * shape * (0.45 + 0.55 * wobble)
            # Smooth attack/release
            cur = self._heights[i]
            self._heights[i] = cur * 0.6 + target * 0.4
        self.update()

    def paintEvent(self, event):
        from PyQt6.QtGui import QPainter, QColor, QLinearGradient, QBrush, QPen
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        w = self.width()
        h = self.height()
        margin = 4

        # If the meter is essentially silent, render a single faint baseline
        # instead of a row of identical floor-height bars (which look like
        # punctuation/dashes to a casual observer).
        max_level = max(self._heights) if self._heights else 0.0
        if max_level < 0.04:
            base_y = h - margin - 2
            grad = QLinearGradient(margin, 0, w - margin, 0)
            grad.setColorAt(0.0, QColor(120, 90, 200, 90))
            grad.setColorAt(1.0, QColor(220, 110, 200, 90))
            p.setPen(QPen(QBrush(grad), 2))
            p.drawLine(margin + 2, base_y, w - margin - 2, base_y)
            return

        usable_w = w - margin * 2
        gap = 2
        bar_w = max(2, (usable_w - (self._n_bars - 1) * gap) // self._n_bars)
        x = margin
        floor = 2  # tiny baseline so quiet bars are still visible
        for lvl in self._heights:
            bar_h = max(floor, int((h - margin * 2) * lvl))
            top = h - margin - bar_h
            grad = QLinearGradient(0, h - margin, 0, top)
            grad.setColorAt(0.0, QColor(110, 60, 240))
            grad.setColorAt(1.0, QColor(240, 90, 200))
            p.fillRect(x, top, bar_w, bar_h, QBrush(grad))
            x += bar_w + gap


class HeroVisualizerWidget(QWidget):
    def __init__(self, level_provider=None, parent=None):
        super().__init__(parent)
        self._level_provider = level_provider
        self._mode = "idle"
        self._badge_text = "KJ"
        self._phase = 0.0
        self._bars = [0.10] * 16
        self._peaks = [0.12] * 16
        self._tick = QTimer(self)
        self._tick.setInterval(45)
        self._tick.timeout.connect(self._advance)
        self._tick.start()
        self.setMinimumSize(156, 90)

    def set_media_badge(self, text: str):
        self._badge_text = str(text or "KJ").upper()
        self.update()

    def set_mode(self, mode: str):
        self._mode = str(mode or "idle").lower()
        self.update()

    def _sample_level(self) -> float:
        try:
            if not callable(self._level_provider):
                return 0.0
            db, ts = self._level_provider()
            if db is None:
                return 0.0
            if ts is not None and (time.monotonic() - float(ts)) > 0.9:
                return 0.0
            return max(0.0, min(1.0, (float(db) + 60.0) / 60.0))
        except Exception:
            return 0.0

    def _advance(self):
        level = self._sample_level() if self._mode == "live" else 0.0
        self._phase = (self._phase + (0.16 + (level * 0.55 if level > 0 else 0.06))) % 10000.0
        for i, old in enumerate(self._bars):
            if level > 0.0:
                wave1 = 0.5 + 0.5 * math.sin(self._phase + (i * 0.52))
                wave2 = 0.5 + 0.5 * math.sin((self._phase * 0.68) + (i * 1.04))
                target = 0.10 + ((0.62 * wave1) + (0.38 * wave2)) * (0.16 + level * 0.76)
            elif self._mode == "next":
                wave = 0.5 + 0.5 * math.sin((self._phase * 0.45) + (i * 0.7))
                target = 0.08 + wave * 0.10
            else:
                target = 0.05
            self._bars[i] = (old * 0.70) + (target * 0.30)
            pk = self._peaks[i]
            if self._bars[i] >= pk:
                pk = min(1.0, self._bars[i])
            else:
                pk = max(0.04, pk - 0.020)
            self._peaks[i] = pk
        self.update()

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)
        rect = self.rect().adjusted(0, 0, -1, -1)

        painter.setPen(QColor(255, 255, 255, 12))
        painter.setBrush(QColor(18, 24, 32, 245))
        painter.drawRoundedRect(rect, 10, 10)

        inner = rect.adjusted(8, 8, -8, -8)
        painter.setPen(Qt.PenStyle.NoPen)
        painter.setBrush(QColor(10, 34, 24, 78 if self._mode == "live" else 44))
        painter.drawRoundedRect(inner, 8, 8)

        bar_area = inner.adjusted(10, 14, -10, -14)
        count = max(1, len(self._bars))
        gap = 4
        bar_w = max(3, int((bar_area.width() - (gap * (count - 1))) / count))
        x = bar_area.left()
        base = bar_area.bottom()
        for i, lvl in enumerate(self._bars):
            h = max(6, int(bar_area.height() * max(0.05, min(1.0, lvl))))
            bar_rect = QRect(int(x), int(base - h), int(bar_w), int(h))
            alpha = 110 + int(min(1.0, lvl) * 55)
            color = QColor(36, 133, 255, alpha) if self._mode == "live" else QColor(72, 96, 128, 62)
            painter.setBrush(color)
            painter.drawRoundedRect(bar_rect, 2, 2)

            peak_y = max(bar_area.top() + 2, base - int(bar_area.height() * max(0.05, min(1.0, self._peaks[i]))))
            painter.setBrush(QColor(255, 255, 255, 55 if self._mode == "live" else 24))
            painter.drawRoundedRect(QRect(int(x), int(peak_y), int(bar_w), 2), 1, 1)
            x += bar_w + gap

        badge_font = painter.font()
        badge_font.setPointSize(18)
        badge_font.setBold(True)
        badge_font.setLetterSpacing(QFont.SpacingType.AbsoluteSpacing, 2.0)
        painter.setFont(badge_font)
        painter.setPen(QColor(255, 255, 255, 12))
        painter.drawText(inner.adjusted(0, 1, 0, 1), int(Qt.AlignmentFlag.AlignCenter), self._badge_text)
        painter.setPen(QColor(255, 255, 255, 26))
        painter.drawText(inner, int(Qt.AlignmentFlag.AlignCenter), self._badge_text)

class PlaylistWidget(QListWidget):
    """Right panel - current playlist with drag/drop support"""

    # Carries (paths, insert_row) — insert_row=-1 means append to end.
    tracks_added = pyqtSignal(list, int)

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setAcceptDrops(True)
        self.setDragDropMode(QListWidget.DragDropMode.InternalMove)
        self.setDefaultDropAction(Qt.DropAction.MoveAction)
        self.setSelectionMode(QAbstractItemView.SelectionMode.ExtendedSelection)

    def dragEnterEvent(self, event: QDragEnterEvent):
        """Accept drags from database or external files"""
        if event.mimeData().hasText() or event.mimeData().hasUrls():
            event.acceptProposedAction()
        else:
            super().dragEnterEvent(event)

    def dragMoveEvent(self, event):
        """Show drop-indicator so the user can see where the track will land."""
        if event.mimeData().hasText() or event.mimeData().hasUrls():
            self.setDropIndicatorShown(True)
            event.acceptProposedAction()
        else:
            super().dragMoveEvent(event)

    def _drop_row_at(self, pos) -> int:
        """Return the row index where a drop at *pos* should be inserted.

        Returns -1 when the drop lands below all existing items (append).
        """
        item = self.itemAt(pos)
        if item is None:
            return -1  # Below all items -> append
        row = self.row(item)
        # If cursor is in the lower half of the item, insert after it.
        rect = self.visualItemRect(item)
        if pos.y() > rect.top() + rect.height() // 2:
            row += 1
        if row >= self.count():
            return -1  # Would be at the very end anyway
        return row

    def dropEvent(self, event: QDropEvent):
        """Handle drops from file tree, external sources, or internal reorders."""
        new_tracks = []

        # Prefer URL payloads (QFileSystemModel drag) so folders/files from browser work reliably.
        if event.mimeData().hasUrls():
            import os
            audio_exts = {'.mp3', '.wav', '.flac', '.m4a', '.aac', '.ogg'}

            def gather_audio(path: str):
                if os.path.isdir(path):
                    for root, _, files in os.walk(path):
                        for f in files:
                            if f.startswith('.'):
                                continue
                            if os.path.splitext(f)[1].lower() in audio_exts:
                                yield os.path.join(root, f)
                else:
                    if os.path.splitext(path)[1].lower() in audio_exts:
                        yield path

            for url in event.mimeData().urls():
                p = url.toLocalFile()
                if p and os.path.exists(p):
                    for ap in gather_audio(p):
                        new_tracks.append(ap)
        # From JSON (legacy internal drag)
        elif event.mimeData().hasText():
            try:
                paths = json.loads(event.mimeData().text())
                audio_exts = {'.mp3', '.wav', '.flac', '.m4a', '.aac', '.ogg'}
                new_tracks = [
                    p for p in paths
                    if isinstance(p, str) and os.path.splitext(p)[1].lower() in audio_exts
                ]
            except json.JSONDecodeError:
                # Not JSON: internal move
                super().dropEvent(event)
                return

        if new_tracks:
            # Deduplicate while preserving order
            seen = set()
            flat = []
            for p in new_tracks:
                if p not in seen:
                    seen.add(p)
                    flat.append(p)
            insert_row = self._drop_row_at(event.position().toPoint())
            self.tracks_added.emit(flat, insert_row)
            event.acceptProposedAction()
        else:
            # Internal reordering
            super().dropEvent(event)


class SeekSlider(QSlider):
    """Horizontal slider that jumps to click position for media scrubbing."""
    def mousePressEvent(self, event):
        try:
            if event.button() == Qt.MouseButton.LeftButton and self.orientation() == Qt.Orientation.Horizontal:
                x = int(event.position().x())
                w = max(1, self.width())
                ratio = max(0.0, min(1.0, x / w))
                val = int(self.minimum() + ratio * (self.maximum() - self.minimum()))
                self.setValue(val)
                self.sliderMoved.emit(val)
        except Exception:
            pass
        super().mousePressEvent(event)


class ClickableImageLabel(QLabel):
    clicked = pyqtSignal()

    def __init__(self, text: str = "", parent=None):
        super().__init__(text, parent)
        self.setCursor(Qt.CursorShape.PointingHandCursor)

    def mousePressEvent(self, event):
        try:
            if event.button() == Qt.MouseButton.LeftButton:
                self.clicked.emit()
        except Exception:
            pass
        super().mousePressEvent(event)

class BackgroundMusicManager(QMainWindow):
    """Main window for background music management - OpenKJ style"""
    
    def __init__(self, bg_music_player, parent=None):
        super().__init__(parent)
        self.bg_music = bg_music_player
        self.host_app = parent if parent is not None and hasattr(parent, "settings") else None
        self.setWindowTitle("Background Music Manager")
        self.setGeometry(100, 100, 1000, 600)

        # Safety: make sure bg_music looks like the player, not the app
        if not hasattr(self.bg_music, "playlist") or not hasattr(self.bg_music, "play"):
            raise TypeError("BackgroundMusicManager expects a BackgroundMusicPlayer as first argument")
        
        # Playlist storage only (no database)
        self.playlist_path = Path.home() / "SingWS" / "bg_playlist.json"
        self.current_playlist = []  # Current playlist
        self._last_highlight_row = None
        self._last_highlight_count = 0
        self._bg_ui_op_in_progress = False
        self._bg_ui_cooldown_until = 0.0
        self._bg_pulse_started_at = time.monotonic()
        
        self.setup_ui()
        self._apply_main_window_look()
        self._match_main_window_geometry()
        self._browser_filter_timer = QTimer(self)
        self._browser_filter_timer.setSingleShot(True)
        self._browser_filter_timer.setInterval(220)
        self._browser_filter_timer.timeout.connect(self._apply_browser_filter_now)
        self._bg_pulse_timer = QTimer(self)
        self._bg_pulse_timer.setInterval(100)
        self._bg_pulse_timer.timeout.connect(self._tick_bg_pulse)
        self.load_data()
        self.setup_connections()
        self._init_file_browser()

    def _host(self):
        host = getattr(self, "host_app", None)
        if host is not None:
            return host
        p = self.parent()
        if p is not None and hasattr(p, "settings"):
            return p
        return None

    def _add_selected_from_library(self):
        items = self.library_list.selectedItems()
        paths = []
        for it in items:
            p = it.data(Qt.ItemDataRole.UserRole)
            if p:
                paths.append(p)
        if paths:
            self.add_tracks_to_playlist(paths)

    def _sync_to_player(self, reset_index: bool = True, defer_pipeline_realign: bool = False):
        """
        Mirror the manager's Current Playlist into the BackgroundMusicPlayer.
        Tries self.bg_music first; falls back to parent().bg_music.
        """
        player = getattr(self, "bg_music", None)
        host = self._host()
        if player is None and host is not None and hasattr(host, "bg_music"):
            player = host.bg_music
        if player is None:
            return  # no player wired yet

        # Push just the file paths to the player
        player.playlist = [t["path"] for t in self.current_playlist]
        if reset_index:
            player.current_index = 0

        # If BG is not actively playing, align any preloaded paused pipeline.
        # For idle shuffles, this can be deferred to the next play to avoid stop/start thrash.
        try:
            is_playing = bool(getattr(player, "is_playing", False))
            if not is_playing:
                expected = ""
                if player.playlist and 0 <= int(player.current_index) < len(player.playlist):
                    expected = str(player.playlist[int(player.current_index)])
                active = ""
                if hasattr(player, "get_active_track_path"):
                    active = str(player.get_active_track_path() or "")
                if getattr(player, "gst_bg_pipeline", None) is not None and active and expected and active != expected:
                    if defer_pipeline_realign:
                        player._pipeline_realign_needed = True
                    else:
                        player.stop()
                        if player.playlist:
                            player.preload_current_track_paused()
        except Exception:
            pass

        # Nudge the mini panel in the main window if present
        parent = self._host()
        if parent and hasattr(parent, "update_bg_track_display"):
            try: parent.update_bg_track_display()
            except Exception: pass
        if parent and hasattr(parent, "update_bg_button_state"):
            try: parent.update_bg_button_state()
            except Exception: pass

    def _begin_bg_ui_action(self, action: str) -> bool:
        now = time.monotonic()
        if self._bg_ui_op_in_progress or now < self._bg_ui_cooldown_until:
            _diag(f"[BG-ACT] ignored action={action} busy_or_cooldown=True")
            return False
        self._bg_ui_op_in_progress = True
        # Small cooldown to absorb double-click bursts.
        self._bg_ui_cooldown_until = now + 0.25
        return True

    def _end_bg_ui_action(self):
        self._bg_ui_op_in_progress = False

    def _init_file_browser(self):
        """Initialize live filesystem browser (no bgmusic.json index)."""
        self.fs_model = QFileSystemModel(self)
        try:
            self.fs_model.setFilter(QDir.Filter.AllDirs | QDir.Filter.Files | QDir.Filter.NoDotAndDotDot | QDir.Filter.Drives)
            self.fs_model.setNameFilterDisables(False)
            self.fs_model.setNameFilters(self._audio_name_filters(""))
        except Exception:
            pass
        self.fs_model.setRootPath("")

        self.fs_tree.setModel(self.fs_model)
        self.fs_tree.setSortingEnabled(True)
        self.fs_tree.sortByColumn(0, Qt.SortOrder.AscendingOrder)
        self.fs_tree.setHeaderHidden(True)
        # Keep browser compact like a DJ crate list.
        for c in (1, 2, 3):
            try:
                self.fs_tree.hideColumn(c)
            except Exception:
                pass

        self._browser_roots = []
        try:
            self._browser_roots.append(("Home", str(Path.home())))
            if sys.platform == "darwin":
                self._browser_roots.append(("Macintosh HD", "/"))
                if Path("/Volumes").exists():
                    self._browser_roots.append(("Volumes", "/Volumes"))
            elif sys.platform == "win32":
                for d in QDir.drives():
                    p = d.absolutePath()
                    self._browser_roots.append((p.rstrip("\\/"), p))
            else:
                self._browser_roots.append(("Root (/)", "/"))
        except Exception:
            self._browser_roots = [("Home", str(Path.home()))]

        self.browser_root_combo.blockSignals(True)
        self.browser_root_combo.clear()
        for label, _path in self._browser_roots:
            self.browser_root_combo.addItem(label)
        self.browser_root_combo.blockSignals(False)
        self._set_browser_root(self._browser_roots[0][1] if self._browser_roots else str(Path.home()))

    def _set_browser_root(self, root_path: str):
        idx = self.fs_model.index(root_path)
        if idx.isValid():
            self.fs_tree.setRootIndex(idx)

    def _on_browser_root_changed(self, index: int):
        if 0 <= index < len(self._browser_roots):
            self._set_browser_root(self._browser_roots[index][1])

    def _open_browser_folder(self):
        folder = QFileDialog.getExistingDirectory(self, "Select Folder")
        if not folder:
            return
        # Add the folder as a quick root for fast return.
        if all(folder != p for _l, p in self._browser_roots):
            self._browser_roots.append((Path(folder).name or folder, folder))
            self.browser_root_combo.addItem(self._browser_roots[-1][0])
        self._set_browser_root(folder)

    def _audio_extensions(self) -> tuple[str, ...]:
        return ('.mp3', '.wav', '.flac', '.m4a', '.aac', '.ogg')

    def _audio_name_filters(self, term: str) -> list[str]:
        term = (term or "").strip()
        if not term:
            return [f"*{ext}" for ext in self._audio_extensions()]
        return [f"*{term}*{ext}" for ext in self._audio_extensions()]

    def _is_audio_file(self, path: str) -> bool:
        ext = os.path.splitext(path)[1].lower()
        return ext in set(self._audio_extensions())

    def _collect_audio_from_path(self, path: str) -> list[str]:
        out = []
        term = (self.library_search.text() or "").strip().lower()
        try:
            if os.path.isdir(path):
                for root, _, files in os.walk(path):
                    for f in files:
                        if f.startswith('.'):
                            continue
                        full = os.path.join(root, f)
                        if self._is_audio_file(full):
                            if term and term not in f.lower():
                                continue
                            out.append(full)
            else:
                if self._is_audio_file(path):
                    if not term or term in os.path.basename(path).lower():
                        out.append(path)
        except Exception:
            pass
        return out

    def _selected_browser_paths(self) -> list[str]:
        paths = []
        seen = set()
        try:
            for idx in self.fs_tree.selectionModel().selectedRows():
                p = self.fs_model.filePath(idx)
                if p and p not in seen:
                    seen.add(p)
                    paths.append(p)
        except Exception:
            pass
        return paths

    def _add_selected_from_browser(self):
        picked = []
        seen = set()
        for p in self._selected_browser_paths():
            for ap in self._collect_audio_from_path(p):
                if ap not in seen:
                    seen.add(ap)
                    picked.append(ap)
        if picked:
            self.add_tracks_to_playlist(picked)

    def _on_browser_double_click(self, index):
        p = self.fs_model.filePath(index)
        if not p:
            return
        # Double-click folder: normal tree navigation (expand/collapse), no root jump.
        if os.path.isdir(p):
            self.fs_tree.setExpanded(index, not self.fs_tree.isExpanded(index))
            return
        # Double-click audio file: add just that file.
        tracks = self._collect_audio_from_path(p)
        if tracks:
            self.add_tracks_to_playlist(tracks)

    def _on_browser_filter_changed(self, _text: str):
        # Debounce filesystem model filtering; setNameFilters can trigger a
        # visible tree refresh, so avoid repainting the browser on every key.
        try:
            self._browser_filter_timer.start()
        except Exception:
            self._apply_browser_filter_now()

    def _apply_browser_filter_now(self):
        try:
            self.fs_model.setNameFilters(self._audio_name_filters(self.library_search.text()))
        except Exception:
            pass

    def _bg_pulse_value(self) -> float:
        """Slow eased pulse for active BGM indicators.

        A single 10 fps timer drives only the small now-playing card while BGM
        is active, keeping repaint cost low and avoiding the old blink effect.
        """
        period = 1.8
        t = (time.monotonic() - float(getattr(self, "_bg_pulse_started_at", time.monotonic()))) % period
        return 0.5 - (0.5 * math.cos((t / period) * math.tau))

    def _bg_player_frame_css(self, active: bool, pulse: float = 0.0) -> str:
        if active:
            glow = 0.14 + (0.11 * max(0.0, min(1.0, float(pulse))))
            border = 0.26 + (0.16 * max(0.0, min(1.0, float(pulse))))
            return f"""
            QFrame#bgPlayerFrame {{
                background: qlineargradient(x1:0,y1:0,x2:1,y2:1,
                    stop:0 rgba(54,214,138,{glow:.3f}),
                    stop:0.42 {_v('surface_alt')},
                    stop:1 {_v('surface')});
                border: 1px solid rgba(141,255,177,{border:.3f});
                border-radius: 8px;
            }}
            """
        return content_card_css("bgPlayerFrame", radius=12)

    def _apply_bg_pulse_style(self):
        try:
            active = bool(getattr(self.bg_music, "is_playing", False))
            if getattr(self, "bg_player_frame", None) is not None:
                self.bg_player_frame.setStyleSheet(self._bg_player_frame_css(active, self._bg_pulse_value()))
            if getattr(self, "bg_now_playing_kicker", None) is not None:
                color = _v("now_singing") if active else _v("text_soft")
                self.bg_now_playing_kicker.setStyleSheet(
                    f"color:{color}; font-size:11px; font-weight:750; letter-spacing:0px;"
                )
        except Exception:
            pass

    def _tick_bg_pulse(self):
        self._apply_bg_pulse_style()

    def _sync_bg_pulse_timer(self):
        try:
            active = bool(getattr(self.bg_music, "is_playing", False))
            timer = getattr(self, "_bg_pulse_timer", None)
            if timer is None:
                return
            if active:
                if not timer.isActive():
                    self._bg_pulse_started_at = time.monotonic()
                    timer.start()
            else:
                if timer.isActive():
                    timer.stop()
            self._apply_bg_pulse_style()
        except Exception:
            pass

    def _play_next_insert_row(self) -> int:
        """Return the playlist row immediately after the currently playing track.

        If nothing is playing, returns -1 (append to end).
        """
        try:
            player = getattr(self, "bg_music", None)
            if player is None:
                return -1
            if not getattr(player, "is_playing", False):
                return -1
            idx = int(getattr(player, "current_index", -1))
            if idx < 0:
                return -1
            # Insert right after the current track.
            return idx + 1
        except Exception:
            return -1

    def _add_as_play_next_from_browser(self):
        """Collect selected browser paths and insert them right after the current track."""
        picked = []
        seen = set()
        for p in self._selected_browser_paths():
            for ap in self._collect_audio_from_path(p):
                if ap not in seen:
                    seen.add(ap)
                    picked.append(ap)
        if picked:
            row = self._play_next_insert_row()
            self.add_tracks_to_playlist(picked, insert_row=row)

    def _show_browser_context_menu(self, pos):
        menu = QMenu(self.fs_tree)
        style_app_menu(menu)

        add_selected = menu.addAction("Add Selected to Playlist")
        # "Play Next" — insert right after the currently playing track.
        play_next_action = menu.addAction("Play Next")

        chosen = menu.exec(self.fs_tree.viewport().mapToGlobal(pos))
        if chosen is None:
            return
        if chosen == add_selected:
            self._add_selected_from_browser()
            return
        if chosen == play_next_action:
            self._add_as_play_next_from_browser()
            return
        
