    def set_embedded_mode(self, embedded: bool = True):
        """Switch between standalone window mode and embedded in-app mode."""
        try:
            self.setWindowFlags(Qt.WindowType.Widget if embedded else Qt.WindowType.Window)
        except Exception:
            pass
        try:
            self.setWindowTitle("" if embedded else "Background Music Manager")
        except Exception:
            pass
        try:
            self.setMinimumSize(0, 0)
            self.setMaximumSize(16777215, 16777215)
        except Exception:
            pass
        try:
            self.show()
        except Exception:
            pass

    def _normalize_fonts_local(self):
        """Force widgets in this window to use QApplication's current font."""
        try:
            app_font = QApplication.font()
        except Exception:
            return

        # Include self + all child widgets
        try:
            self.setFont(app_font)
        except Exception:
            pass

        try:
            for w in self.findChildren(QWidget):
                try:
                    w.setFont(app_font)
                except Exception:
                    pass
        except Exception:
            pass

    def _set_compact_bg_font(self, widget, *, size: int = 12, weight=None):
        try:
            if widget is None:
                return
            f = QApplication.font()
            f.setPointSize(int(size))
            if weight is not None:
                f.setWeight(weight)
            widget.setFont(f)
        except Exception:
            pass

    def _refresh_workspace_meta(self):
        try:
            count = len(self.current_playlist)
            if count <= 0:
                self.bg_workspace_meta.setText("Playlist workspace")
            else:
                self.bg_workspace_meta.setText(f"{count} queued track{'s' if count != 1 else ''}")
        except Exception:
            pass

    def _style_buttons_to_match_main(self):
        """Style QPushButtons similar to KaraokeApp.style_buttons_to_match_queue()."""
        button_style = button_css()
        compact_style = subtle_button_css(padding="5px 10px", radius=8).replace("font-size: 13px;", "font-size: 12px;")
        transport_style = subtle_button_css(padding="4px 8px", radius=8).replace("font-size: 13px;", "font-size: 12px;")

        transport_names = {
            "prev_button",
            "play_button",
            "next_button",
            "stop_button",
        }
        compact_names = {
            "add_selected_button",
            "playlist_up_button",
            "playlist_down_button",
            "remove_selected_button",
            "shuffle_button",
            "clear_playlist_button",
        }

        try:
            for btn in self.findChildren(QPushButton):
                # Preserve any intentionally custom-styled buttons
                try:
                    if btn.styleSheet().strip():
                        continue
                except Exception:
                    pass
                try:
                    if btn.objectName() in transport_names:
                        btn.setStyleSheet(transport_style)
                    elif btn.objectName() in compact_names:
                        btn.setStyleSheet(compact_style)
                    else:
                        btn.setStyleSheet(button_style)
                except Exception:
                    pass
        except Exception:
            pass

    def _match_main_window_geometry(self):
        """Size this window to match the main window when possible."""
        p = self._host()
        if p is None:
            return
        try:
            g = p.geometry()
        except Exception:
            return
        try:
            self.resize(g.width(), g.height())
        except Exception:
            pass
        # Slight offset so it doesn't perfectly cover the main window
        try:
            self.move(g.x() + 30, g.y() + 30)
        except Exception:
            pass


