# LOGGING SYSTEM - Comprehensive diagnostic logging
# ============================================================================

class SingWSLogger:
    """Centralized logging for SingWS - collects system info, tracks events, detects issues"""
    
    @staticmethod
    def log_session_start(app_instance=None):
        """Log comprehensive session start information"""
        import platform
        logging.info("=" * 80)
        logging.info(f"SingWS v{APP_VERSION} - Session Started")
        logging.info("=" * 80)
        logging.info(f"Date/Time: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
        logging.info("")
        
        # Operating System
        logging.info("OPERATING SYSTEM:")
        logging.info(f"- OS: {platform.system()} {platform.release()}")
        logging.info(f"- Version: {platform.version()}")
        logging.info(f"- Architecture: {platform.machine()}")
        
        # Hardware info (if psutil available)
        if PSUTIL_AVAILABLE:
            try:
                # CPU
                logging.info("")
                logging.info("HARDWARE:")
                cpu_count = psutil.cpu_count(logical=False)
                cpu_count_logical = psutil.cpu_count(logical=True)
                logging.info(f"CPU:")
                try:
                    cpu_freq = psutil.cpu_freq()
                    if cpu_freq:
                        logging.info(f"- Speed: {cpu_freq.current:.0f} MHz (Max: {cpu_freq.max:.0f} MHz)")
                except:
                    pass
                logging.info(f"- Cores: {cpu_count} physical, {cpu_count_logical} logical")
                
                # Memory
                mem = psutil.virtual_memory()
                logging.info("")
                logging.info("Memory:")
                logging.info(f"- Total RAM: {mem.total / (1024**3):.1f} GB")
                logging.info(f"- Available: {mem.available / (1024**3):.1f} GB ({100 - mem.percent:.1f}% free)")
                
                # SingWS process memory
                try:
                    process = psutil.Process()
                    process_mem = process.memory_info().rss / (1024**2)  # MB
                    logging.info(f"- SingWS Memory: {process_mem:.0f} MB")
                except:
                    pass
                    
            except Exception as e:
                logging.warning(f"Could not collect hardware info: {e}")
        else:
            logging.info("")
            logging.info("HARDWARE: psutil not available (install for detailed stats)")
        
        # Python/Library versions
        logging.info("")
        logging.info("RUNTIME ENVIRONMENT:")
        logging.info(f"- Python: {platform.python_version()}")
        try:
            from PyQt6.QtCore import PYQT_VERSION_STR
            logging.info(f"- PyQt6: {PYQT_VERSION_STR}")
        except:
            pass
        try:
            import gi
            gi.require_version('Gst', '1.0')
            from gi.repository import Gst
            gst_version = Gst.version_string()
            logging.info(f"- GStreamer: {gst_version}")
        except:
            pass
        if PSUTIL_AVAILABLE:
            logging.info(f"- psutil: {psutil.__version__}")
        
        logging.info("=" * 80)
        logging.info("")

    @staticmethod
    def log_gstreamer_runtime_diagnostics():
        """Log runtime path/env details to diagnose app-bundle vs system GStreamer usage."""
        logging.info("GSTREAMER RUNTIME DIAGNOSTICS:")
        try:
            logging.info(f"- sys.frozen: {bool(getattr(sys, 'frozen', False))}")
            logging.info(f"- sys.executable: {getattr(sys, 'executable', '')}")
        except Exception:
            pass

        try:
            if _GST_RUNTIME_DEBUG:
                for k in sorted(_GST_RUNTIME_DEBUG.keys()):
                    v = str(_GST_RUNTIME_DEBUG.get(k, ""))
                    exists = ""
                    try:
                        p = Path(v)
                        if p.is_absolute():
                            exists = f" (exists={p.exists()})"
                    except Exception:
                        pass
                    logging.info(f"- setup.{k}: {v}{exists}")
            else:
                logging.info("- setup snapshot: <empty>")
        except Exception as e:
            logging.warning(f"Could not log setup snapshot: {e}")

        env_keys = [
            "PATH",
            "GI_TYPELIB_PATH",
            "GST_PLUGIN_PATH",
            "GST_PLUGIN_PATH_1_0",
            "GST_PLUGIN_SYSTEM_PATH",
            "GST_PLUGIN_SYSTEM_PATH_1_0",
            "GST_PLUGIN_SCANNER",
            "GST_REGISTRY",
            "GST_REGISTRY_REUSE_PLUGIN_SCANNER",
            "DYLD_LIBRARY_PATH",
            "DYLD_FALLBACK_LIBRARY_PATH",
        ]
        for k in env_keys:
            try:
                v = os.environ.get(k, "")
                if v:
                    logging.info(f"- env.{k}: {v}")
            except Exception:
                pass

        try:
            import gi
            gi.require_version('Gst', '1.0')
            from gi.repository import Gst
            reg = Gst.Registry.get()
            for plugin_name in ("coreelements", "playback", "autodetect", "volume"):
                try:
                    plug = reg.find_plugin(plugin_name)
                    if plug:
                        logging.info(f"- plugin.{plugin_name}: {plug.get_filename()}")
                    else:
                        logging.info(f"- plugin.{plugin_name}: <not found>")
                except Exception as pe:
                    logging.info(f"- plugin.{plugin_name}: <error: {pe}>")
        except Exception as e:
            logging.warning(f"Could not query loaded GStreamer plugins: {e}")
        logging.info("")
    
    @staticmethod
    def log_library_stats(tracks_list, db_path=None):
        """Log library statistics"""
        if not tracks_list:
            logging.info("LIBRARY: No tracks loaded yet")
            return
            
        total = len(tracks_list)
        logging.info("LIBRARY STATISTICS:")
        logging.info(f"Total Tracks: {total:,}")
        logging.info("")
        
        # Count by type
        type_counts = {'zip': 0, 'mp4': 0, 'cdg': 0, 'mp3': 0, 'other': 0}
        duration_count = 0
        total_duration = 0
        
        for track in tracks_list:
            track_type = (track.get('type') or '').lower()
            if track_type == 'mp3g':
                type_counts['zip'] += 1
            elif track_type in type_counts:
                type_counts[track_type] += 1
            else:
                type_counts['other'] += 1
            
            # Duration tracking
            dur = track.get('duration') or track.get('duration_secs')
            if dur:
                duration_count += 1
                total_duration += int(dur)
        
        # Log file type breakdown
        logging.info("By File Type:")
        if type_counts['zip'] > 0:
            logging.info(f"- ZIP (MP3+G): {type_counts['zip']:,} files ({type_counts['zip']/total*100:.1f}%)")
        if type_counts['mp4'] > 0:
            logging.info(f"- MP4 (Video): {type_counts['mp4']:,} files ({type_counts['mp4']/total*100:.1f}%)")
        if type_counts['cdg'] > 0:
            logging.info(f"- CDG (Unzipped): {type_counts['cdg']:,} files ({type_counts['cdg']/total*100:.1f}%)")
        if type_counts['mp3'] > 0:
            logging.info(f"- MP3 (Audio): {type_counts['mp3']:,} files ({type_counts['mp3']/total*100:.1f}%)")
        if type_counts['other'] > 0:
            logging.info(f"- Other: {type_counts['other']:,} files ({type_counts['other']/total*100:.1f}%)")
        
        # Duration info
        logging.info("")
        logging.info("Duration Data:")
        logging.info(f"- Tracks with duration: {duration_count:,} ({duration_count/total*100:.1f}%)")
        logging.info(f"- Tracks missing duration: {total - duration_count:,} ({(total-duration_count)/total*100:.1f}%)")
        if total_duration > 0:
            hours = total_duration / 3600
            days = hours / 24
            avg_duration = total_duration / duration_count if duration_count > 0 else 0
            logging.info(f"- Total playback time: {hours:.0f} hours ({days:.0f} days)")
            logging.info(f"- Average song length: {int(avg_duration//60)}:{int(avg_duration%60):02d}")
        
        # Database info
        if db_path:
            try:
                from pathlib import Path
                db_file = Path(db_path)
                if db_file.exists():
                    db_size = db_file.stat().st_size / (1024**2)  # MB
                    logging.info("")
                    logging.info("Database:")
                    logging.info(f"- File: {db_file.name}")
                    logging.info(f"- Size: {db_size:.1f} MB")
            except:
                pass
        
        logging.info("")
    
    @staticmethod
    def log_playback_start(file_type, file_path, key, singer, duration=None):
        """Log playback start event"""
        logging.info(f"PLAYBACK_START: {file_type}")
        logging.info(f"  File: {file_path}")
        if key != 0:
            logging.info(f"  Key: {key:+d} semitones")
        if singer:
            logging.info(f"  Singer: {singer}")
        if duration:
            mins = int(duration // 60)
            secs = int(duration % 60)
            logging.info(f"  Duration: {mins}:{secs:02d}")
    
    @staticmethod
    def log_playback_end(duration_played=None, reason=""):
        """Log playback end event"""
        msg = "PLAYBACK_END"
        if duration_played:
            mins = int(duration_played // 60)
            secs = int(duration_played % 60)
            msg += f": {mins}:{secs:02d} played"
        if reason:
            msg += f" ({reason})"
        logging.info(msg)
    
    @staticmethod
    def log_freeze_detected(duration_seconds, state_info=None):
        """Log UI freeze detection"""
        logging.warning(f"FREEZE_DETECTED: UI frozen for {duration_seconds:.1f}s")
        if state_info:
            logging.warning(f"  Active operations: {state_info}")
        
        # Log system state during freeze (if psutil available)
        if PSUTIL_AVAILABLE:
            try:
                process = psutil.Process()
                cpu = process.cpu_percent()
                mem = process.memory_info().rss / (1024**2)  # MB
                logging.warning(f"  SingWS CPU: {cpu:.1f}%")
                logging.warning(f"  SingWS Memory: {mem:.0f} MB")
            except:
                pass
    
    @staticmethod
    def log_scan_start(folder_path):
        """Log library scan start"""
        logging.info(f"SCAN_START: {folder_path}")
    
    @staticmethod
    def log_scan_complete(tracks_found, duration_seconds, file_counts=None):
        """Log library scan completion"""
        logging.info(f"SCAN_COMPLETE: {tracks_found:,} tracks in {duration_seconds:.1f}s")
        if file_counts:
            for file_type, count in file_counts.items():
                logging.info(f"  - {file_type}: {count:,}")
    
    @staticmethod
    def log_external_request(artist, title, singer, key):
        """Log external request received"""
        logging.info(f"EXTERNAL_REQUEST: {artist} - {title} for {singer} ({key:+d} key)")
    
    @staticmethod
    def log_error(message, exception=None):
        """Log error with optional exception"""
        logging.error(f"ERROR: {message}")
        if exception:
            import traceback
            logging.error(traceback.format_exc())
    
    @staticmethod
    def log_crash(exc_type, exc_value, exc_traceback):
        """Log crash with full details - called by exception handler"""
        import traceback
        
        crash_time = datetime.now().strftime('%Y-%m-%d_%H-%M-%S')
        crash_log = LOGS_DIR / f"crash_report_{crash_time}.log"
        
        # Write crash report
        with open(crash_log, 'w', encoding='utf-8') as f:
            f.write("=" * 80 + "\n")
            f.write("CRASH REPORT\n")
            f.write("=" * 80 + "\n")
            f.write(f"Timestamp: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n\n")
            
            f.write("Exception:\n")
            f.write(f"  Type: {exc_type.__name__}\n")
            f.write(f"  Message: {exc_value}\n\n")
            
            f.write("Traceback:\n")
            f.write(''.join(traceback.format_exception(exc_type, exc_value, exc_traceback)))
            f.write("\n")
            
            # System state at crash
            if PSUTIL_AVAILABLE:
                try:
                    process = psutil.Process()
                    mem = psutil.virtual_memory()
                    f.write("System State at Crash:\n")
                    f.write(f"  - Total Memory: {mem.total / (1024**3):.1f} GB\n")
                    f.write(f"  - Available Memory: {mem.available / (1024**3):.1f} GB\n")
                    f.write(f"  - SingWS Memory: {process.memory_info().rss / (1024**2):.0f} MB\n")
                    f.write(f"  - CPU Usage: {process.cpu_percent():.1f}%\n")
                except:
                    pass
        
        logging.critical(f"CRASH DETECTED - Report saved to: {crash_log}")
        logging.critical(f"Exception: {exc_type.__name__}: {exc_value}")
        
        return crash_log


# Setup global exception handler
def exception_handler(exc_type, exc_value, exc_traceback):
    """Global exception handler - logs crashes"""
    crash_log = SingWSLogger.log_crash(exc_type, exc_value, exc_traceback)
    
    # Show user-friendly message
    try:
        from PyQt6.QtWidgets import QMessageBox
        QMessageBox.critical(
            None, 
            "SingWS Crashed", 
            f"SingWS encountered an error and will close.\n\n"
            f"Crash report saved to:\n{crash_log}\n\n"
            f"Please send this file to the developer for analysis."
        )
    except:
        pass
    
    # Call default handler
    sys.__excepthook__(exc_type, exc_value, exc_traceback)

# Install exception handler
sys.excepthook = exception_handler

