class SimplePollWorker(QObject):
    requests_received = pyqtSignal(list)
    host_commands_received = pyqtSignal(list)
    host_state_sync_requested = pyqtSignal()
    connection_status_changed = pyqtSignal(bool, str)  # NEW: (connected, message)

    def __init__(self, base_url, user_id, api_key, interval_sec=2, host_interval_sec=2):
        super().__init__()
        self.base_url = _network_normalize_base_url(base_url)
        self.user_id = (user_id or "").strip() or "default"
        self.api_key = (api_key or "").strip()
        self.normal_interval = interval_sec
        self.interval = interval_sec
        self.host_interval = max(2.0, float(host_interval_sec or 2))
        self._stop_evt = threading.Event()

        # Auto-recovery tracking
        self.consecutive_failures = 0
        self.max_failures_before_backoff = 3
        self.backoff_interval = 30  # Retry every 30s when disconnected
        self.last_status = None  # Track status changes

        # Change detection: only hand the payload to the UI-thread reconcile when
        # the server's request list actually changed. This lets us poll quickly
        # (network-only, cheap) without doing queue work on the UI thread every
        # cycle when nothing is new.
        self._last_sig = None

    def stop(self):
        self._stop_evt.set()

    def run(self):
        # Runs inside the QThread with auto-recovery
        import time as time_module
        next_request_poll = 0.0
        next_host_poll = 0.0
        while not self._stop_evt.is_set() and not QThread.currentThread().isInterruptionRequested():
            now = time_module.time()
            headers = {}
            if self.api_key:
                headers["X-API-Key"] = self.api_key

            if now >= next_request_poll:
                next_request_poll = now + max(1, int(self.interval))
                try:
                    params = {"user": self.user_id, "sync": "1"}

                    start_time = time_module.time()

                    resp = requests.get(
                        f"{self.base_url}/get_requests.php",
                        params=params,
                        headers=headers,
                        timeout=8
                    )

                    elapsed = time_module.time() - start_time
                    elapsed_ms = elapsed * 1000.0
                    if elapsed_ms >= 200.0:
                        _perf_log_if_slow("server_sync", elapsed_ms)

                    if resp.status_code == 200:
                        # SUCCESS - reset failure counter and restore normal interval
                        if self.consecutive_failures > 0:
                            self.consecutive_failures = 0
                            if self.interval != self.normal_interval:
                                self.interval = self.normal_interval
                                print(f"[POLL] Connection restored, back to {self.normal_interval}s interval")
                                # Notify UI that connection is back
                                if self.last_status != "connected":
                                    self.connection_status_changed.emit(True, "Connected")
                                    self.last_status = "connected"

                        try:
                            body = resp.text or ""
                            sig = hash(body)
                            changed = (sig != self._last_sig)
                            self._last_sig = sig
                            # Only do the (UI-thread) reconcile when something
                            # actually changed — keeps fast polling cheap.
                            if changed:
                                data = resp.json()
                                if data:
                                    print(f"[POLL] change detected (fetch {elapsed_ms:.0f}ms) -> updating app")
                                    self.requests_received.emit(data)
                            elif elapsed_ms >= 500.0:
                                print(f"[POLL] no change (fetch {elapsed_ms:.0f}ms)")
                        except Exception:
                            txt = (resp.text or "")[:200]
                            print(f"Poll failed: response not JSON (first 200): {txt!r}")
                    else:
                        txt = (resp.text or "")[:200]
                        print(f"Poll failed: HTTP {resp.status_code} - {txt!r}")
                        self.consecutive_failures += 1

                except Exception as e:
                    elapsed = time_module.time() - start_time if 'start_time' in locals() else 0
                    print(f"[POLL] Poll failed after {elapsed:.2f}s: {e}")
                    self.consecutive_failures += 1

            if self.api_key and now >= next_host_poll:
                next_host_poll = now + self.host_interval
                try:
                    resp = requests.get(
                        f"{self.base_url}/api/v1/host_commands.php",
                        params={"user": self.user_id, "action": "poll"},
                        headers=headers,
                        timeout=3,
                    )
                    if resp.status_code == 200:
                        self.host_state_sync_requested.emit()
                        payload = resp.json()
                        commands = payload.get("commands") if isinstance(payload, dict) else None
                        if isinstance(commands, list) and commands:
                            self.host_commands_received.emit(commands)
                    elif resp.status_code not in (404, 401, 403):
                        print(f"[HOST-CONTROLS] poll failed HTTP {resp.status_code}: {(resp.text or '')[:120]!r}")
                except Exception as e:
                    print(f"[HOST-CONTROLS] poll failed: {e}")
            
            # Handle backoff after repeated failures
            if self.consecutive_failures >= self.max_failures_before_backoff:
                if self.interval != self.backoff_interval:
                    self.interval = self.backoff_interval
                    print(f"[POLL] Connection lost, retrying every {self.backoff_interval}s...")
                    # Notify UI that connection is lost
                    if self.last_status != "disconnected":
                        self.connection_status_changed.emit(False, f"Connection lost, retrying every {self.backoff_interval}s")
                        self.last_status = "disconnected"

            # Interruptible short wait keeps host remote controls responsive.
            self._stop_evt.wait(0.5)

class DurationProbeWorker(QObject):
    progress = pyqtSignal(int, int)   # (done, total)
    finished = pyqtSignal()

    def __init__(self, app):
        super().__init__()
        self.app = app
        # How many durations this run actually resolved. Used to decide whether a
        # post-probe index rebuild is warranted (no new durations → no reindex).
        self.resolved_count = 0

    def run(self):
        """Background thread: probe missing durations for tracks (parallel processing)."""
        import logging
        import time

        # Skip tracks already flagged as unresolvable on this build so we don't
        # re-probe (and reindex) them on every launch. A rescan rebuilds tracks
        # from scratch, clearing the flag, so they get one fresh attempt then.
        tracks = [t for t in self.app.tracks
                if not t.get("duration")
                and not t.get("dur_unavailable")
                and t.get("type") in ("cdg", "mp3g", "mp4")]
        total = len(tracks)
        done = 0

        # heartbeat so UI moves immediately
        self.progress.emit(done, total)

        # Track progress with a lock for thread safety
        from threading import Lock
        progress_lock = Lock()
        
        # Track statistics
        stats = {
            'cdg_method': 0,      # Fast CDG size calculation
            'mp3_method': 0,      # Slower MP3 header parsing
            'mp4_method': 0,      # MP4 files
            'cdg_pairs': 0,       # Unzipped CDG+MP3 pairs
            'failed': 0,          # Failed to get duration
            'resolved': 0,        # Newly resolved durations this run
            'start_time': time.time()
        }
        stats_lock = Lock()
        
        # Log start of duration scan
        logging.info("=" * 80)
        logging.info("DURATION SCAN START")
        logging.info(f"Total files to probe: {total:,}")
        try:
            max_workers = 4 if self.app._performance_mode() else 12
        except Exception:
            max_workers = 12
        logging.info(f"Parallel workers: {max_workers}")
        logging.info(f"Method: CDG size calculation (OpenKJ method) with MP3 fallback")
        logging.info("=" * 80)
        
        def probe_single_track(t):
            """Probe duration for a single track (runs in parallel)."""
            dur = None
            p = t.get("path", "")
            method_used = None

            try:
                if t.get("type") == "mp4":
                    if MutagenFile:
                        try:
                            mf = MutagenFile(p)
                            if mf and mf.info and getattr(mf.info, "length", None):
                                dur = int(mf.info.length)
                                method_used = 'mp4'
                        except Exception:
                            pass
                elif t.get("type") == "mp3g":
                    # header-only ZIP probe (no extraction)
                    try:
                        dur = self.app.probe_mp3g_duration(p)
                        if dur:
                            # Check if it used CDG method or MP3 method
                            # (we can infer this from the speed, but for now just mark as processed)
                            method_used = 'zip'  # Could be either CDG or MP3 method
                    except Exception:
                        dur = None
                elif t.get("type") == "cdg":
                    # Handle unzipped CDG+MP3 pairs
                    # Fast method: Calculate duration from CDG file size (same as ZIP method)
                    try:
                        cdg_size = os.path.getsize(p)
                        if cdg_size > 0:
                            # CDG format: 96 bytes per frame, 75 frames per second
                            dur = int((cdg_size / 96) / 75)
                            method_used = 'cdg_pair'
                    except Exception:
                        # Fallback: try reading MP3 file with Mutagen
                        try:
                            base, _ = os.path.splitext(p)
                            mp3_path = base + ".mp3"
                            if os.path.exists(mp3_path) and MutagenFile:
                                mf = MutagenFile(mp3_path)
                                if mf and mf.info and getattr(mf.info, "length", None):
                                    dur = int(mf.info.length)
                                    method_used = 'cdg_pair'
                        except Exception:
                            dur = None
            except Exception as e:
                print(f"Duration probe failed for {p}: {e}")

            # Update statistics
            with stats_lock:
                if method_used == 'mp4':
                    stats['mp4_method'] += 1
                elif method_used == 'zip':
                    # Assume most zips use CDG method (we could track this more precisely)
                    stats['cdg_method'] += 1
                elif method_used == 'cdg_pair':
                    stats['cdg_pairs'] += 1
                elif dur is None:
                    stats['failed'] += 1

            if dur and dur > 0:
                t["duration"] = int(dur)
                t.pop("dur_unavailable", None)
                with stats_lock:
                    stats['resolved'] += 1
            elif p and os.path.exists(p):
                # File is present but its duration can't be determined on this
                # build (e.g. an mp4 when mutagen isn't bundled). Flag it so it
                # stops being re-probed and re-triggering a full index rebuild on
                # every launch. Files that are simply offline (path missing) are
                # left unflagged so they retry once the drive returns.
                t["dur_unavailable"] = True

            return 1  # Return 1 to count as completed

        # Use ThreadPoolExecutor with 12 workers for parallel processing
        with ThreadPoolExecutor(max_workers=max_workers) as executor:
            # Submit all tracks to the worker pool
            futures = {executor.submit(probe_single_track, t): t for t in tracks}
            
            last_log_time = time.time()
            last_done = 0
            
            # Process results as they complete
            for future in as_completed(futures):
                try:
                    future.result()  # Get result (or raise exception if failed)
                except Exception as e:
                    t = futures[future]
                    print(f"Worker exception for {t.get('path', 'unknown')}: {e}")
                
                # Update progress (thread-safe)
                with progress_lock:
                    done += 1
                    if (done % 10) == 0 or done == total:
                        self.progress.emit(done, total)
                    
                    # Log detailed stats every 1000 files or 30 seconds
                    current_time = time.time()
                    if (done % 1000 == 0) or (current_time - last_log_time >= 30) or done == total:
                        elapsed = current_time - stats['start_time']
                        files_since_last = done - last_done
                        time_since_last = current_time - last_log_time
                        
                        if time_since_last > 0:
                            current_rate = files_since_last / time_since_last
                            overall_rate = done / elapsed if elapsed > 0 else 0
                            eta_seconds = (total - done) / overall_rate if overall_rate > 0 else 0
                            
                            logging.info(f"Duration Scan Progress: {done:,}/{total:,} ({done/total*100:.1f}%)")
                            logging.info(f"  Current rate: {current_rate:.1f} files/sec")
                            logging.info(f"  Overall rate: {overall_rate:.1f} files/sec")
                            logging.info(f"  Elapsed: {elapsed/60:.1f} min")
                            logging.info(f"  ETA: {eta_seconds/60:.1f} min")
                            
                            with stats_lock:
                                logging.info(f"  Methods: CDG={stats['cdg_method']:,} MP4={stats['mp4_method']:,} CDG-pairs={stats['cdg_pairs']:,} Failed={stats['failed']:,}")
                        
                        last_log_time = current_time
                        last_done = done

        # Expose how many durations were newly resolved so the caller can decide
        # whether an index rebuild is actually needed.
        with stats_lock:
            self.resolved_count = int(stats['resolved'])

        # Final statistics
        elapsed = time.time() - stats['start_time']
        overall_rate = done / elapsed if elapsed > 0 else 0
        _perf_log_if_slow("duration_scan_batch", elapsed * 1000.0)

        logging.info("=" * 80)
        logging.info("DURATION SCAN COMPLETE")
        logging.info(f"Total processed: {done:,}/{total:,}")
        logging.info(f"Total time: {elapsed/60:.1f} minutes ({elapsed:.1f} seconds)")
        logging.info(f"Average rate: {overall_rate:.1f} files/second")
        with stats_lock:
            logging.info(f"Methods used:")
            logging.info(f"  - CDG size calc (fast): {stats['cdg_method']:,} files")
            logging.info(f"  - MP4 files: {stats['mp4_method']:,} files")
            logging.info(f"  - CDG+MP3 pairs: {stats['cdg_pairs']:,} files")
            logging.info(f"  - Failed: {stats['failed']:,} files")
        logging.info("=" * 80)

        self.finished.emit()

def _display_for_track(t: dict) -> str:
    import os
    title = (t.get("title") or os.path.splitext(os.path.basename(t.get("path", "")))[0]).strip()
    artist = (t.get("artist") or "").strip()
    disc_id = (t.get("disc_id") or "").strip()

    base = f"{artist} - {title}" if artist else title
    if disc_id:
        base = f"{base} - {disc_id}"
    return base


# ============================================================================
# Filename → (artist, title, disc_id) parsing.
#
# Lots of karaoke libraries are organised with the brand/disc code in
# different positions of the filename:
#
#   "KV - Linkin Park - In The End.cdg"        (disc-artist-title)
#   "Linkin Park - In The End - KV.cdg"        (artist-title-disc)
#   "KV - In The End - Linkin Park.cdg"        (disc-title-artist)
#   "In The End - Linkin Park - KV.cdg"        (title-artist-disc)
#
# The chosen format is persisted in self.settings["filename_format"] and
# controls how scan_folder interprets every track.  Changing the format in
# Settings triggers a one-shot re-parse of all existing rows without a
# disk re-scan.
#
# When a file has more separators than the format expects, the extra parts
# join into the field that's most natural for that layout (usually the
# 'title' position, except for 'disc-title-artist' where the artist is at
# the end and thus expands).
# ============================================================================

FILENAME_FORMATS: dict[str, str] = {
    "disc-artist-title": "Disc - Artist - Title  (e.g. KV - Linkin Park - In The End)",
    "artist-title-disc": "Artist - Title - Disc  (e.g. Linkin Park - In The End - KV)",
    "disc-title-artist": "Disc - Title - Artist  (e.g. KV - In The End - Linkin Park)",
    "title-artist-disc": "Title - Artist - Disc  (e.g. In The End - Linkin Park - KV)",
    "artist-title":      "Artist - Title  (no disc field)",
    "title-artist":      "Title - Artist  (no disc field)",
}

DEFAULT_FILENAME_FORMAT = "disc-artist-title"


def parse_filename_stem(stem: str, fmt: str = DEFAULT_FILENAME_FORMAT) -> tuple[str, str, str]:
    """Parse a filename stem (no extension) into (artist, title, disc_id).

    See ``FILENAME_FORMATS`` for the supported format keys.  Separator is
    always ``" - "``.  Falls back gracefully for filenames with fewer
    separators than the format expects.
    """
    stem = (stem or "").strip()
    if not stem:
        return "", "", ""
    parts = [p.strip() for p in stem.split(" - ")]
    n = len(parts)

    # 2-field formats
    if fmt == "artist-title":
        if n >= 2:
            return parts[0], " - ".join(parts[1:]), ""
        return "", stem, ""
    if fmt == "title-artist":
        if n >= 2:
            return " - ".join(parts[1:]), parts[0], ""
        return "", stem, ""

    # 3-field formats with too few separators — keep what we can.
    if n < 3:
        if n == 2:
            if fmt == "title-artist-disc":
                return parts[1], parts[0], ""
            if fmt == "disc-artist-title":
                return parts[1], "", parts[0]
            if fmt == "disc-title-artist":
                return "", parts[1], parts[0]
            # artist-title-disc (or unknown) → assume disc dropped
            return parts[0], parts[1], ""
        return "", stem, ""

    # 3+ parts: extras absorbed by the semantically-middle field
    if fmt == "artist-title-disc":
        # extras → title
        return parts[0], " - ".join(parts[1:-1]), parts[-1]
    if fmt == "disc-artist-title":
        # extras → title (last positions)
        return parts[1], " - ".join(parts[2:]), parts[0]
    if fmt == "disc-title-artist":
        # extras → artist (last positions)
        return " - ".join(parts[2:]), parts[1], parts[0]
    if fmt == "title-artist-disc":
        # extras → title (first positions)
        return parts[-2], " - ".join(parts[:-2]), parts[-1]

    # Unknown / unrecognised format — best-effort default.
    return parts[0], " - ".join(parts[1:-1]) if n > 2 else (parts[1] if n > 1 else ""), parts[-1] if n > 2 else ""

# VLC code removed - now using GStreamer exclusively

class VideoWindow(QWidget):

    def style_buttons_to_match_queue(self):
        """Style only QPushButtons so they match the queue's empty background area (palette Base).
        This intentionally avoids touching table/list widgets so your results/queue keep their clean system look.
        """
        try:
            base_color = QColor(BASE_COLOR)
        except Exception:
            return

        # Subtle deltas for hover/pressed; keep it very close to the queue background.
        try:
            border_color = base_color.lighter(115)
            hover_color = base_color.lighter(110)
            pressed_color = base_color.darker(110)
        except Exception:
            border_color = base_color
            hover_color = base_color
            pressed_color = base_color

        button_style = f"""
            QPushButton {{
                background-color: {base_color.name()};
                border: 1px solid {border_color.name()};
                border-radius: 6px;
                padding: 6px 12px;
            }}
            QPushButton:hover {{
                background-color: {hover_color.name()};
            }}
            QPushButton:pressed {{
                background-color: {pressed_color.name()};
            }}
        """

        try:
            for btn in self.findChildren(QPushButton):
                # Don't override buttons that already have a custom style (e.g., icon tiles)
                try:
                    if btn.styleSheet().strip():
                        continue
                except Exception:
                    pass
                btn.setStyleSheet(button_style)
        except Exception:
            pass

    def __init__(self, title='Karaoke Video Output', width=640, height=480,
                 get_singer_list_callback=None, get_time_left_callback=None):
        super().__init__()
        self.setWindowTitle(title)
        self.resize(width, height + 40)
        self.setStyleSheet("background-color: black;")
        self.force_black = True
        self.idle = True
        self.background_pixmap = QPixmap()

        # Set layout
        layout = QVBoxLayout(self)
        layout.setContentsMargins(0, 0, 0, 24)
        layout.setSpacing(0)
        self._main_layout = layout

        # Video area
        self.video_area = VideoAreaWidget(self)
        self.video_area.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Expanding)
        layout.addWidget(self.video_area)

        # Native pre-rendered ticker at the bottom: time-based pixel-perfect
        # scrolling (no QML / QPropertyAnimation).
        self.ticker = Ticker(
            get_singer_list_callback,
            self,
            get_time_left_callback=get_time_left_callback
        )
        layout.addWidget(self.ticker)
        # Keep video area dominant and ticker fixed at bottom.
        layout.setStretch(0, 1)
        layout.setStretch(1, 0)

        _diag(
            f"[TICKER] init title={title} winId={int(self.video_area.winId())} backend=native"
        )

        # Keep idle BG overlay repainting even when this window is not focused.
        self._idle_overlay_visible_last = False
        self._idle_overlay_last_state = None
        self._idle_overlay_last_diag_ts = 0.0
        self._resize_diag_last_ts = 0.0
        self._idle_overlay_timer = QTimer(self)
        self._idle_overlay_timer.timeout.connect(self._tick_idle_overlay)
        self._idle_overlay_timer.start(50)

    def _tick_idle_overlay(self):
        """Periodic repaint so idle BG overlay updates without requiring window focus."""
        _perf_t0 = time.perf_counter()
        try:
            owner = getattr(self, "_external_owner", None)
            if owner is None:
                owner = self.parent()
            bg = getattr(owner, "bg_music", None) if owner is not None else None

            should_draw = bool(getattr(self, "idle", False)) and bool(bg) and bool(getattr(bg, "is_playing", False))
            perf_mode = bool(
                owner is not None
                and hasattr(owner, "_performance_mode")
                and owner._performance_mode()
            )
            safe_mode = bool(
                owner is not None
                and hasattr(owner, "_safe_mode")
                and owner._safe_mode()
            )
            try:
                target_interval = 500 if safe_mode else (120 if perf_mode else 50)
                if self._idle_overlay_timer.interval() != target_interval:
                    self._idle_overlay_timer.start(target_interval)
            except Exception:
                pass
            if safe_mode:
                should_draw = False
            try:
                level = 0.0 if safe_mode else (float(getattr(bg, "_meter_level", 0.0)) if bg is not None else 0.0)
            except Exception:
                level = 0.0

            # Log only on meaningful state changes (or an occasional heartbeat while drawing).
            try:
                bg_playing = bool(getattr(bg, "is_playing", False)) if bg is not None else False
                state = (bool(getattr(self, "idle", False)), bool(bg is not None), bg_playing, bool(should_draw))
                now = time.monotonic()
                if state != self._idle_overlay_last_state:
                    _diag(f"[IDLE-OVERLAY] state changed idle={state[0]} bg_exists={state[1]} bg_playing={state[2]} should_draw={state[3]} meter={level:.3f}")
                    self._idle_overlay_last_state = state
                    self._idle_overlay_last_diag_ts = now
            except Exception:
                pass
            try:
                self.video_area.set_audio_level(level)
                self.video_area.advance_visualizer(should_draw)
            except Exception:
                pass
            if should_draw or self._idle_overlay_visible_last:
                try:
                    self.video_area.repaint()
                except Exception:
                    self.video_area.update()
            self._idle_overlay_visible_last = should_draw
        except Exception:
            pass
        finally:
            _perf_log_if_slow("ui_tick_idle_overlay", (time.perf_counter() - _perf_t0) * 1000.0)

    def resizeEvent(self, event):
        super().resizeEvent(event)
        try:
            now = time.monotonic()
            if (now - float(getattr(self, "_resize_diag_last_ts", 0.0))) >= 1.0:
                g = self.geometry()
                _diag(
                    f"[VIDWIN] resize x={g.x()} y={g.y()} w={g.width()} h={g.height()} "
                    f"fullscreen={self.isFullScreen()} maximized={self.isMaximized()} idle={bool(getattr(self, 'idle', False))}"
                )
                self._resize_diag_last_ts = now
        except Exception:
            pass

    def mouseDoubleClickEvent(self, event):
        """Toggle fullscreen on double-click"""
        if self.isFullScreen():
            self.showNormal()
        else:
            self.showFullScreen()
        super().mouseDoubleClickEvent(event)

    def winId(self):
        return self.video_area.winId()

    def recreate_video_surface(self, reason: str = ""):
        """Recreate native video surface widget so stale overlays cannot persist."""
        try:
            old = getattr(self, "video_area", None)
            if old is None:
                return
            old_id = int(old.winId())
            old_size = old.size()
            old_policy = old.sizePolicy()

            new_area = VideoAreaWidget(self)
            new_area.setSizePolicy(old_policy)
            try:
                new_area.setAttribute(Qt.WidgetAttribute.WA_NoSystemBackground, True)
                new_area.setAttribute(Qt.WidgetAttribute.WA_OpaquePaintEvent, True)
            except Exception:
                pass

            try:
                if hasattr(old, "background_pixmap") and not old.background_pixmap.isNull():
                    new_area.background_pixmap = QPixmap(old.background_pixmap)
            except Exception:
                pass

            # Replace in-place to avoid transient layout collapse/jumps.
            self._main_layout.replaceWidget(old, new_area)
            old.setParent(None)
            old.deleteLater()
            self.video_area = new_area
            if old_size.width() > 0 and old_size.height() > 0:
                new_area.resize(old_size)

            try:
                _diag(f"[VIDSURFACE] recreated reason={reason} old={old_id} new={int(new_area.winId())}")
            except Exception:
                pass
        except Exception:
            pass

    def set_background_image(self, image_path):
        self.video_area.set_background_image(image_path)

    def set_ticker_enabled(self, enabled: bool):
        """Show/hide the ticker and collapse its space."""
        if not hasattr(self, "ticker"):
            return
        if enabled:
            self.ticker.setVisible(True)
            try:
                owner = None
                if hasattr(self.ticker, "_settings_owner"):
                    owner = self.ticker._settings_owner()
                if owner is None and hasattr(self, "parent"):
                    owner = self.parent()
                if owner and hasattr(owner, "settings"):
                    idx = int(owner.settings.get("ticker_size_index", TICKER_SIZE_DEFAULT_INDEX))
                    idx = max(0, min(len(TICKER_SIZE_PRESETS) - 1, idx))
                    self.ticker.set_size_preset(idx)
                elif hasattr(self.ticker, "_size_idx"):
                    idx = int(getattr(self.ticker, "_size_idx", TICKER_SIZE_DEFAULT_INDEX))
                    idx = max(0, min(len(TICKER_SIZE_PRESETS) - 1, idx))
                    self.ticker.set_size_preset(idx)
                # If no size source is available, keep current live size (do not reset to default).
            except Exception:
                pass
            # Optional: keep your bottom margin
            self.layout().setContentsMargins(0, 0, 0, 24)
            # (re)start ticker motion/update loops
            if hasattr(self.ticker, "start_scrolling"):
                self.ticker.start_scrolling()
            elif hasattr(self.ticker, "scroll_timer"):
                interval = int(getattr(self.ticker, "_frame_interval_ms", 16) or 16)
                self.ticker.scroll_timer.start(max(6, interval))
            if hasattr(self.ticker, "queue_update_timer"): self.ticker.queue_update_timer.start(5000)
            if hasattr(self.ticker, "right_update_timer"):
                right_interval = 1000 if (owner and hasattr(owner, "_performance_mode") and owner._performance_mode()) else 300
                self.ticker.right_update_timer.start(right_interval)
        else:
            # stop timers to save CPU while hidden
            if hasattr(self.ticker, "stop_scrolling"):
                self.ticker.stop_scrolling()
            elif hasattr(self.ticker, "scroll_timer"):
                self.ticker.scroll_timer.stop()
            if hasattr(self.ticker, "queue_update_timer"): self.ticker.queue_update_timer.stop()
            if hasattr(self.ticker, "right_update_timer"): self.ticker.right_update_timer.stop()
            self.ticker.setVisible(False)
            self.ticker.setFixedHeight(0)    # collapse height so no space is taken
            self.layout().setContentsMargins(0, 0, 0, 0)
        
class AddToQueueDialog(QDialog):
    def __init__(self, parent=None, default_singer="", default_key=0):
        super().__init__(parent)
        self.setWindowTitle("Add to Queue")
        self.setModal(True)

        self.name_edit = QLineEdit(self)
        self.name_edit.setPlaceholderText("Singer name")
        self.name_edit.setText(default_singer)

        self.key_combo = QComboBox(self)
        self.key_combo.addItems(
            ["Key: +4", "Key: +3", "Key: +2", "Key: +1", "Key: 0", "Key: -1", "Key: -2", "Key: -3", "Key: -4"]
        )
        # map default_key (-4..+4) to index (0..8), where 0=+4, 4=0, 8=-4
        idx_map = {+4:0, +3:1, +2:2, +1:3, 0:4, -1:5, -2:6, -3:7, -4:8}
        self.key_combo.setCurrentIndex(idx_map.get(int(default_key), 4))


        # --- Dialog styling (match main UI) ---
        try:
            p = parent
            if p is not None and hasattr(p, "queue_display"):
                base = p.queue_display.palette().color(QPalette.ColorRole.Base)
                win  = p.palette().color(QPalette.ColorRole.Window)
                txtc = p.palette().color(QPalette.ColorRole.Text)
            else:
                base = self.palette().color(QPalette.ColorRole.Base)
                win  = self.palette().color(QPalette.ColorRole.Window)
                txtc = self.palette().color(QPalette.ColorRole.Text)
            self.setStyleSheet(
                dialog_stylesheet(win, base, txtc)
                + """
                QPushButton#spinStepBtn {
                    min-width: 0px;
                    padding: 0px;
                    font-size: 12px;
                    font-weight: 700;
                    border-radius: 4px;
                }
                """
            )
        except Exception:
            pass

        # Remove macOS blue focus ring (visual only)
        try:
            self.name_edit.setAttribute(Qt.WidgetAttribute.WA_MacShowFocusRect, False)
            self.key_combo.setAttribute(Qt.WidgetAttribute.WA_MacShowFocusRect, False)
        except Exception:
            pass

        layout = QVBoxLayout(self)

        row1 = QHBoxLayout()
        row1.addWidget(QLabel("Singer:", self))
        row1.addWidget(self.name_edit)
        layout.addLayout(row1)

        row2 = QHBoxLayout()
        row2.addWidget(QLabel("Key:", self))
        row2.addWidget(self.key_combo)
        layout.addLayout(row2)

        btns = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel, self)

        # Make OK the default (Enter)
        try:
            ok_btn = btns.button(QDialogButtonBox.StandardButton.Ok)
            if ok_btn is not None:
                ok_btn.setDefault(True)
                ok_btn.setAutoDefault(True)
        except Exception:
            pass
        btns.accepted.connect(self.accept)
        btns.rejected.connect(self.reject)
        layout.addWidget(btns)

    def values(self):
        name = self.name_edit.text().strip()
        key_txt = self.key_combo.currentText().replace("Key:", "").replace("+", "").strip()
        try:
            key = int(key_txt)
        except Exception:
            key = 0
        return name, key

class ConfirmInterruptDialog(QDialog):
    def __init__(
        self,
        parent=None,
        *,
        title="Interrupt Playback?",
        message=None,
        confirm_text="Yes",
        cancel_text="No",
    ):
        super().__init__(parent)
        self.setWindowTitle(title)
        self.setModal(True)
        self.setMinimumWidth(620)

        if message is None:
            message = (
                "A track is currently playing.\n"
                "Are you sure you want to play the next song and interrupt the current singer?"
            )

        try:
            if parent is not None and hasattr(parent, "queue_display"):
                base = parent.queue_display.palette().color(QPalette.ColorRole.Base)
                win = parent.palette().color(QPalette.ColorRole.Window)
                txtc = parent.palette().color(QPalette.ColorRole.Text)
            else:
                base = self.palette().color(QPalette.ColorRole.Base)
                win = self.palette().color(QPalette.ColorRole.Window)
                txtc = self.palette().color(QPalette.ColorRole.Text)
            self.setStyleSheet(dialog_stylesheet(win, base, txtc))
        except Exception:
            pass

        layout = QVBoxLayout(self)
        layout.setContentsMargins(20, 18, 20, 18)
        layout.setSpacing(14)

        label = QLabel(message)
        label.setWordWrap(True)
        layout.addWidget(label)

        buttons = QHBoxLayout()
        buttons.addStretch()

        no_btn = QPushButton(cancel_text)
        yes_btn = QPushButton(confirm_text)

        no_btn.clicked.connect(self.reject)
        yes_btn.clicked.connect(self.accept)

        buttons.addWidget(no_btn)
        buttons.addWidget(yes_btn)

        layout.addLayout(buttons)

class PreviewVideoAreaWidget(QWidget):
    """Native preview surface widget that can be replaced to evict stale GL overlays."""
    def __init__(self, owner):
        super().__init__(owner)
        self._owner = owner
        self.karaoke_frame = QImage()
        self.karaoke_stretch_fill = False
        self.cdg_quality_mode = "standard"
        self._karaoke_scaled_pixmap = QPixmap()
        self._karaoke_scaled_key = None
        self._karaoke_scaled_pos = QPoint(0, 0)
        self._karaoke_frame_count = 0
        self._karaoke_scale_time_ms = 0.0
        self.setAttribute(Qt.WidgetAttribute.WA_NativeWindow, True)
        self.setAttribute(Qt.WidgetAttribute.WA_DontCreateNativeAncestors, True)
        try:
            self.setAttribute(Qt.WidgetAttribute.WA_NoSystemBackground, True)
            self.setAttribute(Qt.WidgetAttribute.WA_OpaquePaintEvent, True)
        except Exception:
            pass

    def set_cdg_quality_mode(self, mode: str):
        mode = "high" if str(mode or "").lower() == "high" else "standard"
        if mode == self.cdg_quality_mode:
            return
        self.cdg_quality_mode = mode
        self._karaoke_scaled_key = None
        self.update()

    def set_karaoke_frame(self, image, stretch_fill: bool = False):
        self.karaoke_frame = image if image is not None and not image.isNull() else QImage()
        self.karaoke_stretch_fill = bool(stretch_fill)
        self._ensure_karaoke_scaled_pixmap()
        self.update()

    def clear_karaoke_frame(self):
        self.karaoke_frame = QImage()
        self._karaoke_scaled_pixmap = QPixmap()
        self._karaoke_scaled_key = None
        self.update()

    def resizeEvent(self, event):
        super().resizeEvent(event)
        self._karaoke_scaled_key = None
        if not self.karaoke_frame.isNull():
            self._ensure_karaoke_scaled_pixmap()

    def _ensure_karaoke_scaled_pixmap(self):
        if self.karaoke_frame.isNull() or self.width() <= 0 or self.height() <= 0:
            self._karaoke_scaled_pixmap = QPixmap()
            self._karaoke_scaled_key = None
            return
        try:
            image_key = int(self.karaoke_frame.cacheKey())
        except Exception:
            image_key = id(self.karaoke_frame)
        key = (
            image_key,
            int(self.width()),
            int(self.height()),
            bool(self.karaoke_stretch_fill),
            str(self.cdg_quality_mode),
        )
        if key == self._karaoke_scaled_key and not self._karaoke_scaled_pixmap.isNull():
            return
        mode = (
            Qt.AspectRatioMode.IgnoreAspectRatio
            if bool(self.karaoke_stretch_fill)
            else Qt.AspectRatioMode.KeepAspectRatio
        )
        transform = (
            Qt.TransformationMode.SmoothTransformation
            if self.cdg_quality_mode == "high"
            else Qt.TransformationMode.FastTransformation
        )
        t0 = time.perf_counter()
        scaled = self.karaoke_frame.scaled(self.size(), mode, transform)
        self._karaoke_scaled_pixmap = QPixmap.fromImage(scaled)
        self._karaoke_scaled_pos = QPoint(
            (self.width() - self._karaoke_scaled_pixmap.width()) // 2,
            (self.height() - self._karaoke_scaled_pixmap.height()) // 2,
        )
        self._karaoke_scaled_key = key
        self._karaoke_frame_count += 1
        self._karaoke_scale_time_ms += (time.perf_counter() - t0) * 1000.0
        if self._karaoke_frame_count % 300 == 0:
            try:
                avg = self._karaoke_scale_time_ms / max(1, self._karaoke_frame_count)
                _perf_log_if_slow("cdg_frame_render", avg)
            except Exception:
                pass

    def paintEvent(self, event):
        try:
            painter = QPainter(self)
            painter.fillRect(self.rect(), QColor('black'))
            if not bool(getattr(self._owner, 'force_black', True)) and not self.karaoke_frame.isNull():
                self._ensure_karaoke_scaled_pixmap()
                if self.cdg_quality_mode == "high":
                    painter.setRenderHint(QPainter.RenderHint.SmoothPixmapTransform, True)
                if not self._karaoke_scaled_pixmap.isNull():
                    painter.drawPixmap(self._karaoke_scaled_pos, self._karaoke_scaled_pixmap)
            painter.end()
        except Exception:
            pass
        super().paintEvent(event)


