class PerformanceWaveformWidget(QWidget):
    """Smooth decorative waveform for the operator performance deck.

    Animation runs from an internal 30 fps QTimer (while active), so the
    wave phase advances by small float increments per frame instead of
    integer jumps.  Progress (the "filled" portion of the bar) is held as
    a target value and eased toward each frame, so updates that arrive
    every 500 ms still appear as smooth continuous motion.
    """

    def __init__(self, parent=None):
        super().__init__(parent)
        self._progress = 0.0          # currently rendered
        self._progress_target = 0.0   # last value pushed via set_progress
        self._active = False
        self._phase = 0.0
        self.setMinimumHeight(34)
        self.setMaximumHeight(42)
        self.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Fixed)
        # Internal animation tick.  Runs only while active so an idle deck
        # costs zero CPU.
        self._anim_timer = QTimer(self)
        self._anim_timer.setInterval(33)  # ~30 fps; smooth without burning CPU
        self._anim_timer.timeout.connect(self._on_anim_tick)

    def set_progress(self, value: float):
        try:
            self._progress_target = max(0.0, min(1.0, float(value)))
            if not self._anim_timer.isActive():
                # If we're not animating, still snap once so the static
                # value matches the requested target.
                self._progress = self._progress_target
                self.update()
        except Exception:
            pass

    def set_active(self, active: bool):
        active = bool(active)
        if self._active == active:
            return
        self._active = active
        if active:
            if not self._anim_timer.isActive():
                self._anim_timer.start()
        else:
            # Snap to target and stop animating to release the CPU.
            self._progress = self._progress_target
            if self._anim_timer.isActive():
                self._anim_timer.stop()
            self.update()

    def tick(self):
        # External tick is now a no-op (kept for backward compatibility);
        # the internal QTimer drives all motion.
        pass

    def _on_anim_tick(self):
        # Smoothly advance the wave phase (float — produces continuous
        # motion instead of integer steps).
        self._phase = (self._phase + 0.35) % 1024.0
        # Ease the rendered progress toward the most-recent target.  The
        # 0.20 factor gives ~5-frame catch-up (~165 ms) — fast enough to
        # not feel laggy, slow enough to smooth out the 500 ms step from
        # the seek slider.
        diff = self._progress_target - self._progress
        if abs(diff) > 1e-4:
            self._progress += diff * 0.20
        elif self._progress != self._progress_target:
            self._progress = self._progress_target
        self.update()

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)
        rect = self.rect().adjusted(0, 2, 0, -2)
        painter.setPen(Qt.PenStyle.NoPen)
        painter.setBrush(QColor(5, 8, 15, 205))
        painter.drawRoundedRect(rect, 8, 8)

        inner = rect.adjusted(12, 6, -12, -6)
        if inner.width() <= 0 or inner.height() <= 0:
            painter.end()
            return

        center_y = inner.center().y()
        bar_count = max(18, min(42, inner.width() // 8))
        gap = 3
        bar_w = max(2, int((inner.width() - ((bar_count - 1) * gap)) / max(1, bar_count)))
        active_w = int(inner.width() * self._progress)
        phase = float(self._phase)

        for i in range(bar_count):
            x = inner.left() + i * (bar_w + gap)
            wave = (math.sin((i + phase) * 0.72) + 1.0) * 0.5
            alt = (math.sin(i * 1.53) + 1.0) * 0.5
            h_ratio = 0.22 + (wave * 0.46) + (alt * 0.16)
            h = max(5, int(inner.height() * min(0.88, h_ratio)))
            y = center_y - (h // 2)
            is_played = (x - inner.left()) <= active_w
            if is_played:
                color = QColor(167, 139, 250, 215 if self._active else 150)
            else:
                color = QColor(128, 134, 154, 74)
            painter.setBrush(color)
            painter.drawRoundedRect(QRect(x, y, bar_w, h), max(1, bar_w // 2), max(1, bar_w // 2))

        painter.setPen(QPen(QColor(255, 255, 255, 28), 1))
        painter.drawRoundedRect(rect.adjusted(0, 0, -1, -1), 8, 8)
        painter.end()

    def recreate_video_surface(self, reason: str = ''):
        """Replace preview native child surface so stale compositor layers cannot persist."""
        try:
            old = getattr(self, 'video_area', None)
            if old is None:
                return
            old_id = int(old.winId())
            old_size = old.size()
            old_policy = old.sizePolicy()

            new_area = PreviewVideoAreaWidget(self)
            new_area.setSizePolicy(old_policy)

            self._main_layout.replaceWidget(old, new_area)
            old.setParent(None)
            old.deleteLater()
            self.video_area = new_area
            if old_size.width() > 0 and old_size.height() > 0:
                new_area.resize(old_size)

            new_area.update()
            _diag(
                f"[PREVIEW] surface refresh reason={reason} old={old_id} "
                f"new={int(new_area.winId())} changed={bool(int(new_area.winId()) != old_id)}"
            )
        except Exception:
            pass

