class ZipCache:
    """Manages temporary extraction and caching of zipped MP3G files"""
    
    def __init__(self, max_cache_size=5):
        self.cache = {}  # zip_path -> {cdg_temp_path, mp3_temp_path, last_used}
        self.max_cache_size = max_cache_size
        self.temp_dir = tempfile.mkdtemp(prefix="singws_mp3g_")
        self.lock = threading.Lock()
        
    def get_extracted_paths(self, zip_path):
        """Get CDG and MP3 paths from zip, extracting if needed"""
        with self.lock:
            if zip_path in self.cache:
                entry = self.cache[zip_path]
                entry['last_used'] = datetime.now()
                return entry['cdg_path'], entry['mp3_path']

            try:
                app = QApplication.instance()
                if app is not None and QThread.currentThread() == app.thread():
                    print("[PERF] main_thread_blocking_call risk task=zip_extract caller=get_extracted_paths")
            except Exception:
                pass
            
            # Extract new zip
            try:
                cdg_path, mp3_path = self._extract_zip(zip_path)
                
                # Manage cache size
                if len(self.cache) >= self.max_cache_size:
                    self._evict_oldest()
                
                self.cache[zip_path] = {
                    'cdg_path': cdg_path,
                    'mp3_path': mp3_path,
                    'last_used': datetime.now()
                }
                
                return cdg_path, mp3_path
                
            except Exception as e:
                print(f"Failed to extract {zip_path}: {e}")
                return None, None

    def cached_paths_if_ready(self, zip_path):
        """Return already-extracted paths without doing any disk/process work."""
        with self.lock:
            entry = self.cache.get(zip_path)
            if not entry:
                return None, None
            entry['last_used'] = datetime.now()
            return entry.get('cdg_path'), entry.get('mp3_path')
    
    def _extract_zip(self, zip_path):
        """Extract CDG and MP3 from zip file"""
        import uuid

        cdg_path = None
        mp3_path = None

        # First try Python zipfile path (fast, no external process).
        try:
            try:
                zf = zipfile.ZipFile(zip_path, 'r')
            except UnicodeDecodeError:
                # Some archives have bad UTF-8 metadata flags; force legacy decoding.
                zf = zipfile.ZipFile(zip_path, 'r', metadata_encoding='cp437')

            with zf:
                entries = [zi for zi in zf.infolist() if not zi.is_dir()]
                cdg_entries = [zi for zi in entries if zi.filename.lower().endswith('.cdg')]
                mp3_entries = [zi for zi in entries if zi.filename.lower().endswith('.mp3')]

                if len(cdg_entries) != 1 or len(mp3_entries) != 1:
                    raise ValueError("Zip must contain exactly one CDG and one MP3 file")

                token = uuid.uuid4().hex
                cdg_info = cdg_entries[0]
                mp3_info = mp3_entries[0]

                cdg_path = os.path.join(self.temp_dir, f"{token}_extracted.cdg")
                with open(cdg_path, 'wb') as f:
                    f.write(zf.read(cdg_info))

                mp3_path = os.path.join(self.temp_dir, f"{token}_extracted.mp3")
                with open(mp3_path, 'wb') as f:
                    f.write(zf.read(mp3_info))
        except Exception as py_err:
            # Fallback: system unzip handles many odd ZIP metadata edge cases.
            try:
                token = uuid.uuid4().hex
                tmpdir = os.path.join(self.temp_dir, f"{token}_unz")
                os.makedirs(tmpdir, exist_ok=True)
                proc = subprocess.run(
                    ["unzip", "-qq", "-o", zip_path, "-d", tmpdir],
                    capture_output=True,
                    text=True,
                    check=False,
                )
                if proc.returncode != 0:
                    raise RuntimeError((proc.stderr or proc.stdout or "unzip failed").strip())

                cdg_found, mp3_found = find_mp3g_in_dir(tmpdir)
                if not cdg_found or not mp3_found:
                    raise ValueError("Zip must contain one CDG and one MP3 pair")

                cdg_path = os.path.join(self.temp_dir, f"{token}_extracted.cdg")
                mp3_path = os.path.join(self.temp_dir, f"{token}_extracted.mp3")
                shutil.copyfile(cdg_found, cdg_path)
                shutil.copyfile(mp3_found, mp3_path)
                shutil.rmtree(tmpdir, ignore_errors=True)
                print(f"[ZIP] unzip fallback used for {os.path.basename(zip_path)} (python error: {py_err})")
            except Exception:
                try:
                    if 'tmpdir' in locals() and tmpdir:
                        shutil.rmtree(tmpdir, ignore_errors=True)
                except Exception:
                    pass
                raise

        if not cdg_path or not mp3_path:
            # Clean up partial extraction
            for path in [cdg_path, mp3_path]:
                if path and os.path.exists(path):
                    try:
                        os.remove(path)
                    except:
                        pass
            raise ValueError("Zip must contain exactly one CDG and one MP3 file")

        return cdg_path, mp3_path
    
    def _evict_oldest(self):
        """Remove oldest cache entry"""
        if not self.cache:
            return
            
        oldest_key = min(self.cache.keys(), 
                        key=lambda k: self.cache[k]['last_used'])
        
        entry = self.cache.pop(oldest_key)
        # Clean up temp files
        for path in [entry['cdg_path'], entry['mp3_path']]:
            try:
                if os.path.exists(path):
                    os.remove(path)
            except:
                pass
    
    def clear_cache(self):
        """Clear all cached files"""
        with self.lock:
            for entry in self.cache.values():
                for path in [entry['cdg_path'], entry['mp3_path']]:
                    try:
                        if os.path.exists(path):
                            os.remove(path)
                    except:
                        pass
            self.cache.clear()
    
    def cleanup(self):
        """Clean up all temp files and directory"""
        self.clear_cache()
        try:
            import shutil
            shutil.rmtree(self.temp_dir, ignore_errors=True)
        except:
            pass


class ZipExtractWorker(QObject):
    progress_text = pyqtSignal(str)
    finished = pyqtSignal(str, str, str, int, bool, str)  # zip_path, cdg, mp3, semitones, ok, message

    def __init__(self, zip_cache, zip_path: str, semitones: int):
        super().__init__()
        self.zip_cache = zip_cache
        self.zip_path = str(zip_path or "")
        self.semitones = int(semitones or 0)
        self._cancelled = False

    def cancel(self):
        self._cancelled = True

    def run(self):
        started = time.perf_counter()
        try:
            if self._cancelled:
                self.finished.emit(self.zip_path, "", "", self.semitones, False, "cancelled")
                return
            self.progress_text.emit(f"Extracting ZIP… {os.path.basename(self.zip_path)}")
            cdg_path, mp3_path = self.zip_cache.get_extracted_paths(self.zip_path)
            _perf_log_if_slow("zip_extract", (time.perf_counter() - started) * 1000.0)
            if self._cancelled:
                self.finished.emit(self.zip_path, "", "", self.semitones, False, "cancelled")
                return
            if cdg_path and mp3_path:
                self.finished.emit(self.zip_path, str(cdg_path), str(mp3_path), self.semitones, True, "")
            else:
                self.finished.emit(self.zip_path, "", "", self.semitones, False, "ZIP extraction failed")
        except Exception as e:
            self.finished.emit(self.zip_path, "", "", self.semitones, False, str(e))
        

class TrackItemDelegate(QStyledItemDelegate):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.row_height = 60  # Double the current height
        
    def paint(self, painter, option, index):
        painter.save()
        
        # Get the full display text
        full_text = index.data(Qt.ItemDataRole.DisplayRole)
        
        # Parse the display text to extract components
        artist, title, disc_id, duration = self.parse_display_text(full_text)        # Set up colors based on selection/alternating
        palette = option.palette
        if option.state & QStyle.StateFlag.State_Selected:
            bg_color = palette.color(QPalette.ColorRole.Highlight)
            text_color = palette.color(QPalette.ColorRole.HighlightedText)
        elif index.row() % 2 == 0:
            bg_color = palette.color(QPalette.ColorRole.Base)
            text_color = palette.color(QPalette.ColorRole.Text)
        else:
            bg_color = palette.color(QPalette.ColorRole.AlternateBase)
            text_color = palette.color(QPalette.ColorRole.Text)

        # Fill background
        painter.fillRect(option.rect, bg_color)
        # Set up fonts (inherit global app font family + size)
        artist_font = QApplication.font(); artist_font.setWeight(QFont.Weight.Normal)
        title_font  = QApplication.font();  title_font.setWeight(QFont.Weight.Normal)
        right_font  = QApplication.font();  right_font.setWeight(QFont.Weight.Normal)
        
        painter.setPen(text_color)
        
        # Calculate margins and positions - BALANCED SPACING
        left_margin = 12
        right_margin = 12
        vertical_margin = 12  # Equal top and bottom margin
        line_spacing = 4  # Space between artist and title lines
        
        # Calculate text heights
        artist_metrics = QFontMetrics(artist_font)
        title_metrics = QFontMetrics(title_font)
        right_metrics = QFontMetrics(right_font)
        
        artist_height = artist_metrics.height()
        title_height = title_metrics.height()
        right_height = right_metrics.height()
        
        # Total content height
        total_text_height = artist_height + line_spacing + title_height
        
        # Center the text block vertically within the item
        content_start_y = option.rect.top() + (option.rect.height() - total_text_height) // 2
        
        # Left side content area
        left_area_width = option.rect.width() - 320  # Reserve space for right side        

        # Draw artist (top line, bold) - centered vertically
        artist_rect = QRect(
            option.rect.left() + left_margin,
            content_start_y,
            left_area_width - left_margin,
            artist_height
        )
        painter.setFont(artist_font)
        painter.drawText(artist_rect, Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter, artist)
        
        # Draw title (bottom line, normal weight) - directly below artist
        title_rect = QRect(
            option.rect.left() + left_margin,
            content_start_y + artist_height + line_spacing,
            left_area_width - left_margin,
            title_height
        )
        painter.setFont(title_font)
        painter.drawText(title_rect, Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter, title)
        
        # Draw disc ID (top right) - aligned with artist
        disc_rect = QRect(
            option.rect.right() - 180,
            content_start_y,
            170,
            right_height
        )
        painter.setFont(right_font)
        painter.setPen(text_color)
        painter.drawText(disc_rect, Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter, disc_id)
        
        # --- right-side metrics ---
        right_font = painter.font()
        fm = QFontMetrics(right_font)  # <-- add this line
        painter.setFont(right_font)
        right_height = fm.height()

        # Parse tail from the row text: "... [mm:ss] +N"
        # 'text' here should be the full display string for the row.
        try:
            raw = text.strip()
        except NameError:
            # Fallback if your variable is named differently
            raw = index.data(Qt.ItemDataRole.DisplayRole).strip()

        # 1) duration [mm:ss] at end, with optional bare key after it
        #    We capture both in one pass for robustness.
        dur_key = re.search(r'\[([0-9]{1,2}:[0-9]{2})\]\s*\[?([+\-]\d+)?\]?\s*$', raw)
        duration = ""
        key_info = ""
        if dur_key:
            duration = dur_key.group(1) or ""
            key_info = dur_key.group(2) or ""
            key_info = key_info.strip().strip('[]')
            # Remove the matched tail so the rest of the renderer uses clean text
            raw = raw[:dur_key.start()].strip()

        # --- draw key at far right, duration just to its left ---
        key_w   = 56   # width for "+2"/"-1"
        dur_w   = 74   # width for "03:23"
        gap     = 8    # space between duration and key
        edgepad = 8    # right edge padding

        # KEY (far right)
        if key_info:
            key_rect = QRect(
                option.rect.right() - key_w - edgepad,
                content_start_y + artist_height + line_spacing,
                key_w,
                right_height
            )
            painter.setPen(QColor("#FBD000"))  # warm yellow key change
            painter.drawText(
                key_rect,
                Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter,
                key_info
            )

        # DURATION (to the left of key; if no key, hug the right edge)
        if duration:
            right_edge = option.rect.right() - edgepad
            if key_info:
                right_edge -= (key_w + gap)
            duration_rect = QRect(
                right_edge - dur_w,
                content_start_y + artist_height + line_spacing,
                dur_w,
                right_height
            )
            painter.setPen(text_color)
            painter.drawText(
                duration_rect,
                Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter,
                duration
            )

        # Widths: adjust if your font runs tight
        key_w = 56
        dur_w = 74
        gap   = 8
        edge_pad = 8

        # KEY at absolute far right (only if present)
        if key_info:
            key_rect = QRect(
                option.rect.right() - key_w - edge_pad,
                content_start_y + artist_height + line_spacing,
                key_w,
                right_height
            )
            painter.setPen(QColor("#FBD000"))  # warm yellow key change
            painter.drawText(
                key_rect,
                Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter,
                key_info  # e.g., "+2" or "-1"
            )

        # DURATION just to the left of the key (so key appears AFTER duration)
        if duration:
            # If key missing, keep duration near the edge; otherwise, leave room for key + gap
            right_edge = option.rect.right() - edge_pad
            if key_info:
                right_edge = option.rect.right() - edge_pad - key_w - gap

            duration_rect = QRect(
                right_edge - dur_w,
                content_start_y + artist_height + line_spacing,
                dur_w,
                right_height
            )
            painter.setPen(text_color)
            painter.drawText(
                duration_rect,
                Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter,
                duration
            )
        
        painter.restore()
    
    def sizeHint(self, option, index):
        return QSize(0, self.row_height)
    
    def parse_display_text(self, text):
        """Parse the display text into artist, title, disc_id, and duration.

        Also: if duet info is embedded in disc_id like 'KVDM-12345  👥 A & B',
        move '👥 A & B' onto the artist line so disc IDs don't get cut off.
        """
        # Example input:
        #   "Artist - Title - DISC123  [03:45]"
        # or (with duet marker embedded):
        #   "Artist - Title - DISC123  👥 Des & Bob  [03:45]"

        # Extract duration first (in brackets at the end)
        duration = ""
        duration_match = re.search(r'\[([^\]]+)\]$', text)
        if duration_match:
            duration = duration_match.group(1)
            text = text[:duration_match.start()].strip()

        # Split by " - " to get parts
        parts = text.split(" - ")

        if len(parts) >= 3:
            artist = parts[0].strip()
            title = parts[1].strip()
            disc_id = parts[2].strip()
        elif len(parts) == 2:
            artist = parts[0].strip()
            title = parts[1].strip()
            disc_id = ""
        else:
            # Fallback - use the whole text as title
            artist = ""
            title = text.strip()
            disc_id = ""

        # ---- DUET MARKER RELOCATION ----
        # If duet marker is packed into disc_id, move it to artist so the disc id stays readable.
        if disc_id and "👥" in disc_id:
            disc_main, duet_part = disc_id.split("👥", 1)  # maxsplit=1 (what you wanted)
            disc_id = disc_main.strip()
            duet_part = duet_part.strip()
            if duet_part:
                if artist:
                    artist = f"{artist}  👥 {duet_part}"
                else:
                    artist = f"👥 {duet_part}"

        # Optional safety: if for any reason the duet marker ends up in title, move it too.
        if title and "👥" in title:
            title_main, duet_part = title.split("👥", 1)
            title = title_main.strip()
            duet_part = duet_part.strip()
            if duet_part:
                if artist:
                    artist = f"{artist}  👥 {duet_part}"
                else:
                    artist = f"👥 {duet_part}"

        return artist, title, disc_id, duration


class RightAlignedMetaDelegate(QStyledItemDelegate):
    """Paints list rows with a true right-aligned metadata chunk (disc/duration)."""

    def __init__(
        self,
        left_role: int,
        right_role: int,
        parent=None,
        compact_shift_ratio: float = 0.0,
        edge_pad_px: int = 8,
        gap_px: int = 12,
        force_scrollbar_reserve_px: int | None = None,
        duet_role: int | None = None,
    ):
        super().__init__(parent)
        self.left_role = left_role
        self.right_role = right_role
        self.duet_role = duet_role
        self.gap_px = max(4, int(gap_px))
        self.edge_pad_px = max(0, int(edge_pad_px))
        self.force_scrollbar_reserve_px = force_scrollbar_reserve_px
        # 0.0 = fully edge-aligned (default), 0.5 = pull right chunk left by ~half spare gap.
        try:
            self.compact_shift_ratio = max(0.0, min(1.0, float(compact_shift_ratio)))
        except Exception:
            self.compact_shift_ratio = 0.0

    def _scrollbar_reserve_px(self, opt: QStyleOptionViewItem) -> int:
        """Reserve space so right-aligned metadata is not covered by vertical scrollbars."""
        if self.force_scrollbar_reserve_px is not None:
            return max(0, int(self.force_scrollbar_reserve_px))
        reserve = 0
        try:
            view = opt.widget.parent() if opt.widget is not None and hasattr(opt.widget, "parent") else None
            if view is not None and hasattr(view, "verticalScrollBar"):
                sb = view.verticalScrollBar()
                if sb is not None:
                    if sb.isVisible() or sb.maximum() > sb.minimum():
                        reserve = max(reserve, int(sb.sizeHint().width() or 0), int(sb.width() or 0))
        except Exception:
            pass

        # macOS overlay scrollbars can float above content, so keep a small always-on safety inset.
        if sys.platform == "darwin":
            reserve = max(reserve, 14)
        return reserve

    def paint(self, painter, option, index):
        left = index.data(self.left_role)
        right = index.data(self.right_role)
        if left is None and right is None:
            super().paint(painter, option, index)
            return

        left = str(left or "")
        right = str(right or "")

        opt = QStyleOptionViewItem(option)
        self.initStyleOption(opt, index)
        style = opt.widget.style() if opt.widget is not None else QApplication.style()
        opt.text = ""
        style.drawControl(QStyle.ControlElement.CE_ItemViewItem, opt, painter, opt.widget)

        text_rect = style.subElementRect(QStyle.SubElement.SE_ItemViewItemText, opt, opt.widget)
        if not text_rect.isValid():
            return

        # Vertically center against the FULL row, not the padding-shrunk text
        # rect — otherwise tall vertical padding squeezes the text box and clips
        # descenders (y, p, g, q) off the bottom of each row.
        text_rect.setTop(option.rect.top())
        text_rect.setBottom(option.rect.bottom())

        fm = QFontMetrics(opt.font)
        right_w = fm.horizontalAdvance(right) if right else 0
        left_rect = QRect(text_rect)
        right_rect = QRect()

        scrollbar_reserve = self._scrollbar_reserve_px(opt)
        if right_w > 0:
            right_rect = QRect(
                text_rect.right() - right_w - self.edge_pad_px - scrollbar_reserve + 1,
                text_rect.top(),
                right_w + self.edge_pad_px,
                text_rect.height(),
            )
            left_rect.setRight(max(left_rect.left(), right_rect.left() - self.gap_px))

        left_draw = fm.elidedText(left, Qt.TextElideMode.ElideRight, max(0, left_rect.width()))

        # Optional compact mode: reduce giant middle gap by pulling right metadata left.
        if right and self.compact_shift_ratio > 0.0:
            try:
                left_draw_w = fm.horizontalAdvance(left_draw)
                ideal_right_left = text_rect.left() + left_draw_w + self.gap_px
                extra_gap = int(right_rect.left() - ideal_right_left)
                if extra_gap > 0:
                    shift = int(extra_gap * self.compact_shift_ratio)
                    if shift > 0:
                        right_rect.translate(-shift, 0)
                        left_rect.setRight(max(left_rect.left(), right_rect.left() - self.gap_px))
                        left_draw = fm.elidedText(left, Qt.TextElideMode.ElideRight, max(0, left_rect.width()))
            except Exception:
                pass

        fg = index.data(Qt.ItemDataRole.ForegroundRole)
        if option.state & QStyle.StateFlag.State_Selected:
            pen_color = option.palette.color(QPalette.ColorRole.HighlightedText)
        elif hasattr(fg, "color"):
            pen_color = fg.color()
        else:
            pen_color = option.palette.color(QPalette.ColorRole.Text)

        painter.save()
        painter.setFont(opt.font)
        painter.setPen(pen_color)
        duet_suffix = ""
        if self.duet_role is not None:
            try:
                duet_suffix = str(index.data(self.duet_role) or "").strip()
            except Exception:
                duet_suffix = ""
        if duet_suffix:
            # Draw "<name>   •   <& Partner>" with the partner clause italic and
            # dimmed, separated by a bullet, so it clearly reads as a separate
            # tag rather than a continuation of the song/name text.
            display_suffix = "•  " + duet_suffix
            italic_font = QFont(opt.font)
            italic_font.setItalic(True)
            italic_fm = QFontMetrics(italic_font)
            gap = 10
            suffix_w = italic_fm.horizontalAdvance(display_suffix)
            name_avail = max(0, left_rect.width() - suffix_w - gap)
            name_draw = fm.elidedText(left, Qt.TextElideMode.ElideRight, name_avail)
            name_w = fm.horizontalAdvance(name_draw)
            painter.drawText(left_rect, Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft, name_draw)
            suffix_x = left_rect.left() + name_w + gap
            suffix_rect = QRect(suffix_x, left_rect.top(), max(0, left_rect.right() - suffix_x), left_rect.height())
            # Dim the partner clause: a translucent version of the row colour so
            # it sits visibly behind the primary text on any row state.
            suffix_color = QColor(pen_color)
            try:
                suffix_color.setAlpha(120)
            except Exception:
                pass
            painter.setFont(italic_font)
            painter.setPen(suffix_color)
            painter.drawText(
                suffix_rect,
                Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft,
                italic_fm.elidedText(display_suffix, Qt.TextElideMode.ElideRight, suffix_rect.width()),
            )
            painter.setFont(opt.font)
            painter.setPen(pen_color)
        else:
            painter.drawText(left_rect, Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft, left_draw)
        if right:
            right_text = right
            # Match ONLY the bare DUET token so the disc id / company / duration
            # that follow it stay visible (a greedy match used to swallow them,
            # hiding the disc id on duet rows).
            duet_match = re.search(r"\bDUET\b", right_text, re.IGNORECASE)
            if duet_match:
                badge_label = "DUET"
                eta_text = right_text[:duet_match.start()] + right_text[duet_match.end():]
                eta_text = re.sub(r"\s+", " ", eta_text).strip()
                badge_font = QFont(opt.font)
                badge_font.setPointSize(max(8, opt.font.pointSize() - 2))
                badge_font.setBold(True)
                badge_fm = QFontMetrics(badge_font)
                badge_w = badge_fm.horizontalAdvance(badge_label) + 12
                badge_h = min(18, max(15, text_rect.height() - 8))
                eta_w = fm.horizontalAdvance(eta_text) if eta_text else 0
                total_w = eta_w + (self.gap_px if eta_text else 0) + badge_w
                badge_x = text_rect.right() - total_w - self.edge_pad_px - scrollbar_reserve + 1
                eta_x = badge_x + badge_w + (self.gap_px if eta_text else 0)
                badge_rect = QRect(badge_x, text_rect.center().y() - badge_h // 2, badge_w, badge_h)
                painter.setPen(Qt.PenStyle.NoPen)
                painter.setBrush(QColor(124, 61, 255, 150))
                painter.drawRoundedRect(badge_rect, 4, 4)
                painter.setFont(badge_font)
                painter.setPen(QColor("#FFFFFF"))
                painter.drawText(badge_rect, Qt.AlignmentFlag.AlignCenter, badge_label)
                if eta_text:
                    painter.setFont(opt.font)
                    painter.setPen(pen_color)
                    eta_rect = QRect(eta_x, text_rect.top(), eta_w, text_rect.height())
                    painter.drawText(eta_rect, Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignRight, eta_text)
            else:
                painter.drawText(right_rect, Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignRight, right)
        painter.restore()
    
# QueueItemDelegate removed


class TwoLineSearchDelegate(QStyledItemDelegate):
    """Search-results delegate that paints two lines per row:

    Line 1 (bold): artist
    Line 2 (regular): title, with disc/duration/badge metadata right-aligned

    Falls back to a single-line layout if the row data doesn't include the
    ' • ' separator the search builder uses.
    """

    def __init__(self, left_role: int, right_role: int, parent=None,
                 edge_pad_px: int = 10, gap_px: int = 12, disc_role: int = None):
        super().__init__(parent)
        self.left_role = left_role
        self.right_role = right_role
        self.disc_role = disc_role
        self.edge_pad_px = max(0, int(edge_pad_px))
        self.gap_px = max(4, int(gap_px))

    def sizeHint(self, option, index):
        base = super().sizeHint(option, index)
        fm = QFontMetrics(option.font)
        # Two text lines + small interline gap + a little vertical padding.
        h = fm.height() * 2 + 4 + 12
        return QSize(base.width(), h)

    def paint(self, painter, option, index):
        left = str(index.data(self.left_role) or "")
        right = str(index.data(self.right_role) or "")
        if not left and not right:
            super().paint(painter, option, index)
            return

        opt = QStyleOptionViewItem(option)
        self.initStyleOption(opt, index)
        style = opt.widget.style() if opt.widget is not None else QApplication.style()
        opt.text = ""
        style.drawControl(QStyle.ControlElement.CE_ItemViewItem, opt, painter, opt.widget)

        text_rect = style.subElementRect(QStyle.SubElement.SE_ItemViewItemText, opt, opt.widget)
        if not text_rect.isValid():
            return

        # Split "Artist • Title" into two pieces.
        if " • " in left:
            artist, title = left.split(" • ", 1)
        else:
            artist, title = left, ""

        artist_font = QFont(opt.font)
        artist_font.setBold(True)
        title_font = QFont(opt.font)
        title_font.setPointSizeF(max(8.0, opt.font.pointSizeF() - 1))
        title_font.setBold(False)

        art_fm = QFontMetrics(artist_font)
        ttl_fm = QFontMetrics(title_font)

        if option.state & QStyle.StateFlag.State_Selected:
            fg_primary = option.palette.color(QPalette.ColorRole.HighlightedText)
            fg_secondary = fg_primary
        else:
            fg_primary = option.palette.color(QPalette.ColorRole.Text)
            fg_secondary = QColor(fg_primary)
            fg_secondary.setAlpha(180)

        inter_line_gap = 2
        artist_h = art_fm.height()
        title_h = ttl_fm.height()
        total_h = artist_h + inter_line_gap + title_h
        y0 = text_rect.top() + max(0, (text_rect.height() - total_h) // 2)

        artist_rect = QRect(text_rect.left(), y0, text_rect.width(), artist_h)
        title_rect = QRect(text_rect.left(),
                           y0 + artist_h + inter_line_gap,
                           text_rect.width(),
                           title_h)

        # Right-aligned metadata sits on the title (bottom) line.
        # The leading disc-ID/company segment is rendered bold so it scans fast.
        scrollbar_reserve = 14 if sys.platform == "darwin" else 0
        disc_seg = ""
        rest_seg = right
        if right and self.disc_role is not None:
            disc = str(index.data(self.disc_role) or "")
            if disc and right.startswith(disc):
                disc_seg = disc
                rest_seg = right[len(disc):]
        disc_font = QFont(title_font)
        disc_font.setBold(True)
        disc_fm = QFontMetrics(disc_font)
        disc_w = disc_fm.horizontalAdvance(disc_seg) if disc_seg else 0
        rest_w = ttl_fm.horizontalAdvance(rest_seg) if rest_seg else 0
        right_w = disc_w + rest_w
        if right_w > 0:
            right_rect = QRect(
                title_rect.right() - right_w - self.edge_pad_px - scrollbar_reserve + 1,
                title_rect.top(),
                right_w + self.edge_pad_px,
                title_rect.height(),
            )
            title_rect.setRight(max(title_rect.left(), right_rect.left() - self.gap_px))
        else:
            right_rect = QRect()

        artist_draw = art_fm.elidedText(artist, Qt.TextElideMode.ElideRight, max(0, artist_rect.width()))
        title_draw = ttl_fm.elidedText(title, Qt.TextElideMode.ElideRight, max(0, title_rect.width()))

        painter.save()
        painter.setPen(fg_primary)
        painter.setFont(artist_font)
        painter.drawText(artist_rect, Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft, artist_draw)
        painter.setPen(fg_secondary)
        painter.setFont(title_font)
        painter.drawText(title_rect, Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft, title_draw)
        if right_w > 0:
            x = right_rect.left()
            if disc_seg:
                disc_rect = QRect(x, right_rect.top(), disc_w, right_rect.height())
                painter.setPen(fg_primary)
                painter.setFont(disc_font)
                painter.drawText(disc_rect, Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft, disc_seg)
                x += disc_w
            if rest_seg:
                rest_rect = QRect(x, right_rect.top(), rest_w, right_rect.height())
                painter.setPen(fg_secondary)
                painter.setFont(title_font)
                painter.drawText(rest_rect, Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft, rest_seg)
        painter.restore()


