        for b in (self.play_next, self.karaoke_pause_button, self.restart_button, self.stop_button, self.add_file_icon_button, self.audio_output_button):
            b.setStyleSheet(subtle_button_css(padding="4px 8px", radius=8))
        self.audio_output_button.setStyleSheet(subtle_button_css(padding="0px", radius=8))

        # Make sure all transport icons (▶ ▮▮ ↺ ■ ＋) render at matching
        # visual weight.  Use the system default family at an explicit bold
        # 18pt; ▮ (Geometric Shapes block) renders as a proper solid
        # rectangle in every font, unlike ⏸/❚ which often fall back to a
        # smaller glyph.
        try:
            _karaoke_transport_font = QFont()  # system default family
            _karaoke_transport_font.setPointSize(18)
            _karaoke_transport_font.setWeight(QFont.Weight.Bold)
            for b in (
                self.play_next,
                self.karaoke_pause_button,
                self.restart_button,
                self.stop_button,
                self.add_file_icon_button,
            ):
                b.setFont(_karaoke_transport_font)
            self.karaoke_pause_button.setText("▮▮")
        except Exception:
            pass

        # Always keep the pause button enabled so it looks identical to its
        # neighbours (disabled state renders much darker on macOS, which is
        # what the user saw as "black").  The click handler itself no-ops
        # when nothing is playing.
        self.karaoke_pause_button.setEnabled(True)

        # --- Soundboard strip (inline, under transport buttons) ---
        # Eight pads (2x4) that play sound clips over whatever is currently
        # playing. Pad assignments persist via self.settings["soundboard_pads"].
        # On short displays (e.g. a 15" Intel ~900px tall) the whole transport
        # deck would otherwise not fit, so size the pads/deck down to suit.
        try:
            _avail_h = QApplication.primaryScreen().availableGeometry().height()
        except Exception:
            _avail_h = 1000
        self._compact_deck = bool(_avail_h < 950)
        _pad_h = 40 if self._compact_deck else 58
        self.soundboard_strip = SoundboardStrip(pad_count=8, pad_height=_pad_h, parent=self)
        try:
            self.soundboard_strip.load_from_list(self.settings.get("soundboard_pads", []))
        except Exception:
            pass
        self.soundboard_strip.changed.connect(self._on_soundboard_changed)
        row_controls.addWidget(self.soundboard_strip)

        # Karaoke tempo/key controls (karaoke-only; never touches BG music).
        # Keep this as a simple fixed-height grid; nested layouts in this tight
        # right rail can otherwise compress rows into each other.
        tempo_panel = QWidget()
        tempo_panel.setObjectName("karaokeTempoKeyPanel")
        tempo_panel.setFixedHeight(78)
        tempo_panel.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Fixed)
        tempo_panel.setStyleSheet(
            SINGWS_THEME.control_grid_css("karaokeTempoKeyPanel") if SINGWS_THEME is not None else
            "QWidget#karaokeTempoKeyPanel { background: rgba(5,9,18,0.46); border: 1px solid rgba(255,255,255,0.034); border-radius: 8px; }"
        )
        tempo_controls_grid = QGridLayout(tempo_panel)
        tempo_controls_grid.setContentsMargins(10, 8, 10, 8)
        tempo_controls_grid.setHorizontalSpacing(8)
        tempo_controls_grid.setVerticalSpacing(6)
        self.karaoke_tempo_controls_grid = tempo_controls_grid

        self.karaoke_tempo_label = QLabel("Tempo")
        self.karaoke_tempo_down_button = QToolButton()
        self.karaoke_tempo_down_button.setText("－")
        self.karaoke_tempo_value_label = QLabel("100%")
        self.karaoke_tempo_up_button = QToolButton()
        self.karaoke_tempo_up_button.setText("＋")
