        # Enhanced search box (native clear button)
        self.search_input = QLineEdit()
        self.search_input.setObjectName("librarySearchInput")
        self.search_input.setPlaceholderText("Search songs, artists, or titles...")
        self.search_input.setClearButtonEnabled(True)  # native macOS clear (✕) inside the field
        # Search bar height ~1.5x (keep native look)
        try:
            _h = self.search_input.sizeHint().height()
            self.search_input.setMinimumHeight(max(int(_h * 1.45), 42))
        except Exception:
            self.search_input.setMinimumHeight(42)
        self.search_input.returnPressed.connect(self.search_tracks)
        self.search_input.textChanged.connect(self.on_search_text_changed)
        # Debounce "search as you type" so big libraries stay snappy
        self._search_debounce = QTimer(self)
        self._search_debounce.setSingleShot(True)
        self._search_debounce.timeout.connect(self.search_tracks)

        # DON'T build index on startup - only after scanning
        # Search will show "No DB Found" message if needed
        # try:
        #     QTimer.singleShot(250, lambda: self.ensure_song_index_async(force=False))
        # except Exception:
        #     pass

        # Debounce list reformat on resize (Mode A two-column layout)
        self._list_reformat_timer = QTimer(self)
        self._list_reformat_timer.setSingleShot(True)
        self._list_reformat_timer.timeout.connect(self._reformat_lists_now)

        # Ticker debounce
        self._ticker_update_timer = QTimer(self)
        self._ticker_update_timer.setSingleShot(True)
        self._ticker_update_timer.timeout.connect(self._do_ticker_update)

