        # --- Search Results (clean list, matches queue behavior) ---

        self.results_list = QListWidget()
        self._row_left_role = int(Qt.ItemDataRole.UserRole) + 20
        self._row_right_role = int(Qt.ItemDataRole.UserRole) + 21
        self._row_disc_role = int(Qt.ItemDataRole.UserRole) + 22
        # Optional italic "& Partner" suffix drawn right after the left text
        # (used to show the duet partner on a singer's name row for announcing).
        self._row_duet_role = int(Qt.ItemDataRole.UserRole) + 23

        # Match queue behavior: alternating rows + visible selection + fixed row height
        self.results_list.setAlternatingRowColors(True)
        # Native scrollbars; prevent horizontal scrollbar (we elide text ourselves)
        self.results_list.setVerticalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAsNeeded)
        self.results_list.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)
        try:
            self.results_list.setTextElideMode(Qt.TextElideMode.ElideNone)
        except Exception:
            pass

        self.results_list.setStyleSheet(list_widget_css())
        self.results_list.setUniformItemSizes(True)

        # Set native font with macOS size adjustment (14pt for Mac, 10pt for Windows/Linux)
        results_font = self.results_list.font()
        results_font.setPointSize(int(self._results_base_point_size))
        self.results_list.setFont(results_font)

        # Reformat when the vertical scrollbar appears/disappears (viewport width changes)
        try:
            self.results_list.verticalScrollBar().rangeChanged.connect(lambda *_: self._schedule_reformat_lists())
        except Exception:
            pass

        # Fix "needs two clicks" / focus weirdness on Windows
        self.results_list.setSelectionMode(QAbstractItemView.SelectionMode.SingleSelection)
        self.results_list.setFocusPolicy(Qt.FocusPolicy.StrongFocus)
        self.results_list.setMouseTracking(True)
        self.results_list.viewport().setMouseTracking(True)

        # Allow deselection by clicking empty space (same as queue)
        self.results_list.viewport().installEventFilter(self)

        self.results_list.itemDoubleClicked.connect(self._on_search_result_double_clicked)
        self.results_list.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
        self.results_list.customContextMenuRequested.connect(self.show_search_context_menu)
        self.results_list.setItemDelegate(
            TwoLineSearchDelegate(self._row_left_role, self._row_right_role, self.results_list,
                                  disc_role=self._row_disc_role)
        )
        # Reformat when the vertical scrollbar appears/disappears (viewport width changes without a resize event)
        try:
            self.results_list.verticalScrollBar().rangeChanged.connect(lambda *_: self._list_reformat_timer.start(50))
        except Exception:
            pass


