        def _build_nav_item(glyph: str, text: str) -> QPushButton:
            btn = QPushButton()
            btn.setMinimumHeight(52)
            btn.setMinimumWidth(0)
            btn.setCursor(Qt.CursorShape.PointingHandCursor)
            btn.setFocusPolicy(Qt.FocusPolicy.NoFocus)
            btn.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Expanding)
            cell = QVBoxLayout(btn)
            cell.setContentsMargins(2, 4, 2, 4)
            cell.setSpacing(1)
            cell.setAlignment(Qt.AlignmentFlag.AlignCenter)
            icon_label = QLabel(glyph)
            icon_label.setObjectName("navIcon")
            icon_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
            icon_label.setAttribute(Qt.WidgetAttribute.WA_TransparentForMouseEvents, True)
            text_label = QLabel(text)
            text_label.setObjectName("navLabel")
            text_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
            text_label.setAttribute(Qt.WidgetAttribute.WA_TransparentForMouseEvents, True)
            cell.addWidget(icon_label, 0, Qt.AlignmentFlag.AlignCenter)
            cell.addWidget(text_label, 0, Qt.AlignmentFlag.AlignCenter)
            self._nav_icon_labels[btn] = icon_label
            self._nav_text_labels[btn] = text_label
            return btn

