        def _scale_from_slider() -> float:
            idx = max(0, min(len(LIST_FONT_SCALE_PRESETS) - 1, int(slider.value())))
            return float(LIST_FONT_SCALE_PRESETS[idx])

        def apply_text_size_from_slider():
            if pending_text_size.get("applied"):
                return
            pending_text_size["applied"] = True
            scale = _scale_from_slider()
            self.settings["list_font_scale"] = scale
            self._apply_list_font_scale()
            self.save_settings()

        def on_slider(_idx: int):
            scale = _scale_from_slider()
            self.settings["list_font_scale"] = scale
            pending_text_size["dirty"] = True
            pending_text_size["applied"] = False
            self.save_settings()

