        def _populate_audio_combo(select_id: str | None = None):
            wanted = str(select_id or self._get_selected_audio_output_id() or "default")
            audio_output_combo.blockSignals(True)
            audio_output_combo.clear()
            outputs = self._refresh_audio_output_cache()
            selected_idx = 0
            for i, out in enumerate(outputs):
                oid = str(out.get("id", "default"))
                label = f"{out.get('name', 'Audio Output')}"
                audio_output_combo.addItem(label, oid)
                if oid == wanted:
                    selected_idx = i
            audio_output_combo.setCurrentIndex(selected_idx)
            audio_output_combo.blockSignals(False)

        def on_audio_output_changed(_idx: int):
            oid = str(audio_output_combo.currentData() or "default")
            self._set_audio_output_id(oid)
            _populate_audio_combo(oid)

