        def on_filename_fmt_changed(_idx: int):
            new_fmt = str(filename_fmt_combo.currentData() or DEFAULT_FILENAME_FORMAT)
            prev_fmt = str(self.settings.get("filename_format", DEFAULT_FILENAME_FORMAT)
                           or DEFAULT_FILENAME_FORMAT)
            if new_fmt == prev_fmt:
                return
            self.settings["filename_format"] = new_fmt
            try:
                self.save_settings()
            except Exception:
                pass
            # Re-apply the parser to every track in the in-memory library so
            # Artist / Title / Disc columns update immediately without a
            # full disk re-scan.
            try:
                updated = self.reparse_library_filenames()
            except Exception:
                updated = 0
            try:
                QMessageBox.information(
                    dlg, "Filename format updated",
                    f"Re-parsed {updated:,} tracks using the new layout.\n\n"
                    "Run Scan Folder if you'd also like to rebuild the on-disk "
                    "search index with the new fields.",
                )
            except Exception:
                pass
