    def _history_sort_key(self, record: dict):
        # Alphabetical by singer name (case-insensitive) so the directory is
        # easy to scan during a show.
        return str(record.get("name", "") or "").strip().lower()

    def _history_song_display(self, song: dict) -> str:
        artist = str(song.get("artist", "") or "").strip() or "Unknown Artist"
        title = str(song.get("title", "") or "").strip() or "Unknown Song"
        disc = str(song.get("disc_id", "") or "").strip()
        song_type = str(song.get("song_type", "") or "").strip().upper()
        duet_display = str(song.get("duet_display", "") or "").strip()
        key = int(song.get("last_key") or 0)
        tempo = int(song.get("last_tempo_percent") or 100)
        meta = []
        if duet_display:
            meta.append(f"Duet: {duet_display}")
        if disc:
            meta.append(disc)
        if song_type:
            meta.append(song_type)
        meta.append(f"Key {key:+d}")
        meta.append(f"Tempo {tempo}%")
        return f"{artist} • {title}\n" + "  ·  ".join(meta)

    def _format_history_timestamp(self, ts: int) -> str:
        try:
            ts = int(ts or 0)
            if ts <= 0:
                return "Never"
            return datetime.fromtimestamp(ts).strftime("%b %d, %Y")
        except Exception:
            return "Never"

    def _selected_singer_history_key(self) -> str:
        item = self.singer_history_singer_list.currentItem()
        if not item:
            return ""
        return str(item.data(Qt.ItemDataRole.UserRole) or "")

    def _selected_singer_history_song_key(self) -> str:
        item = self.singer_history_songs_list.currentItem()
        if not item:
            return ""
        return str(item.data(Qt.ItemDataRole.UserRole) or "")

    def _selected_singer_history_song_record(self) -> dict | None:
        singer_key = self._selected_singer_history_key()
        song_key = self._selected_singer_history_song_key()
        if not singer_key or not song_key:
            return None
        singer = self.singer_history.get("singers", {}).get(singer_key)
        if not isinstance(singer, dict):
            return None
        song = (singer.get("songs", {}) or {}).get(song_key)
        return song if isinstance(song, dict) else None

    def _refresh_singer_history_view(self):
        if not hasattr(self, "singer_history_singer_list"):
            return
        current_key = self._selected_singer_history_key()
        search = ""
        try:
            search = str(self.singer_history_search.text() or "").strip().lower()
        except Exception:
            pass
        self.singer_history_singer_list.clear()
        singers = list(self.singer_history.get("singers", {}).items())
        singers.sort(key=lambda kv: self._history_sort_key(kv[1]))
        match_count = 0
        for singer_key, record in singers:
            name = str(record.get("name", "") or singer_key).strip()
            if search:
                haystack = f"{name} {record.get('preferred_disc_priority', '')}".lower()
                if search not in haystack:
                    song_match = False
                    for song in (record.get("songs", {}) or {}).values():
                        text = (
                            f"{song.get('artist', '')} {song.get('title', '')} "
                            f"{song.get('disc_id', '')} {song.get('duet_display', '')}"
                        ).lower()
                        if search in text:
                            song_match = True
                            break
                    if not song_match:
                        continue
            match_count += 1
            perf = int(record.get("total_performances") or 0)
            uniq = int(record.get("unique_song_count") or len(record.get("songs", {}) or {}))
            pref = str(record.get("preferred_disc_priority", "") or "").strip()
            lines = [name, f"{perf} plays  ·  {uniq} songs"]
            if pref:
                lines.append(f"Prefers: {pref}")
            item = QListWidgetItem("\n".join(lines))
            item.setData(Qt.ItemDataRole.UserRole, singer_key)
            # Height is computed by WrapHeightItemDelegate so long names wrap and
            # the row grows to fit (no fixed height, no truncation).
            self.singer_history_singer_list.addItem(item)
            if singer_key == current_key:
                self.singer_history_singer_list.setCurrentItem(item)
        self.singer_history_meta_label.setText(f"{match_count} singers")
        try:
            self.singer_history_left_meta_label.setText("Directory" if match_count else "Empty")
        except Exception:
            pass
        if self.singer_history_singer_list.count() and self.singer_history_singer_list.currentRow() < 0:
            self.singer_history_singer_list.setCurrentRow(0)
        elif self.singer_history_singer_list.count() == 0:
            self._update_singer_history_details("")

    def _on_singer_history_selection_changed(self, *_args):
        self._update_singer_history_details(self._selected_singer_history_key())

    def _update_singer_history_details(self, singer_key: str):
        if not hasattr(self, "singer_history_name_label"):
            return
        record = self.singer_history.get("singers", {}).get(singer_key, {}) if singer_key else {}
        if not isinstance(record, dict) or not singer_key:
            self.singer_history_name_label.setText("Select a singer")
            if hasattr(self, "singer_history_summary_label"):
                self.singer_history_summary_label.setText("No singer selected.")
            self.singer_history_rename_button.setEnabled(False)
            self.singer_history_brand_button.setEnabled(False)
            try:
                self.singer_history_brand_combo.blockSignals(True)
                self.singer_history_brand_combo.clear()
                self.singer_history_brand_combo.addItem("No preferred brand", "")
                self.singer_history_brand_combo.setEnabled(False)
                self.singer_history_brand_combo.blockSignals(False)
            except Exception:
                pass
            self.singer_history_delete_singer_button.setEnabled(False)
            self.singer_history_add_song_button.setEnabled(False)
            self.singer_history_edit_song_button.setEnabled(False)
            self.singer_history_delete_song_button.setEnabled(False)
            self.singer_history_songs_list.clear()
            try:
                self.singer_history_song_meta_label.setText("0 entries")
            except Exception:
                pass
            return
        name = str(record.get("name", "") or singer_key)
        total = int(record.get("total_performances") or 0)
        unique = int(record.get("unique_song_count") or len(record.get("songs", {}) or {}))
        last_seen = self._format_history_timestamp(record.get("last_seen_at") or 0)
        pref = str(record.get("preferred_disc_priority", "") or "").strip()
        self.singer_history_name_label.setText(name)
        summary = f"{total} total performances  ·  {unique} songs  ·  Last seen {last_seen}"
        if pref:
            summary += f"  ·  Preferred brand {pref}"
        if hasattr(self, "singer_history_summary_label"):
            self.singer_history_summary_label.setText(summary)
        self.singer_history_rename_button.setEnabled(True)
        self.singer_history_brand_button.setEnabled(True)
        self._refresh_singer_history_brand_combo(pref)
        self.singer_history_delete_singer_button.setEnabled(True)
        self.singer_history_add_song_button.setEnabled(True)
        self.singer_history_songs_list.clear()
        songs = list((record.get("songs", {}) or {}).items())
        songs.sort(key=lambda kv: (-(int(kv[1].get("last_performed_at") or 0)), kv[1].get("artist", "").lower(), kv[1].get("title", "").lower()))
        for song_key, song in songs:
            item = QListWidgetItem(self._history_song_display(song))
            item.setData(Qt.ItemDataRole.UserRole, song_key)
            item.setSizeHint(QSize(0, 44))
            self.singer_history_songs_list.addItem(item)
        try:
            self.singer_history_song_meta_label.setText(f"{len(songs)} entries")
        except Exception:
            pass
        self.singer_history_edit_song_button.setEnabled(bool(songs))
        self.singer_history_delete_song_button.setEnabled(bool(songs))
        if songs:
            self.singer_history_songs_list.setCurrentRow(0)

    def _history_brand_choices(self) -> list[str]:
        brands = set()
        try:
            for t in getattr(self, "tracks", []) or []:
                disc = str((t or {}).get("disc_id", "") or "").strip()
                if disc:
                    brands.add(disc.upper())
        except Exception:
            pass
        return sorted(brands)

    def _refresh_singer_history_brand_combo(self, current_pref: str = ""):
        combo = getattr(self, "singer_history_brand_combo", None)
        if combo is None:
            return
        current_pref = ", ".join(normalize_disc_priority(current_pref, max_items=10))
        choices = self._history_brand_choices()
        try:
            combo.blockSignals(True)
            combo.clear()
            combo.addItem("No preferred brand", "")
            for brand in choices:
                combo.addItem(brand, brand)
            if current_pref and current_pref not in choices:
                combo.addItem(current_pref, current_pref)
            idx = combo.findData(current_pref)
            combo.setCurrentIndex(idx if idx >= 0 else 0)
            combo.setEnabled(True)
        finally:
            combo.blockSignals(False)

    def _on_singer_history_brand_combo_changed(self, _index: int):
        combo = getattr(self, "singer_history_brand_combo", None)
        singer_key = self._selected_singer_history_key()
        record = self.singer_history.get("singers", {}).get(singer_key)
        if combo is None or not isinstance(record, dict):
            return
        singer_name = str(record.get("name", "") or singer_key)
        value = ", ".join(normalize_disc_priority(combo.currentData() or "", max_items=10))
        current = ", ".join(normalize_disc_priority(record.get("preferred_disc_priority", ""), max_items=10))
        if value == current:
            return
        if value:
            self._set_singer_preference(singer_name, "preferred_disc_priority", value)
            self._commit_singer_history_change("history_brand_quick_select")
        else:
            self._clear_singer_preference(singer_name, "preferred_disc_priority")
            self._commit_singer_history_change("history_brand_quick_clear")

    def _apply_singer_history_preferences_to_queue(self):
        try:
            for singer in self.queue:
                singer_name_key = self._normalize_singer_pref_key(singer.get("name", ""))
                if not singer_name_key:
                    continue
                pref = self.singer_preferences.get(singer_name_key, {})
                pref_disc = ", ".join(normalize_disc_priority(pref.get("preferred_disc_priority", ""), max_items=10))
                if pref_disc:
                    singer["preferred_disc_priority"] = pref_disc
                else:
                    singer.pop("preferred_disc_priority", None)
        except Exception:
            pass

    def _commit_singer_history_change(self, reason: str = "history_edit"):
        self._apply_singer_history_preferences_to_queue()
        try:
            self.save_data()
        except Exception:
            pass
        self._refresh_singer_history_view()
        try:
            self.update_queue_display()
            self.update_rotation_summary_card()
            self._update_last_sung_card()
        except Exception:
            pass
        self._sync_singer_history_async(reason)

    def _rename_selected_singer_history(self):
        singer_key = self._selected_singer_history_key()
        record = self.singer_history.get("singers", {}).get(singer_key)
        if not isinstance(record, dict):
            return
        old_name = str(record.get("name", "") or singer_key).strip()
        new_name, ok = QInputDialog.getText(
            self,
            "Rename Singer History",
            "Singer name:",
            QLineEdit.EchoMode.Normal,
            old_name,
        )
        if not ok:
            return
        new_name = str(new_name or "").strip()
        if not new_name or new_name == old_name:
            return
        old_key = self._normalize_singer_pref_key(old_name)
        new_key = self._normalize_singer_pref_key(new_name)
        singers = self.singer_history.setdefault("singers", {})
        source = singers.pop(old_key, None)
        if not isinstance(source, dict):
            return
        target = singers.get(new_key)
        merged = self._empty_singer_history_record(new_name)
        if isinstance(target, dict):
            merged.update(target)
        merged.update(source)
        merged["name"] = new_name
        merged["songs"] = dict(merged.get("songs", {}) or {})
        merged["unique_song_count"] = len(merged["songs"])
        merged["updated_at"] = int(time.time())
        singers[new_key] = merged
        old_pref = self.singer_preferences.pop(old_key, None)
        if isinstance(old_pref, dict):
            old_pref["name"] = new_name
            self.singer_preferences[new_key] = old_pref
        if old_key != new_key:
            # The old name no longer exists; tombstone it so the rename syncs.
            self._record_singer_tombstone(old_name)
        self._commit_singer_history_change("history_singer_rename")
        for i in range(self.singer_history_singer_list.count()):
            item = self.singer_history_singer_list.item(i)
            if str(item.data(Qt.ItemDataRole.UserRole) or "") == new_key:
                self.singer_history_singer_list.setCurrentItem(item)
                break

    def _edit_history_song_dialog(self, singer_key: str, song_key: str | None = None):
        record = self.singer_history.get("singers", {}).get(singer_key)
        if not isinstance(record, dict):
            return
        songs = record.setdefault("songs", {})
        existing = dict(songs.get(song_key, {})) if song_key else {}

        dlg = QDialog(self)
        dlg.setWindowTitle("Add Song History" if not song_key else "Edit Song History")
        dlg.setModal(True)
        dlg.setMinimumWidth(520)
        try:
            base = self.palette().color(QPalette.ColorRole.Base)
            win = self.palette().color(QPalette.ColorRole.Window)
            txtc = self.palette().color(QPalette.ColorRole.Text)
            dlg.setStyleSheet(dialog_stylesheet(win, base, txtc))
        except Exception:
            pass
        layout = QVBoxLayout(dlg)

        artist_edit = QLineEdit(dlg)
        artist_edit.setPlaceholderText("Artist")
        artist_edit.setText(str(existing.get("artist", "") or ""))
        title_edit = QLineEdit(dlg)
        title_edit.setPlaceholderText("Title")
        title_edit.setText(str(existing.get("title", "") or ""))
        disc_edit = QLineEdit(dlg)
        disc_edit.setPlaceholderText("Disc ID")
        disc_edit.setText(str(existing.get("disc_id", "") or ""))
        type_edit = QLineEdit(dlg)
        type_edit.setPlaceholderText("Type (CDG, ZIP, MP4)")
        type_edit.setText(str(existing.get("song_type", "") or ""))
        key_spin = QSpinBox(dlg)
        key_spin.setRange(-24, 24)
        key_spin.setValue(int(existing.get("last_key") or 0))
        tempo_spin = QSpinBox(dlg)
        tempo_spin.setRange(50, 200)
        tempo_spin.setValue(int(existing.get("last_tempo_percent") or 100))

        for label_text, widget in (
            ("Artist", artist_edit),
            ("Title", title_edit),
            ("Disc ID", disc_edit),
            ("Song Type", type_edit),
            ("Key", key_spin),
            ("Tempo %", tempo_spin),
        ):
            label = QLabel(label_text)
            label.setStyleSheet(section_meta_css())
            layout.addWidget(label)
            layout.addWidget(widget)

        buttons = QDialogButtonBox(dlg)
        save_btn = buttons.addButton("Save", QDialogButtonBox.ButtonRole.AcceptRole)
        buttons.addButton("Cancel", QDialogButtonBox.ButtonRole.RejectRole)
        layout.addWidget(buttons)

        def handle_save():
            if song_key:
                songs.pop(song_key, None)
            new_song = dict(existing)
            new_song["artist"] = str(artist_edit.text() or "").strip()
            new_song["title"] = str(title_edit.text() or "").strip()
            new_song["disc_id"] = str(disc_edit.text() or "").strip()
            new_song["song_type"] = str(type_edit.text() or "").strip().upper()
            new_song["last_key"] = int(key_spin.value())
            new_song["last_tempo_percent"] = int(tempo_spin.value())
            new_song["updated_at"] = int(time.time())
            new_song.setdefault("songid", str(new_song.get("disc_id", "") or ""))
            new_song.setdefault("path", str(existing.get("path", "") or ""))
            new_song.setdefault("play_count", int(existing.get("play_count") or 0))
            new_song.setdefault("first_performed_at", int(existing.get("first_performed_at") or 0))
            new_song.setdefault("last_performed_at", int(existing.get("last_performed_at") or 0))
            new_key = self._normalize_history_song_key(
                new_song.get("artist", ""),
                new_song.get("title", ""),
                new_song.get("songid", ""),
                new_song.get("path", ""),
            )
            if not new_key:
                new_key = song_key or f"manual|{time.time()}"
            songs[new_key] = new_song
            record["unique_song_count"] = len(songs)
            record["updated_at"] = int(time.time())
            dlg.accept()
            self._commit_singer_history_change("history_song_edit" if song_key else "history_song_add")
            for i in range(self.singer_history_songs_list.count()):
                item = self.singer_history_songs_list.item(i)
                if str(item.data(Qt.ItemDataRole.UserRole) or "") == new_key:
                    self.singer_history_songs_list.setCurrentItem(item)
                    break

        save_btn.clicked.connect(handle_save)
        buttons.rejected.connect(dlg.reject)
        dlg.exec()

    def _add_song_to_selected_singer_history(self):
        singer_key = self._selected_singer_history_key()
        if singer_key:
            self._edit_history_song_dialog(singer_key, None)

    def _history_target_singer_names(self, default_name: str = "") -> list[str]:
        names = []
        seen = set()

        def add_name(raw):
            name = str(raw or "").strip()
            if not name:
                return
            key = name.lower()
            if key in seen:
                return
            seen.add(key)
            names.append(name)

        add_name(default_name)
        try:
            for singer in self.queue:
                add_name(singer.get("name", ""))
        except Exception:
            pass
        try:
            for record in (self.singer_history.get("singers", {}) or {}).values():
                if isinstance(record, dict):
                    add_name(record.get("name", ""))
        except Exception:
            pass
        return names

    def _find_matching_mp3_for_cdg(self, cdg_path: str) -> str:
        base = os.path.splitext(str(cdg_path or "").strip())[0]
        if not base:
            return ""
        for ext in (".mp3", ".MP3"):
            mp3_path = base + ext
            if os.path.exists(mp3_path):
                return mp3_path
        return ""

    def _resolve_history_song_track(self, song: dict, singer_name: str):
        if not isinstance(song, dict):
            return None

        path = str(song.get("path", "") or "").strip()
        if path:
            track = self._find_track_by_path_ci(path)
            if track:
                return track
            try:
                track = song_index.find_by_path(path)
                if isinstance(track, dict):
                    return track
            except Exception:
                pass

        disc_id = str(song.get("disc_id", "") or "").strip()
        artist = str(song.get("artist", "") or "").strip()
        title = str(song.get("title", "") or "").strip()

        matches = []
        if artist and title:
            try:
                matches = song_index.find_by_artist_title(artist, title) or []
            except Exception:
                matches = [
                    t for t in self.tracks
                    if str(t.get("artist", "") or "").strip().lower() == artist.lower()
                    and str(t.get("title", "") or "").strip().lower() == title.lower()
                ]

        if not matches and disc_id:
            disc_u = disc_id.upper()
            try:
                matches = [
                    t for t in self.tracks
                    if str(t.get("discid") or t.get("disc_id") or "").strip().upper() == disc_u
                ]
            except Exception:
                matches = []

        if not matches:
            return None

        if disc_id:
            disc_u = disc_id.upper()
            exact_disc = [
                t for t in matches
                if str(t.get("discid") or t.get("disc_id") or "").strip().upper() == disc_u
            ]
            if exact_disc:
                matches = exact_disc

        host_priority = normalize_disc_priority(self.settings.get("disc_id_priority", ""), max_items=10)
        runtime_info = effective_disc_priority(
            host_priority,
            singer_override=self._singer_disc_priority_override(singer_name),
            max_items=10,
        )
        runtime_priority = runtime_info.get("effective", [])
        try:
            return pick_by_disc_priority(matches, runtime_priority)
        except Exception:
            return matches[0] if matches else None

    def _queue_song_from_history_record(self, target_singer: str, song: dict) -> bool:
        target_singer = str(target_singer or "").strip()
        if not target_singer or not isinstance(song, dict):
            return False

        track = self._resolve_history_song_track(song, target_singer)
        if not isinstance(track, dict):
            return False

        try:
            key = int(song.get("last_key") or 0)
        except Exception:
            key = 0
        try:
            tempo_percent = int(song.get("last_tempo_percent") or 100)
        except Exception:
            tempo_percent = 100

        path = str(track.get("path", "") or "").strip()
        ext = os.path.splitext(path)[1].lower()

        if ext == ".mp4":
            song_data = (path, key, tempo_percent)
        elif ext == ".cdg":
            mp3_path = self._find_matching_mp3_for_cdg(path)
            if not mp3_path:
                QMessageBox.warning(self, "Add To Tonight", f"Matching MP3 not found for:\n{path}")
                return False
            song_data = ((path, mp3_path), key, tempo_percent)
        elif ext == ".zip":
            if not self.is_mp3g_zip(path):
                QMessageBox.warning(self, "Add To Tonight", f"Invalid karaoke ZIP:\n{path}")
                return False
            song_data = (path, key, tempo_percent)
        else:
            song_data = (path, key, tempo_percent)

        self._add_song_to_queue(target_singer, song_data, track=track)
        return True

    def _queue_selected_singer_history_song(self):
        singer_key = self._selected_singer_history_key()
        song = self._selected_singer_history_song_record()
        if not singer_key or not isinstance(song, dict):
            return
        singer_record = self.singer_history.get("singers", {}).get(singer_key, {})
        default_singer = str(singer_record.get("name", "") or singer_key).strip()

        dlg = QDialog(self)
        dlg.setWindowTitle("Add To Tonight")
        dlg.setModal(True)
        dlg.setMinimumWidth(520)
        try:
            base = self.palette().color(QPalette.ColorRole.Base)
            win = self.palette().color(QPalette.ColorRole.Window)
            txtc = self.palette().color(QPalette.ColorRole.Text)
            dlg.setStyleSheet(dialog_stylesheet(win, base, txtc))
        except Exception:
            pass

        layout = QVBoxLayout(dlg)
        title = QLabel("Add song to tonight's queue")
        title.setStyleSheet(f"color:{_v('text_bright')}; font-size:18px; font-weight:700;")
        layout.addWidget(title)

        summary = QLabel(self._history_song_display(song))
        summary.setStyleSheet(section_meta_css())
        summary.setWordWrap(True)
        layout.addWidget(summary)

        target_label = QLabel("Singer")
        target_label.setStyleSheet(section_meta_css())
        layout.addWidget(target_label)

        singer_combo = QComboBox(dlg)
        singer_combo.setEditable(True)
        singer_combo.setInsertPolicy(QComboBox.InsertPolicy.NoInsert)
        singer_combo.setStyleSheet(line_edit_css())
        singer_names = self._history_target_singer_names(default_singer)
        singer_combo.addItems(singer_names)
        if default_singer:
            idx = singer_combo.findText(default_singer, Qt.MatchFlag.MatchFixedString)
            if idx >= 0:
                singer_combo.setCurrentIndex(idx)
            singer_combo.setEditText(default_singer)
        layout.addWidget(singer_combo)

        note = QLabel("Defaults to this singer, but you can choose another singer or type a new one.")
        note.setStyleSheet(section_meta_css())
        note.setWordWrap(True)
        layout.addWidget(note)

        buttons = QDialogButtonBox(dlg)
        add_btn = buttons.addButton("Add To Tonight", QDialogButtonBox.ButtonRole.AcceptRole)
        edit_btn = buttons.addButton("Edit Song Instead", QDialogButtonBox.ButtonRole.ActionRole)
        buttons.addButton("Cancel", QDialogButtonBox.ButtonRole.RejectRole)
        layout.addWidget(buttons)

        def handle_add():
            target_singer = str(singer_combo.currentText() or "").strip()
            if not target_singer:
                QMessageBox.warning(dlg, "Add To Tonight", "Choose or enter a singer name.")
                return
            if not self._queue_song_from_history_record(target_singer, song):
                artist = str(song.get("artist", "") or "").strip()
                title_text = str(song.get("title", "") or "").strip()
                QMessageBox.warning(
                    dlg,
                    "Add To Tonight",
                    f"Could not match this history song to a local track:\n\n{artist} - {title_text}"
                )
                return
            dlg.accept()

        def handle_edit():
            dlg.accept()
            song_key = self._selected_singer_history_song_key()
            if singer_key and song_key:
                self._edit_history_song_dialog(singer_key, song_key)

        add_btn.clicked.connect(handle_add)
        edit_btn.clicked.connect(handle_edit)
        buttons.rejected.connect(dlg.reject)
        dlg.exec()

    def _edit_selected_singer_history_brand(self):
        singer_key = self._selected_singer_history_key()
        record = self.singer_history.get("singers", {}).get(singer_key)
        if not isinstance(record, dict):
            return
        singer_name = str(record.get("name", "") or singer_key)
        dlg = QDialog(self)
        dlg.setWindowTitle(f"Preferred Brand: {singer_name}")
        dlg.setModal(True)
        dlg.setMinimumWidth(460)
        try:
            base = self.palette().color(QPalette.ColorRole.Base)
            win = self.palette().color(QPalette.ColorRole.Window)
            txtc = self.palette().color(QPalette.ColorRole.Text)
            dlg.setStyleSheet(dialog_stylesheet(win, base, txtc))
        except Exception:
            pass
        layout = QVBoxLayout(dlg)
        label = QLabel(f"Preferred brand override for {singer_name}")
        layout.addWidget(label)
        edit = QLineEdit(dlg)
        edit.setText(str(record.get("preferred_disc_priority", "") or "").strip())
        edit.setPlaceholderText("KV, SC, SBI")
        layout.addWidget(edit)
        buttons = QDialogButtonBox(dlg)
        save_btn = buttons.addButton("Save", QDialogButtonBox.ButtonRole.AcceptRole)
        clear_btn = buttons.addButton("Clear", QDialogButtonBox.ButtonRole.ResetRole)
        buttons.addButton("Cancel", QDialogButtonBox.ButtonRole.RejectRole)
        layout.addWidget(buttons)

        def handle_save():
            value = ", ".join(normalize_disc_priority(edit.text(), max_items=10))
