    def _apply_live_state_styles(self):
        try:
            active = bool(getattr(self, "karaoke_playing", False))
            timer = getattr(self, "_live_state_timer", None)
            if timer is not None:
                if active and not timer.isActive():
                    self._live_pulse_started_at = time.monotonic()
                    timer.start()
                elif not active and timer.isActive():
                    timer.stop()
            pulse = self._live_pulse_value() if active else 0.0
            if getattr(self, "transport_bar", None) is not None:
                self.transport_bar.setStyleSheet(self._transport_bar_live_css(active, pulse))
            if getattr(self, "rotation_hero_card", None) is not None:
                self.rotation_hero_card.setStyleSheet(self._rotation_hero_live_css(active, pulse))
            if active and getattr(self, "now_singing_label", None) is not None:
                self._now_singing_active_css = self._now_singing_active_css_for_pulse(pulse)
                self.now_singing_label.setStyleSheet(self._now_singing_active_css)
            if getattr(self, "rotation_summary_kicker", None) is not None:
                if active:
                    color = _v("accent_bright")
                    self.rotation_summary_kicker.setStyleSheet(
                        f"color:{color}; font-size:12px; font-weight:850; letter-spacing:0px;"
                    )
                else:
                    self.rotation_summary_kicker.setStyleSheet(
                        f"color:{_v('accent_bright')}; font-size:12px; font-weight:850; letter-spacing:0px;"
                    )
            if getattr(self, "performance_deck_status", None) is not None:
                if active:
                    bg_alpha = 0.17 + (0.09 * pulse)
                    self.performance_deck_status.setText("LIVE")
                    self.performance_deck_status.setStyleSheet(
                        f"""
                        QLabel {{
                            color:{_v('accent_text')};
                            font-size:11px;
                            font-weight:850;
                            padding: 3px 8px;
                            background: rgba(124,61,255,{bg_alpha:.3f});
                            border: 1px solid rgba(167,139,250,0.42);
                            border-radius: 8px;
                        }}
                        """
                    )
                else:
                    self.performance_deck_status.setText("STANDBY")
                    self.performance_deck_status.setStyleSheet(
                        f"""
                        QLabel {{
                            color:{_v('text_muted')};
                            font-size:11px;
                            font-weight:800;
                            padding: 3px 8px;
                            background: rgba(255,255,255,0.020);
                            border: 1px solid rgba(115,144,180,0.12);
                            border-radius: 8px;
                        }}
                        """
                    )
            if getattr(self, "performance_waveform", None) is not None:
                self.performance_waveform.set_active(active)
                if active:
                    self.performance_waveform.tick()
        except Exception:
            pass

    def _tick_live_state_polish(self):
        _perf_t0 = time.perf_counter()
        if self._safe_mode():
            return
        try:
            self._apply_live_state_styles()
        except Exception:
            pass
        finally:
            _perf_log_if_slow("ui_tick_live_state_polish", (time.perf_counter() - _perf_t0) * 1000.0)

    def _install_live_state_polish(self):
        try:
            if getattr(self, "_live_state_polish_installed", False):
                return
            self._live_state_polish_installed = True
            self._live_pulse_started_at = time.monotonic()

            for widget, blur, y, alpha in (
                (getattr(self, "library_card", None), 16, 5, 42),
                (getattr(self, "rotation_card", None), 16, 5, 42),
                (getattr(self, "operator_bottom_nav", None), 14, 4, 34),
                (getattr(self, "transport_bar", None), 24, 8, 70),
                (getattr(self, "rotation_hero_card", None), 22, 7, 65),
                (getattr(self, "bg_main_card", None), 20, 7, 62),
            ):
                if widget is not None:
                    effect = self._make_shadow_effect(blur=blur, y=y, alpha=alpha)
                    if effect is not None:
                        widget.setGraphicsEffect(effect)

            self._live_state_timer = QTimer(self)
            self._live_state_timer.timeout.connect(self._tick_live_state_polish)
            self._live_state_timer.start(500 if self._safe_mode() else (250 if self._performance_mode() else 100))
            self._apply_live_state_styles()
        except Exception:
            pass

    def _on_operator_splitter_moved(self, setting_key: str):
        try:
            self._operator_splitter_save_timer.start(320)
        except Exception:
            pass
        if setting_key in ("operator_column_splitter_sizes", "library_rotation_splitter_sizes"):
            try:
                self._schedule_reformat_lists()
            except Exception:
                pass
        if setting_key in ("operator_column_splitter_sizes", "video_controls_splitter_sizes"):
            try:
                self._schedule_preview_overlay_refresh(0)
            except Exception:
                pass

    def _restore_operator_splitter_sizes(self):
        defaults = {
            "operator_column_splitter_sizes": [1040, 490],
            "library_rotation_splitter_sizes": [420, 620],
            "rotation_now_splitter_sizes": [260, 540],
            "video_controls_splitter_sizes": [260, 560],
            "singer_history_splitter_sizes": [330, 820],
        }
        for setting_key, splitter in list(getattr(self, "_operator_splitters", []) or []):
            raw_sizes = (self.settings or {}).get(setting_key, [])
            try:
                sizes = [max(1, int(v)) for v in raw_sizes]
            except Exception:
                sizes = []
            if len(sizes) != splitter.count():
                sizes = list(defaults.get(setting_key, []))
            if len(sizes) == splitter.count():
                try:
                    available = max(1, int(sum(sizes)))
                    current_width = max(1, int(splitter.width()))
                    if current_width > 1 and (available > current_width * 1.35 or available < current_width * 0.65):
                        sizes = list(defaults.get(setting_key, sizes))
                    splitter.setSizes(sizes)
                except Exception:
                    pass
        try:
            self._schedule_reformat_lists()
        except Exception:
            pass

    def _save_operator_splitter_sizes(self):
        changed = False
        for setting_key, splitter in list(getattr(self, "_operator_splitters", []) or []):
            try:
                sizes = [max(0, int(v)) for v in splitter.sizes()]
            except Exception:
                continue
            if len(sizes) == splitter.count() and sizes != list((self.settings or {}).get(setting_key, [])):
                self.settings[setting_key] = sizes
                changed = True
        if changed:
            self.save_settings()

    def _header_qr_url(self) -> str:
        try:
            url = str(self.settings.get("header_qr_url", "") or "").strip()
        except Exception:
            url = ""
        if url:
            return url
        return self._default_header_qr_url_from_network()

    def _default_header_qr_url_from_network(self) -> str:
        try:
            base_url = _network_normalize_base_url(self.settings.get("base_url", ""))
            tenant = str(self.settings.get("user", self.settings.get("tenant", "")) or "").strip()
        except Exception:
            return ""
        if not base_url or not tenant or not base_url.startswith("http"):
            return ""
        return f"{base_url}/tenants/{tenant}/"

    def _build_qr_pixmap(self, url: str, *, size: int) -> QPixmap:
        if not url:
            return QPixmap()
        try:
            qr = qrcode.QRCode(border=1, box_size=8)
            qr.add_data(url)
            qr.make(fit=True)
            img = qr.make_image(fill_color="black", back_color="white").convert("RGBA")
            data = img.tobytes("raw", "RGBA")
            qimg = QImage(data, img.width, img.height, QImage.Format.Format_RGBA8888).copy()
            return QPixmap.fromImage(
                qimg.scaled(
                    size, size,
                    Qt.AspectRatioMode.KeepAspectRatio,
                    Qt.TransformationMode.SmoothTransformation,
                )
            )
        except Exception:
            return QPixmap()

    def _update_header_qr_widget(self):
        if not hasattr(self, "header_qr_widget"):
            return
        url = self._header_qr_url()
        if url:
            pix = self._build_qr_pixmap(url, size=22)
            if not pix.isNull():
                self.header_qr_widget.setPixmap(pix)
                self.header_qr_widget.setText("")
                self.header_qr_widget.setMinimumSize(38, 30)
                self.header_qr_widget.setToolTip(url)
                return
        self.header_qr_widget.setPixmap(QPixmap())
        self.header_qr_widget.setText("QR")
        self.header_qr_widget.setMinimumSize(38, 30)
        self.header_qr_widget.setToolTip("Set a request QR URL in Settings")

    def _set_header_qr_url(self, url: str):
        self.settings["header_qr_url"] = str(url or "").strip()
        self.save_settings()
        self._update_header_qr_widget()

    def _refresh_header_status(self):
        try:
            accepting = bool(self.settings.get("requests_accepting", True))
            accepting_dot = "●"
            accepting_text = "Accepting Requests" if accepting else "Requests Closed"
            accepting_color = _v("now_singing") if accepting else _v("warning")
            if hasattr(self, "header_status_label"):
                self.header_status_label.setText(
                    f'<span style="color:{accepting_color};">{accepting_dot}</span>  {accepting_text}'
                )
            if hasattr(self, "header_location_label"):
                tenant_name = str(
                    self.settings.get("user")
                    or self.settings.get("tenant")
                    or "Local"
                ).strip()
                self.header_location_label.setText(f"• {tenant_name}")
        except Exception:
            pass

    def _hero_badge_text(self, singer_name: str, artist: str = "", title: str = "") -> str:
        singer_name = str(singer_name or "").strip()
        artist = str(artist or "").strip()
        title = str(title or "").strip()
        source = singer_name or artist or title
        if not source:
            return "LIVE"
        parts = [p for p in re.split(r"\s+", source) if p]
        if len(parts) >= 2:
            return (parts[0][:1] + parts[1][:1]).upper()
        return parts[0][:2].upper()

    def open_header_qr_preview(self):
        url = self._header_qr_url()
        if not url:
            return
        pix = self._build_qr_pixmap(url, size=320)
        if pix.isNull():
            return
        dlg = QDialog(self)
        dlg.setWindowTitle("Request QR")
        dlg.setMinimumSize(320, 320)
        layout = QVBoxLayout(dlg)
        image_label = QLabel()
        image_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
        image_label.setPixmap(pix)
        layout.addWidget(image_label)
        url_label = QLabel(url)
        url_label.setWordWrap(True)
        url_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
        url_label.setStyleSheet(f"color:{_v('text_soft')}; font-size:12px; font-weight:600;")
        layout.addWidget(url_label)

        def save_qr_image():
            try:
                path, selected_filter = QFileDialog.getSaveFileName(
                    dlg,
                    "Save QR Code",
                    os.path.expanduser("~/Downloads/request-qr.png"),
                    "PNG Image (*.png);;JPEG Image (*.jpg *.jpeg)"
                )
                if not path:
                    return
                fmt = "PNG"
                lower_path = path.lower()
                if "jpeg" in selected_filter.lower() or lower_path.endswith(".jpg") or lower_path.endswith(".jpeg"):
                    fmt = "JPEG"
                    if not (lower_path.endswith(".jpg") or lower_path.endswith(".jpeg")):
                        path += ".jpg"
                else:
                    if not lower_path.endswith(".png"):
                        path += ".png"
                pix.save(path, fmt)
            except Exception:
                pass

        btn_row = QHBoxLayout()
        copy_btn = QPushButton("Copy URL")
        open_btn = QPushButton("Open URL")
        save_btn = QPushButton("Save Image")
        close_btn = QPushButton("Close")
        copy_btn.clicked.connect(lambda: QApplication.clipboard().setText(url))
        open_btn.clicked.connect(lambda: QDesktopServices.openUrl(QUrl(url)))
        save_btn.clicked.connect(save_qr_image)
        close_btn.setMinimumWidth(96)
        close_btn.clicked.connect(dlg.accept)
        btn_row.addWidget(copy_btn)
        btn_row.addWidget(open_btn)
        btn_row.addWidget(save_btn)
        btn_row.addStretch(1)
        btn_row.addWidget(close_btn)
        layout.addLayout(btn_row)
        dlg.exec()

    # --- Background settings / idle background resolver ---
    def _default_background_path(self) -> str:
        p = get_resource_path(DEFAULT_BG_IMAGE)
        if p and os.path.exists(p):
            return str(p)
        return str(os.path.join(os.path.dirname(__file__), DEFAULT_BG_IMAGE))

    def _copy_background_image_to_storage(self, file_path: str) -> str:
        if not file_path:
            return ""
        src = Path(file_path)
        if not src.exists():
            return ""
        # Avoid accidental overwrite collisions by appending timestamp on conflict.
        dst = IMAGES_DIR / src.name
        try:
            if dst.exists() and str(dst.resolve()) == str(src.resolve()):
                return str(dst)
        except Exception:
            pass
        if dst.exists():
            stem = src.stem
            suffix = src.suffix
            dst = IMAGES_DIR / f"{stem}_{int(time.time())}{suffix}"
        shutil.copy(file_path, str(dst))
        return str(dst)

    def _is_requests_accepting_cached(self) -> bool:
        try:
            return bool(self.settings.get("requests_accepting", True))
        except Exception:
            return True

    def _refresh_slideshow_images(self):
        folder = str(self.settings.get("background_slideshow_folder", "") or "").strip()
        if folder == self._idle_bg_slideshow_folder_cached and self._idle_bg_slideshow_images:
            return
        self._idle_bg_slideshow_folder_cached = folder
        self._idle_bg_slideshow_images = []
        self._idle_bg_slideshow_idx = -1
        self._idle_bg_slideshow_next_ts = 0.0
        if not folder or not os.path.isdir(folder):
            return
        exts = {".png", ".jpg", ".jpeg", ".bmp", ".webp"}
        try:
            files = []
            for fn in os.listdir(folder):
                p = os.path.join(folder, fn)
                if os.path.isfile(p) and os.path.splitext(fn)[1].lower() in exts:
                    files.append(p)
            files.sort(key=lambda s: s.lower())
            self._idle_bg_slideshow_images = files
        except Exception:
            self._idle_bg_slideshow_images = []

    def _resolve_idle_background_path(self, advance_slideshow: bool = False) -> str:
        # 1) Closed-requests override image (if configured)
        if not self._is_requests_accepting_cached():
            p = str(self.settings.get("background_closed_image_path", "") or "").strip()
            if p and os.path.exists(p):
                return p

        # 2) Slideshow mode
        if bool(self.settings.get("background_slideshow_enabled", False)):
            self._refresh_slideshow_images()
            images = self._idle_bg_slideshow_images
            if images:
                now = time.monotonic()
                try:
                    interval = max(1, int(float(self.settings.get("background_slideshow_interval_sec", 10))))
                except Exception:
                    interval = 10
                if (
                    advance_slideshow
                    or self._idle_bg_slideshow_idx < 0
                    or now >= float(self._idle_bg_slideshow_next_ts)
                ):
                    self._idle_bg_slideshow_idx = (self._idle_bg_slideshow_idx + 1) % len(images)
                    self._idle_bg_slideshow_next_ts = now + float(interval)
                idx = max(0, min(len(images) - 1, int(self._idle_bg_slideshow_idx)))
                return images[idx]

        # 3) Normal idle background
        p = str(self.settings.get("background_image_path", "") or "").strip()
        if p and os.path.exists(p):
            return p
        return self._default_background_path()

    def _apply_idle_background(self, force: bool = False, advance_slideshow: bool = False):
        try:
            if not hasattr(self, "video_window") or self.video_window is None:
                return
            if not force and not bool(getattr(self.video_window, "idle", False)):
                return
            path = self._resolve_idle_background_path(advance_slideshow=advance_slideshow)
            if not path:
                return
            if force or path != self._idle_bg_current_path:
                self._idle_bg_current_path = path
                self.video_window.set_background_image(path)
                self.video_window.update()
                try:
                    pix_ok = not bool(getattr(self.video_window.video_area, "background_pixmap", QPixmap()).isNull())
                    _diag(
                        f"[IDLE-BG] applied force={bool(force)} advance={bool(advance_slideshow)} "
                        f"idle={bool(getattr(self.video_window, 'idle', False))} "
                        f"exists={bool(os.path.exists(path))} pix_ok={pix_ok} path={path}"
                    )
                except Exception:
                    pass
        except Exception:
            pass

    def _tick_idle_background(self):
        _perf_t0 = time.perf_counter()
        if self._safe_mode():
            return
        try:
            if not hasattr(self, "video_window") or self.video_window is None:
                return
            if not bool(getattr(self.video_window, "idle", False)):
                return
            self._apply_idle_background(force=False, advance_slideshow=False)
        except Exception:
            pass
        finally:
            _perf_log_if_slow("ui_tick_idle_background", (time.perf_counter() - _perf_t0) * 1000.0)

