    def get_singer_index_by_row(self, row):
        counter = 0
        for i, singer in enumerate(self.queue):
            if singer["songs"]:
                if counter == row:
                    return i
                counter += 1 + len(singer["songs"])
            else:
                if counter == row:
                    return i
                counter += 1
        return -1

    def get_song_index_by_row(self, row):
        counter = 0
        for i, singer in enumerate(self.queue):
            if counter == row:
                return i, -1
            counter += 1
            for j, _ in enumerate(singer["songs"]):
                if counter == row:
                    return i, j
                counter += 1
        return -1, -1

    def get_block_size(self, singer):
        return 1 + len(singer["songs"])

    def _queue_entry_remote_request_id(self, entry):
        try:
            if isinstance(entry, dict) and entry.get("remote_request_id") is not None:
                return int(entry.get("remote_request_id"))
        except Exception:
            pass
        return None

    def _load_remote_request_tombstones(self) -> dict:
        try:
            if not REMOTE_REQUEST_TOMBSTONES_PATH.exists():
                return {"requests": {}, "generated_at": int(time.time()), "version": 1}
            with open(REMOTE_REQUEST_TOMBSTONES_PATH, "r", encoding="utf-8") as f:
                data = json.load(f)
            if not isinstance(data, dict):
                return {"requests": {}, "generated_at": int(time.time()), "version": 1}
            requests_map = data.get("requests")
            if not isinstance(requests_map, dict):
                requests_map = {}
            data["requests"] = requests_map
            data.setdefault("version", 1)
            return data
        except Exception as e:
            _diag(f"[REMOTE-TOMBSTONE] load failed: {e}")
            return {"requests": {}, "generated_at": int(time.time()), "version": 1}

    def _save_remote_request_tombstones(self, payload: dict | None = None) -> None:
        try:
            data = payload if isinstance(payload, dict) else getattr(self, "_remote_request_tombstones", None)
            if not isinstance(data, dict):
                data = {"requests": {}, "generated_at": int(time.time()), "version": 1}
            data["generated_at"] = int(time.time())
            with open(REMOTE_REQUEST_TOMBSTONES_PATH, "w", encoding="utf-8") as f:
                json.dump(data, f, indent=2, sort_keys=True)
        except Exception as e:
            _diag(f"[REMOTE-TOMBSTONE] save failed: {e}")

    def _ensure_remote_request_tombstones(self) -> dict:
        try:
            data = self.__dict__.get("_remote_request_tombstones")
        except Exception:
            data = None
        if not isinstance(data, dict):
            data = self._load_remote_request_tombstones()
            self._remote_request_tombstones = data
        data.setdefault("requests", {})
        self._prune_remote_request_tombstones(data)
        return data

    def _prune_remote_request_tombstones(self, data: dict | None = None) -> None:
        if not isinstance(data, dict):
            try:
                data = self.__dict__.get("_remote_request_tombstones")
            except Exception:
                data = None
        if not isinstance(data, dict):
            return
        items = data.setdefault("requests", {})
        if not isinstance(items, dict):
            data["requests"] = {}
            return
        now = time.time()
        ttl = 48 * 3600
        changed = False
        for key, tombstone in list(items.items()):
            try:
                removed_at = float((tombstone or {}).get("removed_at") or 0)
            except Exception:
                removed_at = 0
            if removed_at and now - removed_at > ttl:
                items.pop(key, None)
                changed = True
        if changed:
            self._save_remote_request_tombstones(data)

    def _queue_entry_artist_title_for_tombstone(self, entry) -> tuple[str, str]:
        if isinstance(entry, dict):
            artist = str(entry.get("artist") or "").strip()
            title = str(entry.get("title") or "").strip()
            if artist or title:
                return artist, title
            display = str(entry.get("display_name") or "").strip()
            if "•" in display:
                left, right = display.split("•", 1)
                return left.strip(), right.strip()
            if "-" in display:
                left, right = display.split("-", 1)
                return left.strip(), right.strip()
        return "", ""

    def _record_remote_request_tombstone(self, request_id: int, *, entry=None, singer_name: str = "", reason: str = "host_remove") -> dict | None:
        try:
            request_id = int(request_id or 0)
        except Exception:
            request_id = 0
        if request_id <= 0:
            return None
        artist, title = self._queue_entry_artist_title_for_tombstone(entry)
        singer_name = str(singer_name or "").strip()
        try:
            self._queue_revision = int(getattr(self, "_queue_revision", 0)) + 1
        except Exception:
            self._queue_revision = 1
        now = time.time()
        tombstone = {
            "request_id": request_id,
            "singer_name": singer_name,
            "artist": artist,
            "title": title,
            "song_key": remote_request_song_key(singer_name, artist, title),
            "removed_at": now,
            "removed_by": "host",
            "removal_reason": str(reason or "host_remove"),
            "local_revision": int(getattr(self, "_queue_revision", 0) or 0),
            "server_synced_at": None,
            "status": "removed",
        }
        data = self._ensure_remote_request_tombstones()
        data.setdefault("requests", {})[str(request_id)] = tombstone
        self._save_remote_request_tombstones(data)
        try:
            removed = getattr(self, "_remote_removed_request_ids", None)
            if not isinstance(removed, set):
                removed = set()
                self._remote_removed_request_ids = removed
            removed.add(request_id)
        except Exception:
            pass
        _diag(
            "[REMOTE-TOMBSTONE] created "
            f"request_id={request_id} singer={singer_name!r} title={title!r} "
            f"artist={artist!r} reason={reason} revision={tombstone['local_revision']} "
            f"accepting_requests={int(self._is_requests_accepting_cached())}"
        )
        return tombstone

    def _remote_request_matches_tombstone(self, req: dict) -> dict | None:
        if not isinstance(req, dict):
            return None
        data = self._ensure_remote_request_tombstones()
        items = data.get("requests") if isinstance(data, dict) else {}
        if not isinstance(items, dict):
            return None
        try:
            rid = int(req.get("request_id", 0) or 0)
        except Exception:
            rid = 0
        if rid > 0:
            tombstone = items.get(str(rid))
            if isinstance(tombstone, dict):
                return tombstone
        song_key = remote_request_song_key(req.get("singer", ""), req.get("artist", ""), req.get("title", ""))
        if not song_key or song_key == "||":
            return None
        for tombstone in items.values():
            if isinstance(tombstone, dict) and tombstone.get("song_key") == song_key:
                return tombstone
        return None

    def _sync_remote_removal_tombstones_async(self, reason: str = "manual") -> None:
        base_url = _network_normalize_base_url(self.settings.get("base_url", ""))
        tenant = str(self.settings.get("user", self.settings.get("tenant", "")) or "").strip()
        api_key = str(self.settings.get("api_key", "") or "").strip()
        if not base_url or not tenant or not api_key:
            return
        try:
            now = time.time()
            if now - float(getattr(self, "_remote_tombstone_sync_last_ts", 0.0) or 0.0) < 2.0:
                return
            if bool(getattr(self, "_remote_tombstone_sync_active", False)):
                return
            self._remote_tombstone_sync_last_ts = now
            self._remote_tombstone_sync_active = True
        except Exception:
            pass
        data = self._ensure_remote_request_tombstones()
        pending = [
            dict(item)
            for item in (data.get("requests") or {}).values()
            if isinstance(item, dict) and item.get("request_id") and not item.get("server_synced_at")
        ]
        if not pending:
            try:
                self._remote_tombstone_sync_active = False
            except Exception:
                pass
            return

        import threading, requests

        def send():
            headers = {"X-API-Key": api_key, "Accept": "application/json", "User-Agent": "SingWS/removal-sync"}
            synced = []
            try:
                for tombstone in pending:
                    rid = int(tombstone.get("request_id") or 0)
                    payload = {
                        "user": tenant,
                        "request_id": rid,
                        "state": "removed",
                        "status": "removed",
                        "singer_name": tombstone.get("singer_name", ""),
                        "artist": tombstone.get("artist", ""),
                        "title": tombstone.get("title", ""),
                        "removed_at": int(float(tombstone.get("removed_at") or time.time())),
                        "removed_by": tombstone.get("removed_by", "host"),
                        "removal_reason": tombstone.get("removal_reason", reason),
                        "local_revision": tombstone.get("local_revision", ""),
                    }
                    _diag(
                        "[REMOTE-TOMBSTONE] push "
                        f"request_id={rid} reason={reason} accepting_requests={int(self._is_requests_accepting_cached())} "
                        f"sync_connected=1 url={base_url}/api/v1/complete_remote_request.php"
                    )
                    resp = requests.post(
                        f"{base_url}/api/v1/complete_remote_request.php",
                        data=payload,
                        headers=headers,
                        timeout=6,
                    )
                    if 200 <= resp.status_code < 300:
                        synced.append(rid)
                        _diag(f"[REMOTE-TOMBSTONE] server acknowledged removal request_id={rid} status={resp.status_code}")
                    else:
                        _diag(f"[REMOTE-TOMBSTONE] push failed request_id={rid} status={resp.status_code} body={(resp.text or '')[:180]!r}")
            except Exception as e:
                _diag(f"[REMOTE-TOMBSTONE] sync failed reason={reason}: {e}")
            finally:
                try:
                    if synced:
                        latest = self._ensure_remote_request_tombstones()
                        changed = False
                        for rid in synced:
                            item = latest.get("requests", {}).get(str(rid))
                            if isinstance(item, dict) and not item.get("server_synced_at"):
                                item["server_synced_at"] = time.time()
                                changed = True
                        if changed:
                            self._save_remote_request_tombstones(latest)
                finally:
                    try:
                        self._remote_tombstone_sync_active = False
                    except Exception:
                        pass

        threading.Thread(target=send, daemon=True).start()

    def _delete_remote_request(self, request_id: int, *, entry=None, singer_name: str = "", reason: str = "host_remove"):
        try:
            request_id = int(request_id or 0)
        except Exception:
            return
        if request_id <= 0:
            return
        tombstone = self._record_remote_request_tombstone(request_id, entry=entry, singer_name=singer_name, reason=reason)
        try:
            removed = getattr(self, "_remote_removed_request_ids", None)
            if not isinstance(removed, set):
                removed = set()
                self._remote_removed_request_ids = removed
            removed.add(request_id)
        except Exception:
            pass
        base_url = _network_normalize_base_url(self.settings.get("base_url", ""))
        tenant = str(self.settings.get("user", self.settings.get("tenant", "")) or "").strip()
        api_key = str(self.settings.get("api_key", "") or "").strip()
        if not base_url or not tenant or not api_key:
            _diag(f"[REMOTE-TOMBSTONE] queued unsynced request_id={request_id} reason=network_not_configured")
            return

        import threading, requests

        def send():
            headers = {"X-API-Key": api_key, "Accept": "application/json", "User-Agent": "SingWS/remove-request"}
            try:
                # First mark the request non-pending. This prevents the next
                # sync poll from resurrecting a remotely-added song while the
                # cleanup/delete request is still in flight.
                mark = requests.post(
                    f"{base_url}/api/v1/complete_remote_request.php",
                    data={
                        "user": tenant,
                        "request_id": request_id,
                        "state": "removed",
                        "status": "removed",
                        "singer_name": singer_name,
                        "artist": (tombstone or {}).get("artist", ""),
                        "title": (tombstone or {}).get("title", ""),
                        "removed_at": int(float((tombstone or {}).get("removed_at") or time.time())),
                        "removed_by": "host",
                        "removal_reason": reason,
                        "local_revision": (tombstone or {}).get("local_revision", ""),
                    },
                    headers=headers,
                    timeout=5,
                )
                if 200 <= mark.status_code < 300:
                    latest = self._ensure_remote_request_tombstones()
                    item = latest.get("requests", {}).get(str(request_id))
                    if isinstance(item, dict):
                        item["server_synced_at"] = time.time()
                        self._save_remote_request_tombstones(latest)
                    _diag(f"[REMOTE-TOMBSTONE] server acknowledged removal request_id={request_id} status={mark.status_code}")
                else:
                    print(f"[REMOTE-DELETE] mark removed HTTP {mark.status_code}: {mark.text[:160]}")
            except Exception as e:
                print(f"[REMOTE-DELETE] Failed to mark request {request_id} removed: {e}")
            try:
                requests.post(
                    f"{base_url}/api/v1/delete_remote_request.php",
                    data={"user": tenant, "request_id": request_id},
                    headers=headers,
                    timeout=5,
                )
            except Exception as e:
                print(f"[REMOTE-DELETE] Failed to delete request {request_id}: {e}")

        threading.Thread(target=send, daemon=True).start()

    def _queue_remote_request_ids(self) -> list[int]:
        ids = []
        for singer in getattr(self, "queue", []) or []:
            if not isinstance(singer, dict):
                continue
            for entry in singer.get("songs", []) or []:
                remote_id = self._queue_entry_remote_request_id(entry)
                if remote_id is None:
                    continue
                try:
                    rid = int(remote_id)
                    if rid > 0:
                        ids.append(rid)
                except Exception:
                    pass
        return sorted(set(ids))

    def _clear_remote_queue_async(self, request_ids: list[int] | None = None, reason: str = "clear_queue"):
        """Clear server-side requests/rotation, then force a poll refresh.

        The preferred server endpoint is clear_remote_queue.php. For older
        servers, fall back to deleting known remote request ids one by one and
        posting an empty public rotation so stale display data disappears.
        """
        base_url = _network_normalize_base_url(self.settings.get("base_url", ""))
        tenant = str(self.settings.get("user", self.settings.get("tenant", "")) or "").strip()
        api_key = str(self.settings.get("api_key", "") or "").strip()
        ids = []
        for value in request_ids or []:
            try:
                rid = int(value)
                if rid > 0:
                    ids.append(rid)
            except Exception:
                pass
        ids = sorted(set(ids))
        if not base_url or not tenant or not api_key:
            _diag(f"[REMOTE-CLEAR] skipped: network not configured reason={reason}")
            return

        import threading, requests, json as _json

        def send():
            headers = {
                "X-API-Key": api_key,
                "Accept": "application/json",
                "User-Agent": "SingWS/clear-queue",
            }
            cleared = False
            try:
                resp = requests.post(
                    f"{base_url}/api/v1/clear_remote_queue.php",
                    data={"user": tenant, "clear_rotation": "1", "clear_requests": "1"},
                    headers=headers,
                    timeout=8,
                )
                if 200 <= resp.status_code < 300:
                    cleared = True
                    print(f"[REMOTE-CLEAR] server queue cleared ({reason})")
                else:
                    print(f"[REMOTE-CLEAR] clear endpoint HTTP {resp.status_code}: {resp.text[:160]}")
            except Exception as e:
                print(f"[REMOTE-CLEAR] clear endpoint unavailable: {e}")

            if not cleared and ids:
                deleted = 0
                for rid in ids:
                    try:
                        resp = requests.post(
                            f"{base_url}/api/v1/delete_remote_request.php",
                            data={"user": tenant, "request_id": rid},
                            headers=headers,
                            timeout=5,
                        )
                        if 200 <= resp.status_code < 300:
                            deleted += 1
                    except Exception as e:
                        print(f"[REMOTE-CLEAR] delete fallback failed for {rid}: {e}")
                print(f"[REMOTE-CLEAR] delete fallback removed {deleted}/{len(ids)} known request(s)")

            if not cleared:
                try:
                    resp = requests.post(
                        f"{base_url}/api.php",
                        params={"tenant": tenant},
                        json={"command": "clearRequests"},
                        headers=headers,
                        timeout=5,
                    )
                    if 200 <= resp.status_code < 300:
                        print("[REMOTE-CLEAR] legacy api.php clearRequests sent")
                    else:
                        print(f"[REMOTE-CLEAR] legacy clear HTTP {resp.status_code}: {resp.text[:160]}")
                except Exception as e:
                    print(f"[REMOTE-CLEAR] legacy clear failed: {e}")

            try:
                resp = requests.post(
                    f"{base_url}/post_rotation.php",
                    params={"user": tenant},
                    data={
                        "user": tenant,
                        "tenant": tenant,
                        "request_type": "rotation",
                        "rotation": _json.dumps([]),
                    },
                    headers=headers,
                    timeout=5,
                )
                if 200 <= resp.status_code < 300:
                    print("[REMOTE-CLEAR] public rotation cleared")
                else:
                    print(f"[REMOTE-CLEAR] public rotation clear HTTP {resp.status_code}: {resp.text[:160]}")
            except Exception as e:
                print(f"[REMOTE-CLEAR] public rotation clear failed: {e}")

            try:
                QTimer.singleShot(0, self, lambda: self.handle_requests_from_thread([]))
                QTimer.singleShot(1200, self, self.restart_request_polling)
                print("[REMOTE-CLEAR] sync refresh scheduled")
            except Exception:
                pass

        threading.Thread(target=send, daemon=True).start()

    def _sync_remote_singer_order(self, singer_idx: int):
        try:
            singer = self.queue[singer_idx]
        except Exception:
            return
        songs = singer.get("songs", []) if isinstance(singer, dict) else []
        request_ids = []
        for entry in songs:
            remote_id = self._queue_entry_remote_request_id(entry)
            if remote_id is not None:
                request_ids.append(remote_id)
        if not request_ids:
            return
        try:
            import time as _time
            if not hasattr(self, "_pending_remote_order_syncs") or not isinstance(self._pending_remote_order_syncs, dict):
                self._pending_remote_order_syncs = {}
            singer_key = str(singer.get("name", "") or "").strip().lower()
            if singer_key:
                self._pending_remote_order_syncs[singer_key] = {
                    "request_ids": list(request_ids),
                    "expires_at": _time.time() + 30.0,
                }
        except Exception:
            pass

        # Host reorder => bump the queue revision (app is the order authority).
        try:
            self._queue_revision = int(getattr(self, "_queue_revision", 0)) + 1
        except Exception:
            self._queue_revision = 1
        rev = self._queue_revision
        _diag(f"[REORDER] singer={singer.get('name','')!r} order={request_ids} "
              f"queue_revision={rev} (host is authoritative)")

        base_url = _network_normalize_base_url(self.settings.get("base_url", ""))
        tenant = str(self.settings.get("user", self.settings.get("tenant", "")) or "").strip()
        api_key = str(self.settings.get("api_key", "") or "").strip()
        if not base_url or not tenant or not api_key:
            return

        import threading, requests

        def send():
            try:
                resp = requests.post(
                    f"{base_url}/api/v1/set_remote_request_order.php",
                    data=[("user", tenant), ("revision", str(rev)),
                          *[("request_ids[]", rid) for rid in request_ids]],
                    headers={"X-API-Key": api_key},
                    timeout=5,
                )
                _diag(f"[REORDER] server accepted={resp.status_code == 200} "
                      f"(HTTP {resp.status_code}) revision={rev}")
            except Exception as e:
                print(f"[REMOTE-ORDER] Failed to sync order for singer {singer.get('name', '')}: {e}")

        threading.Thread(target=send, daemon=True).start()

    def _reconcile_remote_requests(self, reqs):
        try:
            if time.time() < float(getattr(self, "_remote_clear_in_progress_until", 0.0) or 0.0):
                _diag(f"[REMOTE-CLEAR] ignoring stale poll during clear window ({len(reqs or [])} request(s))")
                return
        except Exception:
            pass
        normalized = []
        try:
            removed_ids = getattr(self, "_remote_removed_request_ids", set())
            if not isinstance(removed_ids, set):
                removed_ids = set()
        except Exception:
            removed_ids = set()
        accepting_requests = self._is_requests_accepting_cached()
        _diag(
            "[REMOTE-SYNC] reconcile "
            f"count={len(reqs or [])} accepting_requests={int(accepting_requests)} "
            f"sync_connected={int(self.is_network_configured())}"
        )
        for req in reqs or []:
            if not isinstance(req, dict):
                continue
            if bool(req.get("sent", False)):
                continue
            try:
                request_id = int(req.get("request_id", 0) or 0)
            except Exception:
                request_id = 0
            if request_id <= 0:
                continue
            if request_id in removed_ids:
                _diag(f"[REMOTE-TOMBSTONE] poll old request ignored request_id={request_id} reason=in_memory_removed")
                try:
                    self._sync_remote_removal_tombstones_async("stale_poll_repush")
                except Exception:
                    pass
                continue
            tombstone = self._remote_request_matches_tombstone(req)
            if tombstone is not None:
                _diag(
                    "[REMOTE-TOMBSTONE] poll old request ignored "
                    f"request_id={request_id} singer={req.get('singer', '')!r} "
                    f"title={req.get('title', '')!r} reason=tombstone; re-push removed status"
                )
                try:
                    removed_ids.add(request_id)
                    self._remote_removed_request_ids = removed_ids
                    self._sync_remote_removal_tombstones_async("stale_poll_repush")
                except Exception:
                    pass
                continue
            singer = str(req.get("singer", "") or "").strip()
            if not singer:
                continue
            try:
                key = int(req.get("key", 0) or 0)
            except Exception:
                key = 0
            try:
                tempo = int(req.get("tempo", 0) or 0)
            except Exception:
                tempo = 0
            queue_singer, _duet_display = self._parse_duet_singer(singer)
            if not queue_singer:
                queue_singer = singer
            normalized.append({
                "request_id": request_id,
                "singer": singer,
                "queue_singer": queue_singer,
                "artist": str(req.get("artist", "") or "").strip(),
                "title": str(req.get("title", "") or "").strip(),
                "key": key,
                "tempo": tempo,
            })

        desired_ids = {item["request_id"] for item in normalized}
        existing_ids = set()
        unmatched_by_signature = {}
        for req in normalized:
            sig = (req["queue_singer"].lower(), req["artist"].lower(), req["title"].lower())
            unmatched_by_signature.setdefault(sig, []).append(req)

        for singer in self.queue:
            singer_name_l = str(singer.get("name", "") or "").strip().lower()
            for entry in singer.get("songs", []):
                remote_id = self._queue_entry_remote_request_id(entry)
                if remote_id is not None:
                    continue
                artist, title = self._queue_entry_artist_title(entry)
                artist_l = str(artist or "").strip().lower()
                title_l = str(title or "").strip().lower()
                if not artist_l or not title_l:
                    continue
                sig = (singer_name_l, artist_l, title_l)
                candidates = unmatched_by_signature.get(sig) or []
                if not candidates:
                    continue
                match = candidates.pop(0)
                if isinstance(entry, dict):
                    entry["remote_request_id"] = match["request_id"]
                    entry["key"] = match["key"]
                    entry["tempo_percent"] = 100 + match["tempo"]
                existing_ids.add(match["request_id"])

        for singer_idx in range(len(self.queue) - 1, -1, -1):
            singer = self.queue[singer_idx]
            songs = singer.get("songs", [])
            for song_idx in range(len(songs) - 1, -1, -1):
                entry = songs[song_idx]
                remote_id = self._queue_entry_remote_request_id(entry)
                if remote_id is None:
                    continue
                if remote_id not in desired_ids:
                    del songs[song_idx]
                else:
                    existing_ids.add(remote_id)
            if not songs:
                if self._should_preserve_rotation_identity(singer):
                    singer["songs"] = []
                else:
                    del self.queue[singer_idx]

        # Requests whose song can't be found in the library would otherwise be
        # re-processed (and re-logged) on every poll, because a failed lookup
        # never lands in the queue and so never enters existing_ids. Remember the
        # ones we've already tried-and-failed and skip them until the server
        # drops them (or the library is re-indexed, which clears this set).
        failed = getattr(self, "_unmatched_remote_request_ids", None)
        if not isinstance(failed, set):
            failed = set()
            self._unmatched_remote_request_ids = failed
        # Forget ids the server no longer lists so a re-submission gets a fresh try.
        failed &= desired_ids

        for req in normalized:
            rid = req["request_id"]
            if rid in existing_ids or rid in failed:
                continue
            if not accepting_requests:
                _diag(
                    "[REMOTE-SYNC] new request not imported because accepting_requests=0 "
                    f"request_id={rid} singer={req.get('singer', '')!r} title={req.get('title', '')!r}"
                )
                continue
            if not self.process_external_request(req):
                failed.add(rid)

        tempo_by_id = {item["request_id"]: item["tempo"] for item in normalized}
        key_by_id = {item["request_id"]: item["key"] for item in normalized}
        desired_by_singer = {}
        for req in normalized:
            desired_by_singer.setdefault(req["queue_singer"].lower(), []).append(req["request_id"])

        try:
            import time as _time
            pending = getattr(self, "_pending_remote_order_syncs", {})
            if isinstance(pending, dict):
                for singer_key in list(pending.keys()):
                    item = pending.get(singer_key) or {}
                    expires_at = float(item.get("expires_at") or 0.0)
                    if expires_at and expires_at < _time.time():
                        pending.pop(singer_key, None)
                        continue
                    pending_ids = [int(v) for v in (item.get("request_ids") or []) if int(v) in desired_ids]
                    server_ids = desired_by_singer.get(singer_key, [])
                    if pending_ids and set(pending_ids) == set(server_ids):
                        desired_by_singer[singer_key] = pending_ids
                        if server_ids == pending_ids:
                            pending.pop(singer_key, None)
        except Exception:
            pass

        # Sync per-song metadata (key / tempo edits made on the website) onto the
        # matching local entries — but DO NOT reorder. The desktop app is the
        # admin/source of truth for show order: once the host arranges the queue,
        # the server must never reshuffle it. New requests are appended by
        # process_external_request and dropped ones were removed above; the
        # host-set order of everything else is preserved exactly.
        entry_by_id = {}
        for singer in self.queue:
            for entry in singer.get("songs", []):
                remote_id = self._queue_entry_remote_request_id(entry)
                if remote_id is None:
                    continue
                entry_by_id[remote_id] = entry
                if isinstance(entry, dict):
                    entry["key"] = key_by_id.get(remote_id, entry.get("key", 0))
                    entry["tempo_percent"] = 100 + tempo_by_id.get(remote_id, int((entry.get("tempo_percent") or 100) - 100))
        # (Intentionally no per-singer song reordering here — see note above.)
        _ = desired_by_singer  # retained for the order-push handshake only

        self.update_queue_display()
        try:
            self.save_data()
        except Exception:
            pass

    def _find_song_for_request(self, artist: str, title: str) -> list:
        """Resolve a web request to library track(s) using the SAME index search
        the in-app library search uses (song_index.search_songs), instead of a
        separate strict exact-match path.

        The strict path (find_by_artist_title) misses anything whose library
        artist/title isn't an exact string match — e.g. a library title of
        "My Way (Remastered)" vs a request for "My Way". The in-app search finds
        those because it matches each query word as a substring of the song's
        search blob, so we route web requests through that same function and then
        pick the best-matching song (possibly several disc versions) for
        pick_by_disc_priority. Returns [] when nothing confidently matches.
        """
        artist = (artist or "").strip()
        title = (title or "").strip()

        # Fast precise path first (indexed exact / normalized artist+title).
        try:
            exact = song_index.find_by_artist_title(artist, title)
        except Exception:
            exact = []
        if exact:
            return exact

        query = (artist + " " + title).strip()
        if not query:
            return []
        # Same search the library box uses. fuzzy=False keeps a burst of remote
        # requests fast (the per-word substring match already absorbs the
        # formatting differences that the strict path chokes on).
        try:
            candidates = song_index.search_songs(query, limit=60, fuzzy=False)
        except Exception:
            candidates = []
        if not candidates:
            return []

        def _tokens(s: str) -> set:
            return set(re.findall(r"[a-z0-9]+", song_index.normalize_text(s or "")))

        req_tt = _tokens(title)
        req_at = _tokens(artist)

        def _score(c) -> int:
            ct = _tokens(str(c.get("title") or ""))
            ca = _tokens(str(c.get("artist") or ""))
            s = 0
            # Title is the strong signal: reward how many of the requested title
            # words appear in the candidate title (all present == best).
            if req_tt:
                if req_tt <= ct:
                    s += 100
                else:
                    s += int(80 * len(req_tt & ct) / len(req_tt))
            # Artist confirms it's the right performer.
            if req_at:
                if req_at <= ca:
                    s += 50
                else:
                    s += int(40 * len(req_at & ca) / len(req_at))
            return s

        best = max(candidates, key=_score)
        if _score(best) < 70:
            # Too little of the requested title/artist is actually present — don't
            # auto-queue a wrong song just because a stray word overlapped.
            return []

        # Return every candidate that is the SAME song as the best pick so
        # pick_by_disc_priority can still choose the preferred disc version.
        best_ak = song_index.fuzzy_match_key(str(best.get("artist") or ""))
        best_tk = song_index.fuzzy_match_key(str(best.get("title") or ""))
        same = [
            c for c in candidates
            if song_index.fuzzy_match_key(str(c.get("title") or "")) == best_tk
            and song_index.fuzzy_match_key(str(c.get("artist") or "")) == best_ak
        ]
        return same or [best]

    def process_external_request(self, req):
        import time as time_module
        start = time_module.time()
        
        singer = (req.get("singer", "") or "").strip()
        artist = (req.get("artist", "") or "").strip()
        title  = (req.get("title", "") or "").strip()

        # Safe int parse for key (semitones)
        try:
            key = int(req.get("key", 0) or 0)
        except Exception:
            key = 0

        # Remote tempo arrives as a signed offset from normal speed.
        try:
            tempo_offset = int(req.get("tempo", 0) or 0)
        except Exception:
            tempo_offset = 0
        tempo_offset = max(-10, min(10, tempo_offset))
        tempo_percent = 100 + tempo_offset

        # Skip requests we've already tried and couldn't match in the library.
        # This dedups by content (singer/artist/title) so it stops the
        # log spam on EVERY poll regardless of which code path delivered the
        # request (the legacy delivery loop has no request_id to dedup on). The
        # set is cleared whenever the library is re-indexed, giving newly-added
        # songs a fresh attempt.
        _sig = (singer.lower(), artist.lower(), title.lower())
        _failed_sigs = getattr(self, "_unmatched_request_sigs", None)
        if not isinstance(_failed_sigs, set):
            _failed_sigs = set()
            self._unmatched_request_sigs = _failed_sigs
        if _sig in _failed_sigs:
            return False

        # Resolve via the SAME search the in-app library box uses (tolerant
        # substring match), not a strict exact artist+title lookup.
        try:
            matches = self._find_song_for_request(artist, title)
        except Exception as e:
            logging.error(f"External request lookup failed for '{artist} - {title}': {e}")
            # Fallback to old in-memory method if the index lookup throws.
            matches = [
                t for t in self.tracks
                if t.get('artist', '').lower() == artist.lower()
                and t.get('title', '').lower() == title.lower()
            ]

        if not matches:
            # A song that simply isn't in this library is normal, not an error —
            # log once and remember it so we don't retry it on every poll.
            msg = f"[REMOTE-REQUEST] no local library match for {artist} - {title} (singer={singer})"
            try:
                logging.info(msg)
            except Exception:
                pass
            print(msg)
            _failed_sigs.add(_sig)
            return False

        # Only log requests we actually resolve and queue.
        SingWSLogger.log_external_request(artist, title, singer, key)
        host_priority = normalize_disc_priority(self.settings.get("disc_id_priority", ""), max_items=10)
        singer_brand_raw = request_preferred_disc_brand(req)
        singer_override = self._singer_disc_priority_override(singer)
        runtime_info = effective_disc_priority(
            host_priority,
            singer_brand_raw=singer_brand_raw,
            singer_override=singer_override,
            max_items=10,
        )
        runtime_priority = runtime_info.get("effective", [])
        available_versions = disc_priority_available_versions(matches)
        selected_brand = runtime_info.get("singer_normalized", "")
        selected_available = any(track_matches_disc_brand(m, selected_brand) for m in matches) if selected_brand else False
        fallback_reason = ""
        if runtime_info.get("unknown_ignored"):
            fallback_reason = "unknown singer brand ignored"
        elif selected_brand and not selected_available:
            fallback_reason = f"{selected_brand} unavailable for matched song"
        brand_log = (
            "[REMOTE-BRAND] "
            f"singer={singer!r} raw={runtime_info.get('singer_raw', '')!r} "
            f"source={runtime_info.get('singer_source', '') or 'none'} "
            f"normalized={selected_brand!r} host_priority={runtime_info.get('host', [])} "
            f"effective_priority={runtime_priority} available_versions={available_versions}"
        )
        try:
            logging.info(brand_log)
        except Exception:
            pass
        print(brand_log)
        chosen = pick_by_disc_priority(matches, runtime_priority)
        chosen_brand = str(chosen.get("disc_id") or chosen.get("discid") or "").strip()
        final_log = (
            "[REMOTE-BRAND] "
            f"final_selected={chosen_brand!r} display={chosen.get('display', '')!r} "
            f"fallback_reason={fallback_reason!r}"
        )
        try:
            logging.info(final_log)
        except Exception:
            pass
        print(final_log)
        print(f"Matched: {chosen['display']} for {singer}")

        base, ext = os.path.splitext(chosen['path'])
        ext = ext.lower()

        if ext == ".mp4":
            # Realtime key-change handled by GStreamer during playback
            song_data = (chosen['path'], key, tempo_percent)  # (mp4_path, semitones, tempo_percent)
            return bool(self._add_song_to_queue(singer, song_data, track=chosen, remote_meta=req))  # Pass track data!

        elif ext == ".cdg":
            # Need matching MP3; we won't preprocess — GStreamer will pitch-shift live
            mp3_path = base + ".mp3"
            
            # Try case variations if exact match fails
            if not os.path.exists(mp3_path):
                # Try uppercase .MP3
                mp3_path_upper = base + ".MP3"
                if os.path.exists(mp3_path_upper):
                    mp3_path = mp3_path_upper
                    print(f"[EXTERNAL-REQ] Found MP3 with uppercase extension: {mp3_path}")
                else:
                    print(f"CDG request missing MP3: {chosen['path']}")
                    print(f"  Expected: {mp3_path}")
                    print(f"  Also tried: {mp3_path_upper}")
                    # Check if directory exists (os already imported at module level)
                    dir_path = os.path.dirname(chosen['path'])
                    if os.path.exists(dir_path):
                        files_in_dir = [f for f in os.listdir(dir_path) if base.split('/')[-1] in f]
                        print(f"  Files with same base name: {files_in_dir}")
                    return False

            song_data = ((chosen['path'], mp3_path), key, tempo_percent)  # ((cdg_path, mp3_path), semitones, tempo_percent)
            return bool(self._add_song_to_queue(singer, song_data, track=chosen, remote_meta=req))  # Pass track data!

        elif ext == ".mp3":
            # In case your library has plain MP3 entries
            song_data = (chosen['path'], key, tempo_percent)  # (mp3_path, semitones, tempo_percent)
            return bool(self._add_song_to_queue(singer, song_data, track=chosen, remote_meta=req))  # Pass track data!

        elif ext == ".zip":
            # NEW: Handle MP3G requests
            if self.is_mp3g_zip(chosen['path']):
                song_data = (chosen['path'], key, tempo_percent)
                return bool(self._add_song_to_queue(singer, song_data, track=chosen, remote_meta=req))  # Pass track data!
            else:
                print("Invalid zip format in external request:", chosen['path'])
                return False

        else:
            print("Unsupported format in external request:", chosen['path'])
            return False
            
    def get_rotation_data(self):
        rotation = []
        number = 1
        for singer in self.queue:
            # Skip if singer is skipped or has no active songs
            if not self.is_singer_active(singer):
                continue
            
            songs = []
            for entry in singer["songs"]:
                # Handle both dict and tuple format
                if isinstance(entry, dict):
                    # Skip if song is skipped
                    if entry.get("skipped", False):
                        continue
                    song_info = entry.get("song_info")
                else:
                    # Old format
                    try:
                        song_info = entry[0]
                    except Exception:
                        song_info = entry
                
                if isinstance(song_info, (tuple, list)) and song_info:
                    song_path = song_info[0]
                else:
                    song_path = song_info
                songs.append(self.lookup_display_name(song_path, artist_title_only=True))
            
            # Only add if has non-skipped songs
            if songs:
                display_name = self._queue_singer_display_for_entry(singer, self._first_active_entry_for_singer(singer))
                rotation.append({"number": number, "name": display_name or singer["name"], "songs": songs})
                number += 1
        return {"rotation": rotation}

    def clear_all_selections(self):
        """Clear selections from both track list and queue display (and drop focus from inputs)."""
        try:
            self.results_list.clearSelection()
        except Exception:
            pass
        try:
            self.queue_display.clearSelection()
        except Exception:
            pass
        # Drop focus so the search box doesn't look "stuck" selected
        try:
            self.search_input.clearFocus()
        except Exception:
            pass

    def mousePressEvent(self, event):
        """Clear selections when clicking empty space in main window"""
        # Get the widget that was clicked
        widget_under_mouse = self.childAt(event.pos())
        
        # If clicking on empty space (not on a widget) or on the main window background
        if widget_under_mouse is None or widget_under_mouse == self:
            self.clear_all_selections()
            # Don't set focus to main window - just clear selections
            return
        
        # Call parent implementation
        super().mousePressEvent(event)

    def setup_clean_focus_behavior(self):
        """Unify selection visuals and remove macOS blue focus rings."""

        # Let views take focus normally (fixes the 'need to click twice' feeling),
        # but suppress macOS focus rectangles so nothing turns blue.
        try:
            self.results_list.setFocusPolicy(Qt.FocusPolicy.StrongFocus)
        except Exception:
            pass
        try:
            self.queue_display.setFocusPolicy(Qt.FocusPolicy.StrongFocus)
        except Exception:
            pass

        import sys
        if sys.platform == "darwin":
            try:
                self.results_list.setAttribute(Qt.WidgetAttribute.WA_MacShowFocusRect, False)
                self.queue_display.setAttribute(Qt.WidgetAttribute.WA_MacShowFocusRect, False)
            except Exception:
                pass
            # Allow first click to interact even when the window is inactive (no "activate then click again")
            try:
                self.results_list.setAttribute(Qt.WidgetAttribute.WA_MacAcceptsFirstMouse, True)
                self.queue_display.setAttribute(Qt.WidgetAttribute.WA_MacAcceptsFirstMouse, True)
            except Exception:
                pass
            # Also apply to the search box itself
            try:
                self.search_input.setAttribute(Qt.WidgetAttribute.WA_MacShowFocusRect, False)
                self.search_input.setAttribute(Qt.WidgetAttribute.WA_MacAcceptsFirstMouse, True)
            except Exception:
                pass

        # Custom gray "glow" focus for the search box (instead of macOS blue).
        try:
            self.search_input.setFocusPolicy(Qt.FocusPolicy.ClickFocus)
            self.search_input.setStyleSheet(line_edit_css())
        except Exception:
            pass

    def setup_selection_behavior(self):
        """Selection + focus behavior:
        - Selecting in one view clears selection in the other
        - Clicking either view drops focus from the search box so it doesn't look 'stuck'
        """

        # Any click in results/queue should drop focus from the search box
        try:
            self.results_list.itemClicked.connect(lambda *_: self.search_input.clearFocus())
        except Exception:
            pass
        try:
            self.queue_display.itemClicked.connect(lambda *_: self.search_input.clearFocus())
        except Exception:
            pass

    def post_rotation(self):
        # Only post rotation if network is configured
        if not self.is_network_configured():
            return  # Silently skip if network not configured

        self.sync_session_location(active=True)
        
        import threading, requests, json as _json

        def send():
            base_url = _network_normalize_base_url(self.settings.get("base_url", "https://beta.wskar.com"))
            tenant   = str(self.settings.get("user", self.settings.get("tenant", ""))).strip()

            # Upload via get_requests.php
            url = f"{base_url}/post_rotation.php"

            # Send rotation as JSON string in a form body (common PHP pattern)
            rot = (self.get_rotation_data() or {}).get("rotation", [])
            form = {
                "user":         tenant,
                "tenant":       tenant,  # back-compat if server still expects it
                "request_type": "rotation",
                "rotation":     _json.dumps(rot),
            }

            try:
                # First try request_type=rotation
                resp = requests.post(
                    url,
                    params={"user": tenant},
                    data=form,  # application/x-www-form-urlencoded
                    timeout=5,
                    headers={
                        "User-Agent": "SingWS/rotation-uploader",
                        "Accept": "application/json",
                        **({"X-API-Key": self.settings.get("api_key", "")} if self.settings.get("api_key") else {}),
                    },
                )

                # If server doesn’t like that key, try request_type=post_rotation
                if resp.status_code == 400 and "bad request_type" in (resp.text or "").lower():
                    form["request_type"] = "post_rotation"
                    resp = requests.post(
                        url,
                        data=form,
                        timeout=5,
                        headers={
                        "User-Agent": "SingWS/rotation-uploader",
                        "Accept": "application/json",
                        **({"X-API-Key": self.settings.get("api_key", "")} if self.settings.get("api_key") else {}),
                    },
                    )

                if resp.status_code != 200:
                    print(f"[rotation] HTTP {resp.status_code} posting to {url}: {resp.text[:200]}")
                else:
                    print(f"[rotation] public display updated ({len(rot)} singer(s))")

            except requests.Timeout:
                print(f"[rotation] timeout posting to {url}")
            except Exception as e:
                print("Rotation post failed:", e)

        threading.Thread(target=send, daemon=True).start()

    def debug_bg_music_state(self):
        """Debug method to check background music state"""
        if hasattr(self, 'bg_music'):
            print(f"Background Music Debug:")
            print(f"  - Has playlist: {bool(self.bg_music.playlist)}")
            print(f"  - Playlist length: {len(self.bg_music.playlist) if self.bg_music.playlist else 0}")
            print(f"  - Current index: {self.bg_music.current_index}")
            print(f"  - Is playing: {self.bg_music.is_playing}")
            print(f"  - Volume: {self.bg_music.volume}")
            print(f"  - Has pipeline: {self.bg_music.gst_bg_pipeline is not None}")
            if self.bg_music.playlist:
                print(f"  - Current track: {self.bg_music.get_current_track_info()}")
        else:
            print("No background music object found")

